import { Controller, Get, Query, Param, UseGuards } from '@nestjs/common';
import { AuditService } from './audit.service';
import { JwtAuthGuard } from '@core/common/guards/jwt-auth.guard';
import { RolesGuard } from '@core/common/guards/roles.guard';
import { Roles } from '@core/common/decorators/roles.decorator';
import { Role } from '@prisma/client';

@Controller('audit-logs')
@UseGuards(RolesGuard)
@Roles('SUPER_ADMIN' as any) // Apenas SUPER_ADMIN pode ver logs
export class AuditController {
  constructor(private readonly auditService: AuditService) {
    // Empty implementation
  }

  /**
   * GET /audit-logs
   * Listar logs de auditoria com filtros
   */
  @Get()
  async findAll(
    @Query('page') page?: string,
    @Query('limit') limit?: string,
    @Query('action') action?: string,
    @Query('userId') userId?: string,
    @Query('tenantId') tenantId?: string,
    @Query('startDate') startDate?: string,
    @Query('endDate') endDate?: string,
  ) {
    return this.auditService.findAll({
      page: page ? parseInt(page) : undefined,
      limit: limit ? parseInt(limit) : undefined,
      action,
      userId,
      tenantId,
      startDate: startDate ? new Date(startDate) : undefined,
      endDate: endDate ? new Date(endDate) : undefined,
    });
  }

  /**
   * GET /audit-logs/stats
   * Estatísticas de logs
   */
  @Get('stats')
  async getStats(
    @Query('startDate') startDate?: string,
    @Query('endDate') endDate?: string,
    @Query('tenantId') tenantId?: string,
  ) {
    return this.auditService.getStats({
      startDate: startDate ? new Date(startDate) : undefined,
      endDate: endDate ? new Date(endDate) : undefined,
      tenantId,
    });
  }

  /**
   * GET /audit-logs/:id
   * Buscar log específico
   */
  @Get(':id')
  async findOne(@Param('id') id: string) {
    return this.auditService.findOne(id);
  }
}

import { Injectable } from '@nestjs/common';
import { PrismaService } from '@core/prisma/prisma.service';

export interface AuditLogData {
  action: string;
  userId?: string;
  tenantId?: string;
  ipAddress?: string;
  userAgent?: string;
  details?: Record<string, unknown>;
}

@Injectable()
export class AuditService {
  constructor(private prisma: PrismaService) { }

  /**
   * Criar log de auditoria
   */
  async log(data: AuditLogData) {
    return this.prisma.auditLog.create({
      data: {
        action: data.action,
        userId: data.userId,
        tenantId: data.tenantId,
        ipAddress: data.ipAddress,
        userAgent: data.userAgent,
        details: data.details ? JSON.stringify(data.details) : null,
      },
    });
  }

  /**
   * Buscar logs com filtros e paginação
   */
  async findAll(params: {
    page?: number;
    limit?: number;
    action?: string;
    userId?: string;
    tenantId?: string;
    startDate?: Date;
    endDate?: Date;
  }) {
    const page = params.page || 1;
    const limit = params.limit || 50;
    const skip = (page - 1) * limit;

    const where: any = {};

    if (params.action) {
      where.action = params.action;
    }

    if (params.userId) {
      where.userId = params.userId;
    }

    if (params.tenantId) {
      where.tenantId = params.tenantId;
    }

    if (params.startDate || params.endDate) {
      where.createdAt = {};
      if (params.startDate) {
        where.createdAt.gte = params.startDate;
      }
      if (params.endDate) {
        where.createdAt.lte = params.endDate;
      }
    }

    const [logs, total] = await Promise.all([
      this.prisma.auditLog.findMany({
        where,
        include: {
          user: {
            select: {
              id: true,
              name: true,
              email: true,
              role: true,
            },
          },
        },
        orderBy: {
          createdAt: 'desc',
        },
        skip,
        take: limit,
      }),
      this.prisma.auditLog.count({ where }),
    ]);

    return {
      data: logs,
      meta: {
        total,
        page,
        limit,
        totalPages: Math.ceil(total / limit),
      },
    };
  }

  /**
   * Buscar log por ID
   */
  async findOne(id: string) {
    return this.prisma.auditLog.findUnique({
      where: { id },
      include: {
        user: {
          select: {
            id: true,
            name: true,
            email: true,
            role: true,
          },
        },
      },
    });
  }

  /**
   * Estatísticas de logs
   */
  async getStats(params: { startDate?: Date; endDate?: Date; tenantId?: string }) {
    const where: any = {};

    if (params.startDate || params.endDate) {
      where.createdAt = {};
      if (params.startDate) {
        where.createdAt.gte = params.startDate;
      }
      if (params.endDate) {
        where.createdAt.lte = params.endDate;
      }
    }

    if (params.tenantId) {
      where.tenantId = params.tenantId;
    }

    const [total, byAction, byUser] = await Promise.all([
      this.prisma.auditLog.count({ where }),
      this.prisma.auditLog.groupBy({
        by: ['action'],
        where,
        _count: true,
        orderBy: {
          _count: {
            action: 'desc',
          },
        },
        take: 10,
      }),
      this.prisma.auditLog.groupBy({
        by: ['userId'],
        where: { ...where, userId: { not: null } },
        _count: true,
        orderBy: {
          _count: {
            userId: 'desc',
          },
        },
        take: 10,
      }),
    ]);

    return {
      total,
      byAction: byAction.map((item) => ({
        action: item.action,
        count: item._count,
      })),
      byUser: byUser.map((item) => ({
        userId: item.userId,
        count: item._count,
      })),
    };
  }
}

import { SetMetadata } from '@nestjs/common';

export const SECURITY_LOG_KEY = 'securityLog';

export interface SecurityLogOptions {
  action: string;
  includeUser?: boolean;
  includeTenant?: boolean;
  includeIp?: boolean;
  includeUserAgent?: boolean;
  customDetails?: Record<string, any>;
}

/**
 * Decorator para marcar endpoints que devem ser registrados no log de segurança
 * 
 * @param options - Configurações do log de segurança
 * 
 * Exemplo de uso:
 * 
 * @Post('sensitive-operation')
 * @SecurityLog({
 *   action: 'SENSITIVE_DATA_ACCESS',
 *   includeUser: true,
 *   includeTenant: true,
 *   customDetails: { operation: 'view_financial_data' }
 * })
 * async sensitiveOperation(@Body() data: unknown) {
 *   // operação sensível
 * }
 */
export const SecurityLog = (options: SecurityLogOptions) => SetMetadata(SECURITY_LOG_KEY, options);

import { Injectable, CanActivate, ExecutionContext } from '@nestjs/common';
import { Reflector } from '@nestjs/core';
import { AuditService } from '../audit.service';
import { SECURITY_LOG_KEY, SecurityLogOptions } from '../decorators/security-log.decorator';
import { Request } from 'express';

@Injectable()
export class SecurityLogGuard implements CanActivate {
  constructor(
    private reflector: Reflector,
    private auditService: AuditService
  ) { }

  async canActivate(context: ExecutionContext): Promise<boolean> {
    const securityLogOptions = this.reflector.getAllAndOverride<SecurityLogOptions>(
      SECURITY_LOG_KEY,
      [context.getHandler(), context.getClass()]
    );

    if (!securityLogOptions) {
      return true;
    }

    const request = context.switchToHttp().getRequest<Request>();

    // Coletar informações baseadas nas opções
    const logData: any = {
      action: securityLogOptions.action
    };

    // Incluir usuário se solicitado
    if (securityLogOptions.includeUser) {
      const user = (request as any).user;
      if (user) {
        logData.userId = user.id;
        logData.userName = user.name;
        logData.userEmail = user.email;
        logData.userRole = user.role;
      }
    }

    // Incluir tenant se solicitado
    if (securityLogOptions.includeTenant) {
      const user = (request as any).user;
      if (user?.tenantId) {
        logData.tenantId = user.tenantId;
      }
    }

    // Incluir IP se solicitado
    if (securityLogOptions.includeIp) {
      logData.ipAddress = this.getClientIp(request);
    }

    // Incluir User-Agent se solicitado
    if (securityLogOptions.includeUserAgent) {
      logData.userAgent = request.get('user-agent') || '';
    }

    // Detalhes personalizados
    const details: any = {
      method: request.method,
      url: request.url,
      timestamp: new Date().toISOString(),
      ...securityLogOptions.customDetails
    };

    // Adicionar parâmetros da requisição (sem dados sensíveis)
    if (request.params && Object.keys(request.params).length > 0) {
      details.params = this.sanitizeParams(request.params);
    }

    if (request.query && Object.keys(request.query).length > 0) {
      details.query = this.sanitizeParams(request.query);
    }

    logData.details = details;

    try {
      // Registrar log de acesso
      await this.auditService.log(logData);
    } catch (error) {
      // Não bloquear a requisição se o log falhar
      console.error('Falha ao registrar log de segurança:', error);
    }

    return true;
  }

  private getClientIp(request: Request): string {
    return (
      request.get('x-forwarded-for')?.split(',')[0]?.trim() ||
      request.get('x-real-ip') ||
      request.get('x-client-ip') ||
      request.ip ||
      'unknown'
    );
  }

  private sanitizeParams(params: any): any {
    const sanitized: any = {};

    // Campos sensíveis que devem ser mascarados
    const sensitiveFields = [
      'password', 'senha', 'token', 'authorization', 'auth',
      'creditCard', 'cartaoCredito', 'cpf', 'cnpj', 'rg'
    ];

    for (const [key, value] of Object.entries(params)) {
      if (sensitiveFields.some(field =>
        key.toLowerCase().includes(field.toLowerCase())
      )) {
        sanitized[key] = '[REDACTED]';
      } else {
        sanitized[key] = value;
      }
    }

    return sanitized;
  }
}

import { Injectable, NestInterceptor, ExecutionContext, CallHandler } from '@nestjs/common';
import { Observable } from 'rxjs';
import { tap } from 'rxjs/operators';
import { AuditService } from '../audit.service';
import { Request } from 'express';

@Injectable()
export class SecurityAuditInterceptor implements NestInterceptor {
  constructor(private auditService: AuditService) {
      // Empty implementation
    }

  intercept(context: ExecutionContext, next: CallHandler): Observable<any> {
    const request = context.switchToHttp().getRequest<Request>();
    const response = context.switchToHttp().getResponse();

    // Coletar informações básicas
    const startTime = Date.now();
    const userAgent = request.get('user-agent') || '';
    const ipAddress = this.getClientIp(request);
    const method = request.method;
    const url = request.url;
    const userId = (request as any).user?.id;
    const tenantId = (request as any).user?.tenantId;

    return next.handle().pipe(
      tap({
        next: (data) => {
          // Log de sucesso para operações críticas
          this.logSuccessfulOperation(request, response, startTime, {
            userId,
            tenantId,
            ipAddress,
            userAgent
          });
        },
        error: (error) => {
          // Log de falhas de segurança
          this.logSecurityViolation(request, error, {
            userId,
            tenantId,
            ipAddress,
            userAgent
          });
        }
      })
    );
  }

  private logSuccessfulOperation(
    request: Request,
    response: any,
    startTime: number,
    context: { userId?: string; tenantId?: string; ipAddress: string; userAgent: string }
  ) {
    const method = request.method;
    const url = request.url;
    const statusCode = response.statusCode;
    const duration = Date.now() - startTime;

    // Operações que merecem log automático
    const criticalOperations = [
      'POST /auth/login',
      'POST /auth/register',
      'PUT /users/profile',
      'POST /users',
      'DELETE /users',
      'POST /tenants',
      'PUT /tenants',
      'DELETE /tenants',
      'POST /modules',
      'PUT /modules',
      'DELETE /modules'
    ];

    const operationKey = `${method} ${url.split('?')[0]}`;

    if (criticalOperations.includes(operationKey) || statusCode >= 400) {
      this.auditService.log({
        action: `SECURITY_${statusCode < 400 ? 'SUCCESS' : 'FAILED'}_${method}_${url.replace(/\//g, '_').toUpperCase()}`,
        userId: context.userId,
        tenantId: context.tenantId,
        ipAddress: context.ipAddress,
        userAgent: context.userAgent,
        details: {
          method,
          url: url.split('?')[0], // Remove query params
          statusCode,
          durationMs: duration,
          timestamp: new Date().toISOString()
        }
      });
    }
  }

  private logSecurityViolation(
    request: Request,
    error: any,
    context: { userId?: string; tenantId?: string; ipAddress: string; userAgent: string }
  ) {
    const method = request.method;
    const url = request.url;

    // Log violações de segurança
    this.auditService.log({
      action: `SECURITY_VIOLATION_${error.status || 500}_${method}_${url.replace(/\//g, '_').toUpperCase()}`,
      userId: context.userId,
      tenantId: context.tenantId,
      ipAddress: context.ipAddress,
      userAgent: context.userAgent,
      details: {
        method,
        url: url.split('?')[0],
        error: error.message,
        statusCode: error.status || 500,
        stack: process.env.NODE_ENV === 'development' ? error.stack : undefined,
        timestamp: new Date().toISOString()
      }
    });
  }

  private getClientIp(request: Request): string {
    // Ordem de prioridade para obter IP real
    return (
      request.get('x-forwarded-for')?.split(',')[0]?.trim() ||
      request.get('x-real-ip') ||
      request.get('x-client-ip') ||
      request.ip ||
      'unknown'
    );
  }
}

import { Controller, Post, Body, Ip, UseGuards, Get, Req } from '@nestjs/common';
import { Throttle } from '@nestjs/throttler';
import { AuthService } from './auth.service';
import { TwoFactorService } from './two-factor.service';
import { EmailVerificationService } from './email-verification.service';
import { PasswordResetService } from './password-reset.service';
import { LoginDto } from './dto/login.dto';
import { Login2FADto } from './dto/login-2fa.dto';
import { RefreshTokenDto } from './dto/refresh-token.dto';
import { LogoutDto } from './dto/logout.dto';
import { Verify2FADto } from './dto/verify-2fa.dto';
import { VerifyEmailDto } from './dto/verify-email.dto';
import { ForgotPasswordDto } from './dto/forgot-password.dto';
import { ResetPasswordDto } from './dto/reset-password.dto';
import { JwtAuthGuard } from '@core/common/guards/jwt-auth.guard';
import { SkipCsrf } from '@core/common/decorators/skip-csrf.decorator';
import { Request } from 'express';

@Controller('auth')
export class AuthController {
  constructor(
    private authService: AuthService,
    private twoFactorService: TwoFactorService,
    private emailVerificationService: EmailVerificationService,
    private passwordResetService: PasswordResetService,
  ) { }

  /**
   * POST /auth/login
   * Rate Limiting: 5 tentativas por minuto
   * CSRF: Desabilitado - endpoint público de autenticação
   */
  @SkipCsrf()
  @Post('login')
  @Throttle({ login: { limit: 5, ttl: 60000 } }) // 5 tentativas por minuto
  async login(
    @Body() loginDto: LoginDto,
    @Req() req: Request,
    @Ip() ip: string,
  ) {
    const userAgent = req.headers['user-agent'] || 'Unknown';
    return this.authService.login(loginDto, ip, userAgent);
  }

  /**
   * POST /auth/refresh
   * Renovar access token usando refresh token
   * CSRF: Desabilitado - usa refresh token como autenticação
   */
  @SkipCsrf()
  @Post('refresh')
  @Throttle({ default: { limit: 10, ttl: 60000 } }) // 10 tentativas por minuto
  async refresh(
    @Body() refreshTokenDto: RefreshTokenDto,
    @Req() req: Request,
    @Ip() ip: string,
  ) {
    const userAgent = req.headers['user-agent'] || 'Unknown';
    return this.authService.refreshTokens(refreshTokenDto.refreshToken, ip, userAgent);
  }

  /**
   * POST /auth/logout
   * Invalidar refresh token
   */
  @Post('logout')
  @UseGuards(JwtAuthGuard)
  async logout(
    @Body() logoutDto: LogoutDto,
    @Req() req: any,
    @Ip() ip: string,
  ) {
    const userAgent = req.headers['user-agent'] || 'Unknown';
    return this.authService.logout(logoutDto.refreshToken, req.user.id, ip, userAgent);
  }

  /**
   * POST /auth/login-2fa
   * Login com 2FA
   * CSRF: Desabilitado - endpoint público de autenticação
   */
  @SkipCsrf()
  @Post('login-2fa')
  @Throttle({ login: { limit: 5, ttl: 60000 } })
  async login2FA(
    @Body() login2FADto: Login2FADto,
    @Req() req: Request,
    @Ip() ip: string,
  ) {
    const userAgent = req.headers['user-agent'] || 'Unknown';
    return this.authService.login2FA(login2FADto, ip, userAgent);
  }

  /**
   * GET /auth/2fa/generate
   * Gerar QR Code para 2FA
   */
  @Get('2fa/generate')
  @UseGuards(JwtAuthGuard)
  async generate2FA(@Req() req: any) {
    return this.twoFactorService.generateSecret(req.user.id);
  }

  /**
   * POST /auth/2fa/enable
   * Ativar 2FA
   */
  @Post('2fa/enable')
  @UseGuards(JwtAuthGuard)
  async enable2FA(@Body() verify2FADto: Verify2FADto, @Req() req: any) {
    return this.twoFactorService.enable(req.user.id, verify2FADto.token);
  }

  /**
   * POST /auth/2fa/disable
   * Desativar 2FA
   */
  @Post('2fa/disable')
  @UseGuards(JwtAuthGuard)
  async disable2FA(@Body() verify2FADto: Verify2FADto, @Req() req: any) {
    return this.twoFactorService.disable(req.user.id, verify2FADto.token);
  }
  /**
   * GET /auth/2fa/status
   * Verificar status de 2FA do usuário logado
   */
  @Get('2fa/status')
  @UseGuards(JwtAuthGuard)
  async get2FAStatus(@Req() req: any) {
    const user = await this.authService.getProfile(req.user.id);
    return {
      enabled: user.twoFactorEnabled || false,
      suggested: true, // Esta informação virá da configuração de segurança
    };
  }

  /**
   * GET /auth/me
   * Retornar dados do usuário logado
   */
  @Get('me')
  @UseGuards(JwtAuthGuard)
  async getProfile(@Req() req: any) {
    return this.authService.getProfile(req.user.id);
  }

  /**
   * POST /auth/email/send-verification
   * Enviar email de verificação
   */
  @Post('email/send-verification')
  @UseGuards(JwtAuthGuard)
  @Throttle({ default: { limit: 3, ttl: 3600000 } }) // 3 tentativas por hora
  async sendVerificationEmail(@Req() req: any) {
    return this.emailVerificationService.sendVerificationEmail(req.user.id);
  }

  /**
   * POST /auth/email/verify
   * Verificar email com token
   * CSRF: Desabilitado - endpoint público
   */
  @SkipCsrf()
  @Post('email/verify')
  @Throttle({ default: { limit: 10, ttl: 60000 } }) // 10 tentativas por minuto
  async verifyEmail(@Body() verifyEmailDto: VerifyEmailDto) {
    return this.emailVerificationService.verifyEmail(verifyEmailDto.token);
  }

  /**
   * GET /auth/email/status
   * Verificar status de verificação de email
   */
  @Get('email/status')
  @UseGuards(JwtAuthGuard)
  async checkEmailVerification(@Req() req: any) {
    return this.emailVerificationService.checkEmailVerification(req.user.id);
  }

  /**
   * POST /auth/forgot-password
   * Solicitar recuperação de senha
   * CSRF: Desabilitado - endpoint público
   */
  @SkipCsrf()
  @Post('forgot-password')
  @Throttle({ default: { limit: 3, ttl: 3600000 } }) // 3 tentativas por hora
  async forgotPassword(@Body() forgotPasswordDto: ForgotPasswordDto) {
    return this.passwordResetService.requestPasswordReset(forgotPasswordDto.email);
  }

  /**
   * POST /auth/reset-password
   * Redefinir senha com token
   * CSRF: Desabilitado - endpoint público
   */
  @SkipCsrf()
  @Post('reset-password')
  @Throttle({ default: { limit: 5, ttl: 3600000 } }) // 5 tentativas por hora
  async resetPassword(@Body() resetPasswordDto: ResetPasswordDto) {
    return this.passwordResetService.resetPassword(
      resetPasswordDto.token,
      resetPasswordDto.newPassword
    );
  }
}

import { Injectable, UnauthorizedException, Inject, forwardRef } from '@nestjs/common';
import { JwtService } from '@nestjs/jwt';
import { ConfigService } from '@nestjs/config';
import { PrismaService } from '@core/prisma/prisma.service';
import { AuditService } from '../audit/audit.service';
import { TwoFactorService } from './two-factor.service';
import { TokenBlacklistService } from '../common/services/token-blacklist.service';
import * as bcrypt from 'bcrypt';
import * as crypto from 'crypto';
import { LoginDto } from './dto/login.dto';
import { Login2FADto } from './dto/login-2fa.dto';

@Injectable()
export class AuthService {
  constructor(
    private prisma: PrismaService,
    private jwtService: JwtService,
    private config: ConfigService,
    @Inject(forwardRef(() => AuditService))
    private auditService: AuditService,
    @Inject(forwardRef(() => TwoFactorService))
    private twoFactorService: TwoFactorService,
    private tokenBlacklistService: TokenBlacklistService,
  ) {
    // Empty implementation
  }

  async login(loginDto: LoginDto, ipAddress?: string, userAgent?: string) {
    const { email, password } = loginDto;

    // Busca o usuário pelo email
    const user = await this.prisma.user.findUnique({
      where: { email },
      include: { tenant: true },
    });

    if (!user) {
      // Log de tentativa de login falha
      await this.auditService.log({
        action: 'LOGIN_FAILED',
        ipAddress,
        userAgent,
        details: { email, reason: 'user_not_found' },
      });
      throw new UnauthorizedException('Credenciais inválidas');
    }

    // Verificar se o usuário está bloqueado
    if (user.isLocked) {
      // Verificar se o bloqueio ainda está ativo
      if (user.lockedUntil && user.lockedUntil > new Date()) {
        const minutesRemaining = Math.ceil(
          (user.lockedUntil.getTime() - new Date().getTime()) / 60000,
        );

        await this.auditService.log({
          action: 'LOGIN_BLOCKED',
          userId: user.id,
          tenantId: user.tenantId,
          ipAddress,
          userAgent,
          details: { email, reason: 'account_locked', minutesRemaining },
        });

        throw new UnauthorizedException(
          `Conta bloqueada por múltiplas tentativas de login. Tente novamente em ${minutesRemaining} minuto(s) ou contate um administrador.`,
        );
      } else {
        // Bloqueio expirou, desbloquear automaticamente
        await this.prisma.user.update({
          where: { id: user.id },
          data: {
            isLocked: false,
            loginAttempts: 0,
            lockedAt: null,
            lockedUntil: null,
          },
        });
      }
    }

    // Verifica a senha usando bcrypt.compare()
    const isPasswordValid = await bcrypt.compare(password, user.password);

    if (!isPasswordValid) {
      // Buscar configurações de segurança
      const securityConfig = await this.prisma.securityConfig.findFirst();
      const maxAttempts = securityConfig?.loginMaxAttempts || 5;
      const lockDurationMinutes = securityConfig?.loginLockDurationMinutes || 30;

      // Incrementar tentativas de login
      const newAttempts = user.loginAttempts + 1;

      // Atualizar tentativas
      const updateData: any = {
        loginAttempts: newAttempts,
        lastFailedLoginAt: new Date(),
      };

      // Se atingiu o máximo de tentativas, bloquear
      if (newAttempts >= maxAttempts) {
        const lockedUntil = new Date();
        lockedUntil.setMinutes(lockedUntil.getMinutes() + lockDurationMinutes);

        updateData.isLocked = true;
        updateData.lockedAt = new Date();
        updateData.lockedUntil = lockedUntil;

        await this.prisma.user.update({
          where: { id: user.id },
          data: updateData,
        });

        await this.auditService.log({
          action: 'ACCOUNT_LOCKED',
          userId: user.id,
          tenantId: user.tenantId,
          ipAddress,
          userAgent,
          details: { email, attempts: newAttempts, lockedUntil, maxAttempts, lockDurationMinutes },
        });

        throw new UnauthorizedException(
          `Conta bloqueada por múltiplas tentativas de login. Tente novamente em ${lockDurationMinutes} minutos ou contate um administrador.`,
        );
      }

      // Atualizar tentativas sem bloquear
      await this.prisma.user.update({
        where: { id: user.id },
        data: updateData,
      });

      // Avisar se está próximo do bloqueio (1 tentativa restante)
      const attemptsRemaining = maxAttempts - newAttempts;
      let errorMessage = 'Credenciais inválidas';

      if (attemptsRemaining === 1) {
        errorMessage = `Credenciais inválidas. ATENÇÃO: Você tem apenas ${attemptsRemaining} tentativa restante antes de sua conta ser bloqueada por ${lockDurationMinutes} minutos.`;
      } else if (attemptsRemaining <= 3) {
        errorMessage = `Credenciais inválidas. Você tem ${attemptsRemaining} tentativas restantes.`;
      }

      // Log de tentativa de login falha
      await this.auditService.log({
        action: 'LOGIN_FAILED',
        userId: user.id,
        tenantId: user.tenantId,
        ipAddress,
        userAgent,
        details: { email, reason: 'invalid_password', attempts: newAttempts, attemptsRemaining, maxAttempts },
      });

      throw new UnauthorizedException(errorMessage);
    }

    // Login bem-sucedido - resetar tentativas
    if (user.loginAttempts > 0) {
      await this.prisma.user.update({
        where: { id: user.id },
        data: {
          loginAttempts: 0,
          lastFailedLoginAt: null,
        },
      });
    }

    // Verificar se 2FA é obrigatório para este usuário
    const securityConfig = await this.prisma.securityConfig.findFirst();
    const is2FARequired = securityConfig?.twoFactorRequired || false;
    const is2FARequiredForAdmins = securityConfig?.twoFactorRequiredForAdmins || false;
    const isAdmin = user.role === 'ADMIN' || user.role === 'SUPER_ADMIN';

    // Se 2FA é obrigatório e usuário não tem ativado
    if ((is2FARequired || (is2FARequiredForAdmins && isAdmin)) && !user.twoFactorEnabled) {
      // Log de aviso
      await this.auditService.log({
        action: 'LOGIN_2FA_REQUIRED',
        userId: user.id,
        tenantId: user.tenantId,
        ipAddress,
        userAgent,
        details: {
          email,
          reason: is2FARequired ? '2fa_globally_required' : '2fa_required_for_admins',
          role: user.role
        },
      });

      throw new UnauthorizedException(
        '2FA é obrigatório para sua conta. Por favor, ative a autenticação de dois fatores antes de fazer login.',
      );
    }

    // Gera tokens
    const tokens = await this.generateTokens(user.id, user.email, user.role, user.tenantId);

    // Log de login bem-sucedido
    await this.auditService.log({
      action: 'LOGIN_SUCCESS',
      userId: user.id,
      tenantId: user.tenantId,
      ipAddress,
      userAgent,
      details: { email },
    });

    return {
      accessToken: tokens.accessToken,
      refreshToken: tokens.refreshToken,
      user: {
        id: user.id,
        email: user.email,
        name: user.name,
        role: user.role,
        tenantId: user.tenantId,
        tenant: user.tenant,
        // Remover dados sensíveis
        twoFactorSecret: undefined,
      },
    };
  }

  /**
   * Gera access token e refresh token
   */
  async generateTokens(userId: string, email: string, role: string, tenantId: string | null) {
    const payload = {
      sub: userId,
      email,
      role,
      tenantId,
    };

    // Access Token: 15 minutos (configurável)
    const accessToken = this.jwtService.sign(payload, {
      expiresIn: this.config.get('JWT_ACCESS_EXPIRES_IN', '15m'),
    });

    // Refresh Token: token aleatório
    const refreshToken = crypto.randomBytes(64).toString('hex');

    // Salvar refresh token no banco
    const expiresIn = this.config.get('JWT_REFRESH_EXPIRES_IN', '7d');
    const expiresAt = this.calculateExpirationDate(expiresIn);

    await this.prisma.refreshToken.create({
      data: {
        token: refreshToken,
        userId,
        expiresAt,
      },
    });

    return {
      accessToken,
      refreshToken,
    };
  }

  /**
   * Renovar access token usando refresh token
   */
  async refreshTokens(refreshToken: string, ipAddress?: string, userAgent?: string) {
    // Buscar refresh token no banco
    const storedToken = await this.prisma.refreshToken.findUnique({
      where: { token: refreshToken },
      include: { user: { include: { tenant: true } } },
    });

    if (!storedToken) {
      throw new UnauthorizedException('Refresh token inválido');
    }

    // Verificar se expirou
    if (storedToken.expiresAt < new Date()) {
      // Remover token expirado
      await this.prisma.refreshToken.delete({
        where: { id: storedToken.id },
      });
      throw new UnauthorizedException('Refresh token expirado');
    }

    // Gerar novos tokens
    const tokens = await this.generateTokens(
      storedToken.user.id,
      storedToken.user.email,
      storedToken.user.role,
      storedToken.user.tenantId,
    );

    // Remover refresh token antigo (rotação)
    await this.prisma.refreshToken.delete({
      where: { id: storedToken.id },
    });

    // Log de refresh
    await this.auditService.log({
      action: 'TOKEN_REFRESHED',
      userId: storedToken.user.id,
      tenantId: storedToken.user.tenantId,
      ipAddress,
      userAgent,
      details: { email: storedToken.user.email },
    });

    return {
      accessToken: tokens.accessToken,
      refreshToken: tokens.refreshToken,
      user: {
        id: storedToken.user.id,
        email: storedToken.user.email,
        name: storedToken.user.name,
        role: storedToken.user.role,
        tenantId: storedToken.user.tenantId,
        tenant: storedToken.user.tenant,
        // Remover dados sensíveis
        twoFactorSecret: undefined,
      },
    };
  }

  /**
   * Logout - invalida refresh token e adiciona à blacklist
   */
  async logout(refreshToken: string, userId: string, ipAddress?: string, userAgent?: string) {
    // Buscar o refresh token para obter a data de expiração
    const storedToken = await this.prisma.refreshToken.findUnique({
      where: { token: refreshToken },
    });

    if (storedToken) {
      // Adicionar token à blacklist
      await this.tokenBlacklistService.blacklistToken(
        refreshToken,
        storedToken.expiresAt,
        userId
      );

      // Remover refresh token do banco
      await this.prisma.refreshToken.delete({
        where: { id: storedToken.id },
      });
    }

    // Log de logout
    await this.auditService.log({
      action: 'LOGOUT',
      userId,
      ipAddress,
      userAgent,
    });

    return { message: 'Logout realizado com sucesso' };
  }

  /**
   * Calcular data de expiração baseado em string (ex: "7d", "30d")
   */
  private calculateExpirationDate(expiresIn: string): Date {
    const now = new Date();
    const match = expiresIn.match(/^(\d+)([smhd])$/);

    if (!match) {
      // Padrão: 7 dias
      return new Date(now.getTime() + 7 * 24 * 60 * 60 * 1000);
    }

    const value = parseInt(match[1]);
    const unit = match[2];

    switch (unit) {
      case 's': // segundos
        return new Date(now.getTime() + value * 1000);
      case 'm': // minutos
        return new Date(now.getTime() + value * 60 * 1000);
      case 'h': // horas
        return new Date(now.getTime() + value * 60 * 60 * 1000);
      case 'd': // dias
        return new Date(now.getTime() + value * 24 * 60 * 60 * 1000);
      default:
        return new Date(now.getTime() + 7 * 24 * 60 * 60 * 1000);
    }
  }

  /**
   * Login com 2FA
   */
  async login2FA(login2FADto: Login2FADto, ipAddress?: string, userAgent?: string) {
    const { email, password, twoFactorToken } = login2FADto;

    // Busca o usuário
    const user = await this.prisma.user.findUnique({
      where: { email },
      include: { tenant: true },
    });

    if (!user) {
      await this.auditService.log({
        action: 'LOGIN_2FA_FAILED',
        ipAddress,
        userAgent,
        details: { email, reason: 'user_not_found' },
      });
      throw new UnauthorizedException('Credenciais inválidas');
    }

    // Verificar se está bloqueado
    if (user.isLocked) {
      if (user.lockedUntil && user.lockedUntil > new Date()) {
        const minutesRemaining = Math.ceil(
          (user.lockedUntil.getTime() - new Date().getTime()) / 60000,
        );
        throw new UnauthorizedException(
          `Conta bloqueada. Tente novamente em ${minutesRemaining} minuto(s).`,
        );
      }
    }

    // Verificar senha
    const isPasswordValid = await bcrypt.compare(password, user.password);

    if (!isPasswordValid) {
      await this.auditService.log({
        action: 'LOGIN_2FA_FAILED',
        userId: user.id,
        tenantId: user.tenantId,
        ipAddress,
        userAgent,
        details: { email, reason: 'invalid_password' },
      });
      throw new UnauthorizedException('Credenciais inválidas');
    }

    // Verificar se 2FA está ativado
    if (!user.twoFactorEnabled || !user.twoFactorSecret) {
      throw new UnauthorizedException('2FA não está ativado para este usuário');
    }

    // Verificar código 2FA
    const is2FAValid = this.twoFactorService.verify(user.twoFactorSecret, twoFactorToken);

    if (!is2FAValid) {
      await this.auditService.log({
        action: 'LOGIN_2FA_FAILED',
        userId: user.id,
        tenantId: user.tenantId,
        ipAddress,
        userAgent,
        details: { email, reason: 'invalid_2fa_token' },
      });
      throw new UnauthorizedException('Código 2FA inválido');
    }

    // Login bem-sucedido - resetar tentativas
    if (user.loginAttempts > 0) {
      await this.prisma.user.update({
        where: { id: user.id },
        data: {
          loginAttempts: 0,
          lastFailedLoginAt: null,
        },
      });
    }

    // Gerar tokens
    const tokens = await this.generateTokens(user.id, user.email, user.role, user.tenantId);

    // Log de login bem-sucedido
    await this.auditService.log({
      action: 'LOGIN_2FA_SUCCESS',
      userId: user.id,
      tenantId: user.tenantId,
      ipAddress,
      userAgent,
      details: { email },
    });

    return {
      accessToken: tokens.accessToken,
      refreshToken: tokens.refreshToken,
      user: {
        id: user.id,
        email: user.email,
        name: user.name,
        role: user.role,
        tenantId: user.tenantId,
        tenant: user.tenant,
        // Remover dados sensíveis
        twoFactorSecret: undefined,
      },
    };
  }

  async hashPassword(password: string): Promise<string> {
    const saltRounds = 10;
    return bcrypt.hash(password, saltRounds);
  }

  /**
   * Buscar dados do perfil do usuário
   */
  async getProfile(userId: string) {
    const user = await this.prisma.user.findUnique({
      where: { id: userId },
      include: { tenant: true },
    });

    if (!user) {
      throw new UnauthorizedException('Usuário não encontrado');
    }

    return {
      id: user.id,
      email: user.email,
      name: user.name,
      role: user.role,
      tenantId: user.tenantId,
      tenant: user.tenant,
      twoFactorEnabled: user.twoFactorEnabled,
      // Remover dados sensíveis
      twoFactorSecret: undefined,
    };
  }
}

 import { Injectable, BadRequestException, Logger } from '@nestjs/common';
import { PrismaService } from '@core/prisma/prisma.service';
import { EmailService } from '../email/email.service';
import { JwtService } from '@nestjs/jwt';
import { ConfigService } from '@nestjs/config';
import * as bcrypt from 'bcrypt';

@Injectable()
export class PasswordResetService {
  private readonly logger = new Logger(PasswordResetService.name);

  constructor(
    private prisma: PrismaService,
    private emailService: EmailService,
    private jwtService: JwtService,
    private config: ConfigService,
  ) {
      // Empty implementation
    }

  /**
   * Solicitar recuperação de senha
   */
  async requestPasswordReset(email: string): Promise<{ message: string }> {
    try {
      // Verificar se o usuário existe
      const user = await this.prisma.user.findUnique({
        where: { email: email.toLowerCase() },
      });

      // Por segurança, sempre retornamos sucesso mesmo se o email não existir
      // Isso evita que atacantes descubram quais emails estão cadastrados
      if (!user) {
        this.logger.warn(`Tentativa de reset de senha para email não cadastrado: ${email}`);
        return {
          message: 'Se o email estiver cadastrado, você receberá as instruções para redefinir sua senha.',
        };
      }

      // Verificar se o usuário não está bloqueado
      if (user.isLocked) {
        this.logger.warn(`Tentativa de reset de senha para usuário bloqueado: ${email}`);
        return {
          message: 'Se o email estiver cadastrado, você receberá as instruções para redefinir sua senha.',
        };
      }

      // Gerar token JWT para reset de senha (expira em 1 hora)
      const resetToken = this.jwtService.sign(
        { 
          userId: user.id, 
          email: user.email,
          type: 'password-reset'
        },
        {
          secret: this.config.get('JWT_SECRET'),
          expiresIn: '1h', // Token expira em 1 hora
        }
      );

      // Salvar o token no banco de dados para validação posterior
      await this.prisma.passwordResetToken.create({
        data: {
          userId: user.id,
          token: resetToken,
          expiresAt: new Date(Date.now() + 60 * 60 * 1000), // 1 hora
        },
      });

      // Enviar email de recuperação
      const emailSent = await this.emailService.sendPasswordResetEmail(
        user.email,
        user.name,
        resetToken
      );

      if (!emailSent) {
        this.logger.error(`Falha ao enviar email de recuperação para: ${email}`);
        throw new BadRequestException('Erro interno. Tente novamente mais tarde.');
      }

      this.logger.log(`Email de recuperação enviado para: ${email}`);

      return {
        message: 'Se o email estiver cadastrado, você receberá as instruções para redefinir sua senha.',
      };

    } catch (error) {
      this.logger.error('Erro ao processar solicitação de reset de senha:', error);

      if (error instanceof BadRequestException) {
        throw error;
      }

      throw new BadRequestException('Erro interno. Tente novamente mais tarde.');
    }
  }

  /**
   * Redefinir senha com token
   */
  async resetPassword(token: string, newPassword: string): Promise<{ message: string }> {
    try {
      // Verificar e decodificar o token
      let payload;
      try {
        payload = this.jwtService.verify(token, {
          secret: this.config.get('JWT_SECRET'),
        });
      } catch (error) {
        this.logger.warn('Token de reset inválido ou expirado');
        throw new BadRequestException('Token inválido ou expirado. Solicite um novo link de recuperação.');
      }

      // Verificar se é um token de reset de senha
      if (payload.type !== 'password-reset') {
        this.logger.warn('Token não é do tipo password-reset');
        throw new BadRequestException('Token inválido.');
      }

      // Verificar se o token existe no banco de dados e não foi usado
      const resetTokenRecord = await this.prisma.passwordResetToken.findFirst({
        where: {
          token,
          userId: payload.userId,
          usedAt: null,
          expiresAt: {
            gt: new Date(), // Token não expirado
          },
        },
        include: {
          user: true,
        },
      });

      if (!resetTokenRecord) {
        this.logger.warn('Token de reset não encontrado ou já usado');
        throw new BadRequestException('Token inválido ou expirado. Solicite um novo link de recuperação.');
      }

      // Verificar se o usuário ainda existe e não está bloqueado
      if (!resetTokenRecord.user || resetTokenRecord.user.isLocked) {
        this.logger.warn('Usuário não encontrado ou bloqueado');
        throw new BadRequestException('Usuário não encontrado ou bloqueado.');
      }

      // Hash da nova senha
      const saltRounds = 12;
      const hashedPassword = await bcrypt.hash(newPassword, saltRounds);

      // Atualizar a senha do usuário e marcar o token como usado
      await this.prisma.$transaction([
        // Atualizar senha do usuário
        this.prisma.user.update({
          where: { id: resetTokenRecord.userId },
          data: {
            password: hashedPassword,
            // Resetar tentativas de login se houver
            loginAttempts: 0,
            lockedUntil: null,
          },
        }),
        // Marcar token como usado
        this.prisma.passwordResetToken.update({
          where: { id: resetTokenRecord.id },
          data: { usedAt: new Date() },
        }),
        // Invalidar todos os outros tokens de reset do usuário
        this.prisma.passwordResetToken.updateMany({
          where: {
            userId: resetTokenRecord.userId,
            usedAt: null,
            id: { not: resetTokenRecord.id },
          },
          data: { usedAt: new Date() },
        }),
      ]);

      this.logger.log(`Senha redefinida com sucesso para usuário: ${resetTokenRecord.user.email}`);

      return {
        message: 'Senha redefinida com sucesso. Você já pode fazer login com sua nova senha.',
      };

    } catch (error) {
      this.logger.error('Erro ao redefinir senha:', error);

      if (error instanceof BadRequestException) {
        throw error;
      }

      throw new BadRequestException('Erro interno. Tente novamente mais tarde.');
    }
  }

  /**
   * Limpar tokens expirados (pode ser chamado por um cron job)
   */
  async cleanupExpiredTokens(): Promise<void> {
    try {
      const result = await this.prisma.passwordResetToken.deleteMany({
        where: {
          OR: [
            { expiresAt: { lt: new Date() } }, // Tokens expirados
            { usedAt: { not: null } }, // Tokens já usados
          ],
        },
      });

      this.logger.log(`Limpeza de tokens: ${result.count} tokens removidos`);
    } catch (error) {
      this.logger.error('Erro ao limpar tokens expirados:', error);
    }
  }
}

