import { RolesGuard } from '../common/guards/roles.guard';
import { BackupService } from './backup.service';
import { CreateBackupDto } from './dto/create-backup.dto';
import { RestoreRequestDto } from './dto/restore-request.dto';
import { SseJwtGuard } from './guards/sse-jwt.guard';

@Controller('backup')
export class BackupController {
  private readonly logger = new Logger(BackupController.name);
  private progressSubjects = new Map<string, Subject<MessageEvent>>();

  constructor(private backupService: BackupService) {}

  @Sse('progress/:sessionId')
  @UseGuards(SseJwtGuard, RolesGuard)
  @Roles(Role.SUPER_ADMIN)
  backupProgress(@Param('sessionId') sessionId: string): Observable<MessageEvent> {
    let subject = this.progressSubjects.get(sessionId);
    if (!subject) {
      subject = new Subject<MessageEvent>();
      this.progressSubjects.set(sessionId, subject);
    }
    return subject.asObservable();
  }

  @Post('create')
  @UseGuards(JwtAuthGuard, RolesGuard)
  @Roles(Role.SUPER_ADMIN)
  @Throttle({ default: { limit: 5, ttl: 3600000 } })
  async createBackup(@Body() dto: CreateBackupDto, @Request() req) {
    try {
      const userId = req.user?.id || req.user?.sub;
      if (!userId) {
        throw new HttpException('Usuário não autenticado', HttpStatus.UNAUTHORIZED);
      }

      const ipAddress = req.ip;
      const sessionId = dto.sessionId || `session_${Date.now()}`;
      if (!this.progressSubjects.has(sessionId)) {
        this.progressSubjects.set(sessionId, new Subject<MessageEvent>());
      }

      const progressCallback = (message: string) => {
        const subject = this.progressSubjects.get(sessionId);
        if (subject) {
          subject.next({ data: { message, timestamp: Date.now() } } as MessageEvent);
        }
      };

      const result = await this.backupService.createBackup(dto, userId, ipAddress, progressCallback);

      const subject = this.progressSubjects.get(sessionId);
      if (subject) {
        subject.next({ data: { message: 'Backup concluído!', completed: true } } as MessageEvent);
        subject.complete();
        this.progressSubjects.delete(sessionId);
      }

      return { success: true, message: 'Backup criado com sucesso', data: { ...result, sessionId } };
    } catch (error: any) {
      throw new HttpException(error.message || 'Erro ao criar backup', error.status || HttpStatus.INTERNAL_SERVER_ERROR);
    }
  }

  @Get('download/:backupId')
  @UseGuards(SseJwtGuard, RolesGuard)
  @Roles(Role.SUPER_ADMIN)
  async downloadBackup(@Param('backupId') backupId: string, @Res() res: Response) {
    try {
      const backupInfo = await this.backupService.getBackupInfo(backupId);
      if (!backupInfo) {
        throw new HttpException('Backup não encontrado', HttpStatus.NOT_FOUND);
      }

      const filePath = path.join(this.backupService['tempDir'], backupInfo.fileName);
      if (!fs.existsSync(filePath)) {
        throw new HttpException('Arquivo de backup não encontrado', HttpStatus.NOT_FOUND);
      }

      res.setHeader('Content-Type', 'application/octet-stream');
      res.setHeader('Content-Disposition', `attachment; filename="${backupInfo.fileName}"`);
      res.setHeader('Content-Length', backupInfo.fileSize.toString());
      fs.createReadStream(filePath).pipe(res);
    } catch (error: any) {
      throw new HttpException(error.message || 'Erro ao fazer download', error.status || HttpStatus.INTERNAL_SERVER_ERROR);
    }
  }

  @Post('restore')
  @UseGuards(JwtAuthGuard, RolesGuard)
  @Roles(Role.SUPER_ADMIN)
  @Throttle({ default: { limit: 10, ttl: 3600000 } })
  async restoreBackup(@Body() dto: RestoreRequestDto, @Request() req) {
    try {
      const userId = req.user?.id || req.user?.sub;
      if (!userId) {
        throw new HttpException('Usuário não autenticado', HttpStatus.UNAUTHORIZED);
      }

      const ipAddress = req.ip;
      const userAgent = req.headers?.['user-agent'] as string | undefined;
      const result = await this.backupService.restoreFromBackup(dto, userId, ipAddress, userAgent);

      return { success: true, message: 'Restore executado com sucesso', data: result };
    } catch (error: any) {
      throw new HttpException(error.message || 'Erro ao executar restore', error.status || HttpStatus.INTERNAL_SERVER_ERROR);
    }
  }

  @Get('restore-logs')
  @UseGuards(JwtAuthGuard, RolesGuard)
  @Roles(Role.SUPER_ADMIN)
  async getRestoreLogs(@Query('limit') limit?: string) {
    const limitNum = limit ? parseInt(limit, 10) : 50;
    const data = await this.backupService.listRestoreLogs(limitNum);
    return { success: true, data, total: data.length };
  }

  @Get('restore-logs/:id')
  @UseGuards(JwtAuthGuard, RolesGuard)
  @Roles(Role.SUPER_ADMIN)
  async getRestoreLog(@Param('id') id: string) {
    const data = await this.backupService.getRestoreLog(id);
    return { success: true, data };
  }

  @Post('validate')
  @UseInterceptors(FileInterceptor('file'))
  async validateBackup(@UploadedFile() file: Express.Multer.File) {
    try {
      if (!file) {
        throw new HttpException('Arquivo não fornecido', HttpStatus.BAD_REQUEST);
      }

      const validationResult = await this.backupService.validateBackupFile(file);
      return { valid: validationResult.valid, fileInfo: validationResult.info };
    } catch (error: any) {
      throw new HttpException(error.message || 'Erro ao validar arquivo', error.status || HttpStatus.INTERNAL_SERVER_ERROR);
    }
  }

  @Get('available')
  @UseGuards(JwtAuthGuard, RolesGuard)
  @Roles(Role.SUPER_ADMIN)
  async getAvailableBackups() {
    try {
      const backups = await this.backupService.listAvailableBackups();
      return {
        success: true,
        data: backups.map((backup) => ({
          fileName: backup.fileName,
          fileSize: backup.fileSize,
          createdAt: backup.createdAt,
          backupId: backup.backupId,
        })),
        total: backups.length,
      };
    } catch {
      throw new HttpException('Erro ao listar backups', HttpStatus.INTERNAL_SERVER_ERROR);
    }
  }

  @Get('download-file/:fileName')
  @UseGuards(JwtAuthGuard, RolesGuard)
  @Roles(Role.SUPER_ADMIN)
  async downloadBackupFile(@Param('fileName') fileName: string, @Res() res: Response) {
    try {
      if (!/^[a-zA-Z0-9._-]+$/.test(fileName)) {
        throw new HttpException('Nome de arquivo invalido', HttpStatus.BAD_REQUEST);
      }

      const normalizedName = path.basename(fileName);
      if (normalizedName !== fileName) {
        throw new HttpException('Nome de arquivo invalido', HttpStatus.BAD_REQUEST);
      }

      const backupsDir = path.resolve(this.backupService.getBackupsDir());
      const candidatePath = path.resolve(path.join(backupsDir, normalizedName));
      if (!candidatePath.startsWith(backupsDir + path.sep)) {
        throw new HttpException('Acesso a caminho invalido', HttpStatus.BAD_REQUEST);
      }

      const backups = await this.backupService.listAvailableBackups();
      const backup = backups.find((b) => b.fileName === normalizedName);
      if (!backup || !fs.existsSync(backup.filePath)) {
        throw new HttpException('Backup não encontrado', HttpStatus.NOT_FOUND);
      }

      res.setHeader('Content-Type', 'application/octet-stream');
      res.setHeader('Content-Disposition', `attachment; filename="${backup.fileName}"`);
      res.setHeader('Content-Length', backup.fileSize.toString());
      res.setHeader('Cache-Control', 'no-cache');
      res.setHeader('Pragma', 'no-cache');
      res.setHeader('Expires', '0');

      const fileStream = fs.createReadStream(backup.filePath);
      fileStream.on('error', (error) => {
        this.logger.error(`Erro ao ler arquivo de backup: ${error.message}`);
        if (!res.headersSent) {
          res.status(HttpStatus.INTERNAL_SERVER_ERROR).json({ success: false, message: 'Erro ao ler arquivo de backup' });
        }
      });
      fileStream.pipe(res);
    } catch (error: any) {
      this.logger.error(`Erro no download: ${error.message}`);
      throw new HttpException(error.message || 'Erro ao fazer download', error.status || HttpStatus.INTERNAL_SERVER_ERROR);
    }
  }

  @Delete('delete/:fileName')
  @UseGuards(JwtAuthGuard, RolesGuard)
  @Roles(Role.SUPER_ADMIN)
  @Throttle({ default: { limit: 20, ttl: 3600000 } })
  async deleteBackup(@Param('fileName') fileName: string, @Request() req) {
    try {
      const userId = req.user?.id || req.user?.sub;
      if (!userId) {
        throw new HttpException('Usuário não autenticado', HttpStatus.UNAUTHORIZED);
      }
      const result = await this.backupService.deleteBackup(fileName, userId);
      return { success: true, message: 'Backup apagado com sucesso', data: result };
    } catch (error: any) {
      this.logger.error(`Erro ao apagar backup: ${error.message}`);
      throw new HttpException(error.message || 'Erro ao apagar backup', error.status || HttpStatus.INTERNAL_SERVER_ERROR);
    }
  }

  @Get('logs')
  @UseGuards(JwtAuthGuard, RolesGuard)
  @Roles(Role.SUPER_ADMIN)
  async getLogs(
    @Query('limit') limit?: string,
    @Query('operationType') operationType?: 'BACKUP' | 'RESTORE',
    @Query('status') status?: 'STARTED' | 'SUCCESS' | 'FAILED' | 'CANCELLED',
  ) {
    try {
      const limitNum = limit ? parseInt(limit, 10) : 50;
      if (limitNum > 200) {
        throw new HttpException('Limite máximo de 200 registros', HttpStatus.BAD_REQUEST);
      }

      const logs = await this.backupService.getBackupLogs(limitNum, operationType, status);
      return { success: true, data: logs, total: logs.length };
    } catch {
      throw new HttpException('Erro ao buscar logs', HttpStatus.INTERNAL_SERVER_ERROR);
    }
  }
}

import { Injectable, Logger, HttpException, HttpStatus } from '@nestjs/common';
import { PrismaService } from '../core/prisma/prisma.service';
import { AuditService } from '../audit/audit.service';
import { spawn } from 'child_process';
import { execFile } from 'child_process';
import { promisify } from 'util';
import { createHash } from 'crypto';
import * as fs from 'fs';
import * as path from 'path';
import { CreateBackupDto } from './dto/create-backup.dto';
import { RestoreRequestDto } from './dto/restore-request.dto';
import * as semver from 'semver';

const execFileAsync = promisify(execFile);

/**
 * Serviço responsável por operações de backup e restore do banco de dados
 */
@Injectable()
export class BackupService {
  private readonly logger = new Logger(BackupService.name);
  private readonly tempDir: string;
  private readonly maxFileSize: number;
  private readonly timeout: number;

  constructor(
    private prisma: PrismaService,
    private auditService: AuditService,
  ) {
    // Configurações a partir de variáveis de ambiente
    // Usar diretório permanente para backups (não temporário)
    this.tempDir = process.env.BACKUP_DIR || path.join(process.cwd(), 'backups');
    this.maxFileSize = parseInt(process.env.BACKUP_MAX_SIZE || '2147483648', 10); // 2GB
    this.timeout = parseInt(process.env.BACKUP_TIMEOUT || '900', 10) * 1000; // 15 min em ms

    // Criar diretório de backups se não existir
    this.ensureTempDirExists();
  }

  /**
   * Retorna o diretório raiz onde os backups ficam armazenados.
   */
  getBackupsDir(): string {
    return this.tempDir;
  }

  async restoreFromBackup(
    dto: RestoreRequestDto,
    userId: string,
    ipAddress?: string,
    userAgent?: string,
  ): Promise<{ restoreLogId: string; fileName: string; message: string }> {
    let restoreLog: any;

    try {
      const normalizedName = this.validateBackupFileName(dto.backupFile);
      const filePath = path.resolve(path.join(this.tempDir, normalizedName));
      if (!fs.existsSync(filePath)) {
        throw new HttpException('Arquivo de backup nao encontrado', HttpStatus.NOT_FOUND);
      }

      await this.ensureRestoreNotLocked();

      restoreLog = await (this.prisma as any).backupRestoreLog.create({
        data: {
          fileName: normalizedName,
          status: 'STARTED',
          executedBy: userId,
          metadata: {
            runMigrations: !!dto.runMigrations,
            targetReleaseTag: dto.targetReleaseTag || null,
            mode: dto.mode || 'restore-only',
          },
        },
      });

      await this.auditService.log({
        action: 'BACKUP_RESTORE_STARTED',
        userId,
        ipAddress,
        userAgent,
        details: {
          fileName: normalizedName,
          restoreLogId: restoreLog.id,
          runMigrations: !!dto.runMigrations,
          targetReleaseTag: dto.targetReleaseTag || null,
          mode: dto.mode || 'restore-only',
        },
      });

      const settings: any = await (this.prisma as any).systemSettings.findFirst();
      const composeFile = settings?.composeFile || 'docker-compose.prod.yml';
      const envFile = settings?.envFile || 'install/.env.production';
      this.validateRunnerAllowlist(composeFile, envFile);

      const releaseTag = dto.targetReleaseTag ? semver.clean(dto.targetReleaseTag) : undefined;
      if (dto.targetReleaseTag && !releaseTag) {
        throw new HttpException('targetReleaseTag invalida', HttpStatus.BAD_REQUEST);
      }

      const scriptPath = path.join(process.cwd(), 'install', 'restore-db.sh');
      if (!fs.existsSync(scriptPath)) {
        throw new HttpException('Runner de restore nao encontrado (install/restore-db.sh)', HttpStatus.INTERNAL_SERVER_ERROR);
      }

      const { stdout, stderr } = await execFileAsync('bash', [scriptPath], {
        cwd: process.cwd(),
        timeout: 45 * 60 * 1000,
        maxBuffer: 20 * 1024 * 1024,
        env: {
          ...process.env,
          PROJECT_ROOT: process.cwd(),
          COMPOSE_FILE: composeFile,
          ENV_FILE: envFile,
          BACKUPS_DIR: this.tempDir,
          BACKUP_FILE: normalizedName,
          RUN_MIGRATIONS: dto.runMigrations ? 'true' : 'false',
          RESTORE_MODE: dto.mode || 'restore-only',
          TARGET_RELEASE_TAG: releaseTag || '',
          HEALTH_TIMEOUT: process.env.RESTORE_HEALTH_TIMEOUT || '180',
        },
      });

      await (this.prisma as any).backupRestoreLog.update({
        where: { id: restoreLog.id },
        data: {
          status: 'SUCCESS',
          completedAt: new Date(),
          stdout,
          stderr,
        },
      });

      await this.auditService.log({
        action: 'BACKUP_RESTORE_SUCCESS',
        userId,
        ipAddress,
        userAgent,
        details: { fileName: normalizedName, restoreLogId: restoreLog.id },
      });

      return {
        restoreLogId: restoreLog.id,
        fileName: normalizedName,
        message: 'Restore executado com sucesso',
      };
    } catch (error: any) {
      const stdout = typeof error?.stdout === 'string' ? error.stdout : '';
      const stderr = typeof error?.stderr === 'string' ? error.stderr : '';

      if (restoreLog) {
        await (this.prisma as any).backupRestoreLog.update({
          where: { id: restoreLog.id },
          data: {
            status: 'FAILED',
            completedAt: new Date(),
            stdout,
            stderr,
            errorMessage: error.message || 'Erro no restore',
          },
        });

        await this.auditService.log({
          action: 'BACKUP_RESTORE_FAILED',
          userId,
          ipAddress,
          userAgent,
          details: {
            fileName: dto.backupFile,
            restoreLogId: restoreLog.id,
            error: error.message || 'Erro no restore',
          },
        });
      }

      if (error instanceof HttpException) {
        throw error;
      }
      throw new HttpException(
        `Erro ao executar restore: ${error.message || 'erro desconhecido'}`,
        HttpStatus.INTERNAL_SERVER_ERROR,
      );
    }
  }

  async listRestoreLogs(limit: number = 50): Promise<any[]> {
    const logs = await (this.prisma as any).backupRestoreLog.findMany({
      orderBy: { startedAt: 'desc' },
      take: Math.min(limit, 200),
      include: {
        user: {
          select: { id: true, name: true, email: true },
        },
      },
    });

    return logs.map((log: any) => ({
      id: log.id,
      fileName: log.fileName,
      status: log.status,
      startedAt: log.startedAt,
      completedAt: log.completedAt,
      executedBy: log.user?.name || log.executedBy,
      rollbackReason: log.rollbackReason,
      errorMessage: log.errorMessage,
    }));
  }

  async getRestoreLog(logId: string): Promise<any> {
    const log = await (this.prisma as any).backupRestoreLog.findUnique({
      where: { id: logId },
      include: { user: { select: { id: true, name: true, email: true } } },
    });
    if (!log) {
      throw new HttpException('Log de restore nao encontrado', HttpStatus.NOT_FOUND);
    }
    return log;
  }

  private validateBackupFileName(fileName: string): string {
    if (!/^[a-zA-Z0-9._-]+$/.test(fileName)) {
      throw new HttpException('Nome de arquivo invalido', HttpStatus.BAD_REQUEST);
    }
    const normalizedName = path.basename(fileName);
    if (normalizedName !== fileName) {
      throw new HttpException('Nome de arquivo invalido', HttpStatus.BAD_REQUEST);
    }
    const backupsDir = path.resolve(this.tempDir);
    const candidatePath = path.resolve(path.join(backupsDir, normalizedName));
    if (!candidatePath.startsWith(backupsDir + path.sep)) {
      throw new HttpException('Acesso a caminho invalido', HttpStatus.BAD_REQUEST);
    }
    return normalizedName;
  }

  private validateRunnerAllowlist(composeFile: string, envFile: string): void {
    const allowedCompose = new Set(['docker-compose.prod.yml', 'docker-compose.prod.external.yml']);
    const allowedEnv = new Set(['install/.env.production', '.env.production', '.env']);

    if (!allowedCompose.has(composeFile)) {
      throw new HttpException('composeFile nao permitido para restore', HttpStatus.BAD_REQUEST);
    }
    if (!allowedEnv.has(envFile)) {
      throw new HttpException('envFile nao permitido para restore', HttpStatus.BAD_REQUEST);
    }
  }

  private async ensureRestoreNotLocked(): Promise<void> {
    const runningUpdate = await (this.prisma as any).updateLog.findFirst({
      where: { status: 'STARTED' },
    });
    if (runningUpdate) {
      throw new HttpException('Existe update em andamento. Restore bloqueado.', HttpStatus.CONFLICT);
    }

    const runningRestore = await (this.prisma as any).backupRestoreLog.findFirst({
      where: { status: 'STARTED' },
    });
    if (runningRestore) {
      throw new HttpException('Existe restore em andamento.', HttpStatus.CONFLICT);
    }
  }

  /**
   * Garante que o diretório de backups existe
   */
  private ensureTempDirExists(): void {
    if (!fs.existsSync(this.tempDir)) {
      fs.mkdirSync(this.tempDir, { recursive: true });
      this.logger.log(`Diretório de backups criado: ${this.tempDir}`);
    }
  }

  /**
   * Cria backup completo do banco de dados
   */
  async createBackup(
    dto: CreateBackupDto,
    userId: string,
    ipAddress?: string,
    onProgress?: (message: string) => void,
  ): Promise<{
    backupId: string;
    fileName: string;
    fileSize: number;
    checksum: string;
    downloadUrl: string;
    createdAt: Date;
  }> {
    const startTime = Date.now();
    let backupLog: any;

    try {
      // Validar userId
      if (!userId) {
        throw new Error('UserId é obrigatório para criar backup');
      }

      // Extrair credenciais do DATABASE_URL
      const dbConfig = this.parseDatabaseUrl();

      // Gerar nome do arquivo com timestamp
      const timestamp = new Date().toISOString().replace(/[:.]/g, '-').slice(0, -5);
      const fileName = `backup_${dbConfig.database}_${timestamp}.dump`;
      const filePath = path.join(this.tempDir, fileName);

      // Criar registro de log inicial
      backupLog = await this.prisma.backupLog.create({
        data: {
          operationType: 'BACKUP',
          status: 'STARTED',
          fileName,
          executedBy: userId,
          ipAddress,
          metadata: {
            includeMetadata: dto.includeMetadata,
            compressionLevel: dto.compressionLevel,
          } as any,
        },
      });

      this.logger.log(`Iniciando backup: ${fileName}`);

      // Enviar progresso inicial
      if (onProgress) {
        onProgress(`Iniciando backup do banco de dados ${dbConfig.database}...`);
      }

      // Registrar auditoria
      await this.auditService.log({
        action: 'BACKUP_STARTED',
        userId,
        ipAddress,
        details: { fileName, backupId: backupLog.id },
      });

      // Executar pg_dump com logging de progresso
      const args = this.getPgDumpArgs(dbConfig, filePath);

      this.logger.log('Executando pg_dump...');
      if (onProgress) {
        onProgress('Executando pg_dump - iniciando exportação...');
      }

      await this.executeCommand('pg_dump', args, this.timeout, (progress) => {
        // Log do progresso para debug e envio para frontend
        if (progress.trim()) {
          this.logger.debug(`pg_dump: ${progress.trim()}`);
          if (onProgress) {
            onProgress(progress.trim());
          }
        }
      }, dbConfig.password); // ✅ Passar senha para evitar prompt interativo

      // Verificar se arquivo foi criado
      if (!fs.existsSync(filePath)) {
        throw new Error('Arquivo de backup não foi criado');
      }

      if (onProgress) {
        onProgress('Backup exportado com sucesso, validando arquivo...');
      }

      // Obter tamanho do arquivo
      const stats = fs.statSync(filePath);
      const fileSize = stats.size;

      // Validar tamanho
      if (fileSize === 0) {
        throw new Error('Arquivo de backup está vazio');
      }

      // Gerar checksum
      if (onProgress) {
        onProgress('Calculando checksum de integridade...');
      }
      const checksum = await this.calculateChecksum(filePath);

      // Calcular duração
      const durationSeconds = Math.floor((Date.now() - startTime) / 1000);

      // Atualizar log de backup
      await this.prisma.backupLog.update({
        where: { id: backupLog.id },
        data: {
          status: 'SUCCESS',
          fileSize: BigInt(fileSize),
          completedAt: new Date(),
          durationSeconds,
          metadata: {
            includeMetadata: dto.includeMetadata,
            compressionLevel: dto.compressionLevel,
            checksum,
          } as any,
        },
      });

      // Registrar auditoria de sucesso
      await this.auditService.log({
        action: 'BACKUP_SUCCESS',
        userId,
        ipAddress,
        details: { fileName, backupId: backupLog.id, fileSize, durationSeconds },
      });

      this.logger.log(`Backup criado com sucesso: ${fileName} (${fileSize} bytes)`);

      if (onProgress) {
        onProgress(`Backup finalizado: ${fileName} (${(fileSize / 1024 / 1024).toFixed(2)} MB)`);
      }

      return {
        backupId: backupLog.id,
        fileName,
        fileSize,
        checksum,
        downloadUrl: `/api/backup/download/${backupLog.id}`,
        createdAt: new Date(),
      };

    } catch (error) {
      this.logger.error(`Erro ao criar backup: ${error.message}`, error.stack);

      // Atualizar log com erro
      if (backupLog) {
        await this.prisma.backupLog.update({
          where: { id: backupLog.id },
          data: {
            status: 'FAILED',
            completedAt: new Date(),
            errorMessage: error.message,
            durationSeconds: Math.floor((Date.now() - startTime) / 1000),
          },
        });

        // Registrar auditoria de falha
        await this.auditService.log({
          action: 'BACKUP_FAILED',
          userId,
          ipAddress,
          details: { error: error.message, backupId: backupLog.id },
        });
      }

      throw new HttpException(
        `Erro ao criar backup: ${error.message}`,
        HttpStatus.INTERNAL_SERVER_ERROR,
      );
    }
  }

  /**
   * Faz parse da URL de conexão do banco de dados
   */
  private parseDatabaseUrl(): {
    host: string;
    port: string;
    user: string;
    password: string;
    database: string;
  } {
    const databaseUrl = process.env.DATABASE_URL;
    if (!databaseUrl) {
      throw new Error('DATABASE_URL não configurada');
    }

    try {
      // Formato: postgresql://user:password@host:port/database
      const url = new URL(databaseUrl);

      return {
        host: url.hostname,
        port: url.port || '5432',
        user: url.username,
        password: url.password,
        database: url.pathname.slice(1), // Remove a barra inicial
      };
    } catch (error) {
      throw new Error(`Erro ao fazer parse de DATABASE_URL: ${error.message}`);
    }
  }

  /**
   * Obtém argumentos para pg_dump
   */
  private getPgDumpArgs(
    dbConfig: ReturnType<typeof this.parseDatabaseUrl>,
    filePath: string,
  ): string[] {
    return [
      `--host=${dbConfig.host}`,
      `--port=${dbConfig.port}`,
      `--username=${dbConfig.user}`,
      `--dbname=${dbConfig.database}`,
      '--format=custom',
      '--verbose',
      `--file=${filePath}`,
    ];
  }

  /**
   * Obtém argumentos para pg_restore
   */
  private getPgRestoreArgs(
    dbConfig: ReturnType<typeof this.parseDatabaseUrl>,
    filePath: string,
  ): string[] {
    return [
      `--host=${dbConfig.host}`,
      `--port=${dbConfig.port}`,
      `--username=${dbConfig.user}`,
      `--dbname=${dbConfig.database}`,
      '--clean',
      '--if-exists',
      '--no-owner',
      '--no-acl',
      '--verbose',
      filePath,
    ];
  }

  /**
   * Executa comando shell com timeout e callback de progresso de forma segura
   */
  private async executeCommand(
    command: string,
    args: string[],
    timeoutMs: number,
    onProgress?: (data: string) => void,
    password?: string,
  ): Promise<{ stdout: string; stderr: string }> {
    return new Promise((resolve, reject) => {
      const env = { ...process.env };
      if (password) {
        env.PGPASSWORD = password;
      }

      const childProcess = spawn(command, args, { env });

      let stdout = '';
      let stderr = '';

      const timeout = setTimeout(() => {
        childProcess.kill();
        reject(new Error(`Comando ${command} excedeu o tempo limite de ${timeoutMs}ms`));
      }, timeoutMs);

      if (childProcess.stdout) {
        childProcess.stdout.on('data', (data) => {
          stdout += data.toString();
          if (onProgress) onProgress(data.toString());
        });
      }

      if (childProcess.stderr) {
        childProcess.stderr.on('data', (data) => {
          stderr += data.toString();
          if (onProgress) onProgress(data.toString());
          this.logger.debug(`[${command}]: ${data.toString().trim()}`);
        });
      }

      childProcess.on('close', (code) => {
        clearTimeout(timeout);
        if (code === 0) {
          resolve({ stdout, stderr });
        } else {
          reject(new Error(`Comando ${command} falhou com código ${code}: ${stderr}`));
        }
      });

      childProcess.on('error', (error) => {
        clearTimeout(timeout);
        reject(error);
      });
    });
  }

  /**
   * Calcula checksum SHA256 de um arquivo
   */
  private async calculateChecksum(filePath: string): Promise<string> {
    return new Promise((resolve, reject) => {
      const hash = createHash('sha256');
      const stream = fs.createReadStream(filePath);

      stream.on('data', (data) => hash.update(data));
      stream.on('end', () => resolve(hash.digest('hex')));
      stream.on('error', reject);
    });
  }

  /**
   * Obtém caminho do arquivo de backup
   */
  getBackupFilePath(backupId: string): string {
    // Buscar no banco de dados
    return path.join(this.tempDir, backupId);
  }

  /**
   * Lista todos os arquivos de backup disponíveis no diretório
   */
  async listAvailableBackups(): Promise<Array<{
    fileName: string;
    filePath: string;
    fileSize: number;
    createdAt: Date;
    backupId?: string;
  }>> {
    try {
      const files = fs.readdirSync(this.tempDir);
      const backupFiles = files.filter(file => 
        file.endsWith('.dump') || file.endsWith('.sql') || file.endsWith('.backup')
      );

      const backups = backupFiles.map(fileName => {
        const filePath = path.join(this.tempDir, fileName);
        const stats = fs.statSync(filePath);

        return {
          fileName,
          filePath,
          fileSize: stats.size,
          createdAt: stats.mtime,
        };
      });

      // Buscar informações do banco de dados para arquivos correspondentes
      const backupsWithInfo = await Promise.all(
        backups.map(async (backup) => {
          const dbBackup = await this.prisma.backupLog.findFirst({
            where: {
              fileName: backup.fileName,
              operationType: 'BACKUP',
            },
            orderBy: { startedAt: 'desc' },
          });

          return {
            ...backup,
            backupId: dbBackup?.id,
          };
        })
      );

      // Ordenar por data de criação (mais recentes primeiro)
      return backupsWithInfo.sort((a, b) => b.createdAt.getTime() - a.createdAt.getTime());
    } catch (error) {
      this.logger.error(`Erro ao listar backups: ${error.message}`);
      return [];
    }
  }

  /**
   * Retorna histórico de operações de backup/restore
   */
  async getBackupLogs(
    limit: number = 50,
    operationType?: 'BACKUP' | 'RESTORE',
    status?: 'STARTED' | 'SUCCESS' | 'FAILED' | 'CANCELLED',
  ): Promise<any[]> {
    const logs = await this.prisma.backupLog.findMany({
      where: {
        ...(operationType && { operationType }),
        ...(status && { status }),
      },
      orderBy: { startedAt: 'desc' },
      take: Math.min(limit, 200),
      include: {
        user: {
          select: {
            id: true,
            name: true,
            email: true,
          },
        },
      },
    });

    return logs.map(log => ({
      id: log.id,
      operationType: log.operationType,
      status: log.status,
      fileName: log.fileName,
      fileSize: log.fileSize ? Number(log.fileSize) : null,
      startedAt: log.startedAt,
      completedAt: log.completedAt,
      durationSeconds: log.durationSeconds,
      executedBy: log.user?.name || 'Desconhecido',
      errorMessage: log.errorMessage,
    }));
  }

  /**
   * Obtém informações de um backup específico
   */
  async getBackupInfo(backupId: string): Promise<any> {
    const backup = await this.prisma.backupLog.findUnique({
      where: { id: backupId },
      include: {
        user: {
          select: {
            id: true,
            name: true,
            email: true,
          },
        },
      },
    });

    if (!backup) {
      return null;
    }

    return {
      id: backup.id,
      fileName: backup.fileName,
      fileSize: backup.fileSize ? Number(backup.fileSize) : 0,
      status: backup.status,
      createdAt: backup.startedAt,
      executedBy: backup.user?.name,
    };
  }

  /**
   * Valida arquivo de backup antes de restaurar
   */
  async validateBackupFile(file: Express.Multer.File): Promise<{
    valid: boolean;
    info?: any;
    error?: string;
  }> {
    try {
      // Validar extensão
      const validExtensions = ['.sql', '.dump', '.backup'];
      const ext = path.extname(file.originalname).toLowerCase();

      if (!validExtensions.includes(ext)) {
        return {
          valid: false,
          error: 'Formato de arquivo inválido. Use .sql, .dump ou .backup',
        };
      }

      // Validar tamanho
      if (file.size > this.maxFileSize) {
        return {
          valid: false,
          error: `Arquivo muito grande. Tamanho máximo: ${this.maxFileSize / 1024 / 1024 / 1024}GB`,
        };
      }

      if (file.size === 0) {
        return {
          valid: false,
          error: 'Arquivo vazio',
        };
      }

      // Detectar formato do arquivo
      let isValid = false;
      let detectedFormat = 'UNKNOWN';

      // Verificar se é formato custom/binário do PostgreSQL
      // Formato custom do pg_dump começa com "PGDMP" (magic number)
      if (ext === '.dump' || ext === '.backup') {
        // Ler primeiros 5 bytes para verificar magic number
        const header = file.buffer.toString('ascii', 0, Math.min(5, file.size));

        if (header === 'PGDMP') {
          this.logger.log('✅ Arquivo identificado como PostgreSQL custom format (binário)');
          isValid = true;
          detectedFormat = 'CUSTOM';
        } else {
          // Tentar ler como texto (pode ser dump em formato plain)
          try {
            const content = file.buffer.toString('utf8', 0, Math.min(1000, file.size));
            const isPgDump = content.includes('PostgreSQL') || 
                            content.includes('pg_dump') ||
                            content.includes('CREATE TABLE') ||
                            content.includes('COPY ');

            if (isPgDump) {
              this.logger.log('✅ Arquivo identificado como PostgreSQL plain format (texto)');
              isValid = true;
              detectedFormat = 'PLAIN';
            }
          } catch (err) {
            this.logger.warn('Não foi possível ler arquivo como texto');
          }
        }
      } 
      // Arquivos .sql devem ser texto puro
      else if (ext === '.sql') {
        try {
          const content = file.buffer.toString('utf8', 0, Math.min(1000, file.size));
          const isPgDump = content.includes('PostgreSQL') || 
                          content.includes('pg_dump') ||
                          content.includes('CREATE TABLE') ||
                          content.includes('INSERT INTO') ||
                          content.includes('COPY ');

          if (isPgDump) {
            this.logger.log('✅ Arquivo SQL identificado como backup PostgreSQL');
            isValid = true;
            detectedFormat = 'SQL';
          }
        } catch (err) {
          this.logger.error('Erro ao ler arquivo SQL', err);
        }
      }

      if (!isValid) {
        return {
          valid: false,
          error: 'Arquivo não parece ser um backup PostgreSQL válido. Verifique o formato.',
        };
      }

      return {
        valid: true,
        info: {
          format: detectedFormat,
          extension: ext.replace('.', '').toUpperCase(),
          size: file.size,
          fileName: file.originalname,
        },
      };
    } catch (error) {
      this.logger.error(`Erro ao validar arquivo: ${error.message}`);
      return {
        valid: false,
        error: `Erro na validação: ${error.message}`,
      };
    }
  }

  /**
   * Restaura banco de dados a partir de arquivo de backup
   */
  async restoreBackup(
    file: Express.Multer.File,
    userId: string,
    ipAddress?: string,
  ): Promise<{
    restoreId: string;
    fileName: string;
    durationSeconds: number;
    completedAt: Date;
  }> {
    const startTime = Date.now();
    let restoreLog: any;
    let backupSafetyFile: string | null = null;

    try {
      // Validar userId
      if (!userId) {
        throw new Error('UserId é obrigatório para executar restore');
      }

      // Validar arquivo primeiro
      const validation = await this.validateBackupFile(file);
      if (!validation.valid) {
        throw new Error(validation.error || 'Arquivo inválido');
      }

      // Extrair credenciais do DATABASE_URL
      const dbConfig = this.parseDatabaseUrl();

      // Salvar arquivo temporariamente
      const tempFileName = `restore_${Date.now()}_${file.originalname}`;
      const tempFilePath = path.join(this.tempDir, tempFileName);
      fs.writeFileSync(tempFilePath, file.buffer);

      // Criar registro de log inicial
      restoreLog = await this.prisma.backupLog.create({
        data: {
          operationType: 'RESTORE',
          status: 'STARTED',
          fileName: file.originalname,
          fileSize: BigInt(file.size),
          executedBy: userId,
          ipAddress,
          metadata: {
            originalFileName: file.originalname,
            fileSize: file.size,
          } as any,
        },
      });

      this.logger.log(`Iniciando restore: ${file.originalname}`);

      // Registrar auditoria
      await this.auditService.log({
        action: 'RESTORE_STARTED',
        userId,
        ipAddress,
        details: { fileName: file.originalname, restoreId: restoreLog.id },
      });

      // Criar backup de segurança antes do restore
      this.logger.log('Criando backup de segurança...');
      const safetyBackupName = `safety_backup_${Date.now()}.dump`;
      backupSafetyFile = path.join(this.tempDir, safetyBackupName);

      const safetyArgs = this.getPgDumpArgs(dbConfig, backupSafetyFile);
      await this.executeCommand('pg_dump', safetyArgs, this.timeout, null, dbConfig.password);
      this.logger.log('Backup de segurança criado');

      // Executar pg_restore
      this.logger.log('Executando restore...');
      const restoreArgs = this.getPgRestoreArgs(dbConfig, tempFilePath);
      await this.executeCommand('pg_restore', restoreArgs, this.timeout, (progress) => {
        // Log do progresso para debug
        if (progress.trim()) {
          this.logger.debug(`pg_restore: ${progress.trim()}`);
        }
      }, dbConfig.password);

      // Calcular duração
      const durationSeconds = Math.floor((Date.now() - startTime) / 1000);

      // Atualizar log de restore com proteção contra deleção pelo --clean
      try {
        await this.prisma.backupLog.update({
          where: { id: restoreLog.id },
          data: {
            status: 'SUCCESS',
            completedAt: new Date(),
            durationSeconds,
          },
        });
      } catch (updateError) {
        // Se o log foi deletado pelo pg_restore --clean, criar novo
        this.logger.warn(`Log foi deletado durante restore, recriando: ${updateError.message}`);
        try {
          restoreLog = await this.prisma.backupLog.create({
            data: {
              operationType: 'RESTORE',
              status: 'SUCCESS',
              fileName: file.originalname,
              fileSize: BigInt(file.size),
              executedBy: userId,
              ipAddress,
              startedAt: new Date(startTime),
              completedAt: new Date(),
              durationSeconds,
              metadata: {
                originalFileName: file.originalname,
                fileSize: file.size,
                recreated: true, // Indica que foi recriado
              } as any,
            },
          });
        } catch (createError) {
          this.logger.error(`Erro ao recriar log: ${createError.message}`);
          // Continua mesmo se não conseguir criar o log
        }
      }

      // Registrar auditoria de sucesso
      await this.auditService.log({
        action: 'RESTORE_SUCCESS',
        userId,
        ipAddress,
        details: { fileName: file.originalname, restoreId: restoreLog.id, durationSeconds },
      });

      this.logger.log(`Restore concluído com sucesso: ${file.originalname}`);

      // Limpar arquivos temporários
      if (fs.existsSync(tempFilePath)) {
        fs.unlinkSync(tempFilePath);
      }
      if (backupSafetyFile && fs.existsSync(backupSafetyFile)) {
        // Manter backup de segurança por algumas horas
        setTimeout(() => {
          if (fs.existsSync(backupSafetyFile)) {
            fs.unlinkSync(backupSafetyFile);
          }
        }, 3 * 60 * 60 * 1000); // 3 horas
      }

      return {
        restoreId: restoreLog.id,
        fileName: file.originalname,
        durationSeconds,
        completedAt: new Date(),
      };

    } catch (error) {
      this.logger.error(`Erro ao executar restore: ${error.message}`, error.stack);

      // Atualizar ou criar log com erro
      try {
        if (restoreLog?.id) {
          // Tentar atualizar o log existente
          try {
            await this.prisma.backupLog.update({
              where: { id: restoreLog.id },
              data: {
                status: 'FAILED',
                completedAt: new Date(),
                errorMessage: error.message,
                durationSeconds: Math.floor((Date.now() - startTime) / 1000),
              },
            });
          } catch (updateError) {
            // Se o update falhar (registro não encontrado), criar um novo
            this.logger.warn(`Log não encontrado, criando novo: ${updateError.message}`);
            await this.prisma.backupLog.create({
              data: {
                operationType: 'RESTORE',
                status: 'FAILED',
                fileName: file?.originalname || 'unknown',
                fileSize: BigInt(file?.size || 0),
                executedBy: userId,
                ipAddress,
                completedAt: new Date(),
                errorMessage: error.message,
                durationSeconds: Math.floor((Date.now() - startTime) / 1000),
              },
            });
          }

          // Registrar auditoria de falha
          await this.auditService.log({
            action: 'RESTORE_FAILED',
            userId,
            ipAddress,
            details: { error: error.message, restoreId: restoreLog.id },
          });
        }
      } catch (logError) {
        this.logger.error(`Erro ao registrar falha no log: ${logError.message}`);
      }

      throw new Error(`Erro ao executar restore: ${error.message}`);
    }
  }

  /**
   * Constrói comando pg_restore
   */
  private buildPgRestoreCommand(
    dbConfig: ReturnType<typeof this.parseDatabaseUrl>,
    filePath: string,
  ): string {
    // --clean remove objetos antes de recriar
    // --if-exists usa IF EXISTS ao remover objetos
    // --no-owner não tenta recriar ownership
    // --no-acl não restaura privilégios de acesso
    return `pg_restore --host=${dbConfig.host} --port=${dbConfig.port} --username=${dbConfig.user} --dbname=${dbConfig.database} --clean --if-exists --no-owner --no-acl --verbose "${filePath}"`;
  }

  /**
   * Apaga um arquivo de backup
   */
  async deleteBackup(
    fileName: string,
    userId: string,
  ): Promise<{ fileName: string; deleted: boolean }> {
    try {
      // Validar nome do arquivo (segurança)
      if (!fileName || fileName.includes('..') || fileName.includes('/') || fileName.includes('\\')) {
        throw new HttpException(
          'Nome de arquivo inválido',
          HttpStatus.BAD_REQUEST,
        );
      }

      const filePath = path.join(this.tempDir, fileName);

      // Verificar se arquivo existe
      if (!fs.existsSync(filePath)) {
        throw new HttpException(
          'Arquivo de backup não encontrado',
          HttpStatus.NOT_FOUND,
        );
      }

      // Apagar arquivo do sistema de arquivos
      fs.unlinkSync(filePath);

      this.logger.log(`Backup apagado: ${fileName} por usuário ${userId}`);

      // Registrar auditoria
      await this.auditService.log({
        action: 'BACKUP_DELETED',
        userId,
        details: { fileName },
      });

      return {
        fileName,
        deleted: true,
      };
    } catch (error) {
      this.logger.error(`Erro ao apagar backup: ${error.message}`);

      if (error instanceof HttpException) {
        throw error;
      }

      throw new HttpException(
        `Erro ao apagar backup: ${error.message}`,
        HttpStatus.INTERNAL_SERVER_ERROR,
      );
    }
  }

  /**
   * Limpa arquivos temporários antigos
   */
  async cleanupOldBackups(retentionHours: number = 1): Promise<void> {
    const cutoffTime = new Date(Date.now() - retentionHours * 60 * 60 * 1000);

    try {
      const files = fs.readdirSync(this.tempDir);
      let deletedCount = 0;

      for (const file of files) {
        const filePath = path.join(this.tempDir, file);
        const stats = fs.statSync(filePath);

        if (stats.isFile() && stats.mtime < cutoffTime) {
          fs.unlinkSync(filePath);
          deletedCount++;
          this.logger.log(`Arquivo temporário removido: ${file}`);
        }
      }

      if (deletedCount > 0) {
        this.logger.log(`Limpeza concluída: ${deletedCount} arquivo(s) removido(s)`);
      }
    } catch (error) {
      this.logger.error(`Erro ao limpar arquivos temporários: ${error.message}`);
    }
  }
}

import {
  ExceptionFilter,
  Catch,
  ArgumentsHost,
  HttpException,
  HttpStatus,
} from '@nestjs/common';
import { Request, Response } from 'express';
import * as Sentry from '@sentry/node';

@Catch()
export class SentryExceptionFilter implements ExceptionFilter {
  catch(exception: unknown, host: ArgumentsHost) {
    const ctx = host.switchToHttp();
    const response = ctx.getResponse<Response>();
    const request = ctx.getRequest<Request>();

    const status =
      exception instanceof HttpException
        ? exception.getStatus()
        : HttpStatus.INTERNAL_SERVER_ERROR;

    const message =
      exception instanceof HttpException
        ? exception.getResponse()
        : 'Internal server error';

    // Capturar no Sentry apenas erros 500+
    if (status >= 500) {
      Sentry.captureException(exception, {
        contexts: {
          http: {
            method: request.method,
            url: request.url,
            status_code: status,
          },
        },
        user: (request as any).user
          ? {
            id: (request as any).user.id,
            email: (request as any).user.email,
            role: (request as any).user.role,
          }
          : undefined,
      });
    }

    // Retornar resposta ao cliente
    response.status(status).json({
      statusCode: status,
      timestamp: new Date().toISOString(),
      path: request.url,
      message: typeof message === 'string' ? message : (message as any).message,
    });
  }
}

import {
  Injectable,
  CanActivate,
  ExecutionContext,
  ForbiddenException,
} from '@nestjs/common';
import { Reflector } from '@nestjs/core';
import * as crypto from 'crypto';

export const SKIP_CSRF_KEY = 'skipCsrf';

/**
 * CSRF Guard - Proteção contra Cross-Site Request Forgery
 * 
 * Implementa Double Submit Cookie pattern:
 * 1. Backend gera token CSRF e envia via cookie
 * 2. Frontend lê cookie e envia token em header X-CSRF-Token
 * 3. Backend valida se token do header = token do cookie
 * 
 * Métodos seguros (GET, HEAD, OPTIONS) são isentos de validação
 */
@Injectable()
export class CsrfGuard implements CanActivate {
  constructor(private reflector: Reflector) { }

  canActivate(context: ExecutionContext): boolean {
    // Verifica se a rota está marcada para pular CSRF
    const skipCsrf = this.reflector.getAllAndOverride<boolean>(SKIP_CSRF_KEY, [
      context.getHandler(),
      context.getClass(),
    ]);

    if (skipCsrf) {
      return true;
    }

    const request = context.switchToHttp().getRequest();
    const response = context.switchToHttp().getResponse();
    const method = request.method.toUpperCase();

    // Validar origem da requisição
    if (!this.isValidOrigin(request)) {
      throw new ForbiddenException('Origem da requisição inválida');
    }

    // Métodos seguros não precisam de validação CSRF
    const safeMethods = ['GET', 'HEAD', 'OPTIONS'];
    if (safeMethods.includes(method)) {
      // Gerar e enviar token CSRF para métodos seguros
      this.setCsrfToken(request, response);
      return true;
    }

    // Para métodos não seguros, validar token CSRF
    const cookieToken = request.cookies?.['XSRF-TOKEN'];
    const headerToken = request.headers['x-csrf-token'] || request.headers['x-xsrf-token'];

    // Em desenvolvimento, ser mais tolerante
    if (process.env.NODE_ENV !== 'production') {
      if (!cookieToken && !headerToken) {
        // Gerar token automaticamente em DEV se ambos estiverem ausentes
        this.setCsrfToken(request, response);
        return true;
      }

      // Se apenas um estiver presente, permitir em DEV
      if (cookieToken || headerToken) {
        return true;
      }
    }

    if (!cookieToken || !headerToken) {
      this.logSuspiciousActivity(request, 'TOKEN_MISSING');
      throw new ForbiddenException('Token CSRF ausente');
    }

    if (cookieToken !== headerToken) {
      this.logSuspiciousActivity(request, 'TOKEN_MISMATCH');
      throw new ForbiddenException('Token CSRF inválido');
    }

    // Validar timestamp do token (opcional, para tokens com expiração)
    if (!this.isValidTokenAge(cookieToken)) {
      this.logSuspiciousActivity(request, 'TOKEN_EXPIRED');
      throw new ForbiddenException('Token CSRF expirado');
    }

    return true;
  }

  /**
   * Gera e define token CSRF no cookie
   */
  private setCsrfToken(request: any, response: any): void {
    // Se já existe token válido, não gerar novo
    if (request.cookies?.['XSRF-TOKEN']) {
      return;
    }

    // Gerar token aleatório
    const token = crypto.randomBytes(32).toString('hex');

    // Definir cookie com token CSRF
    // httpOnly: false - permite JavaScript ler o cookie
    // sameSite: 'lax' - mais compatível com desenvolvimento
    response.cookie('XSRF-TOKEN', token, {
      httpOnly: false, // Precisa ser acessível pelo JavaScript
      secure: process.env.NODE_ENV === 'production', // HTTPS apenas em produção
      sameSite: process.env.NODE_ENV === 'production' ? 'strict' : 'lax',
      path: '/',
      maxAge: 24 * 60 * 60 * 1000, // 24 horas
    });
  }

  /**
   * Valida a origem da requisição
   */
  private isValidOrigin(request: any): boolean {
    const origin = request.headers.origin;
    const referer = request.headers.referer;

    // Em ambiente de desenvolvimento, ser mais permissivo
    if (process.env.NODE_ENV !== 'production') {
      // Permitir localhost e IPs locais
      if (origin) {
        try {
          const originUrl = new URL(origin);
          if (originUrl.hostname === 'localhost' ||
            originUrl.hostname === '127.0.0.1' ||
            originUrl.hostname.startsWith('192.168.') ||
            originUrl.hostname.startsWith('10.')) {
            return true;
          }
        } catch {
          // URL inválida, continuar verificação
        }
      }
      return true; // Permitir tudo em DEV
    }

    // Lista de origens permitidas
    const allowedOrigins = [
      process.env.FRONTEND_URL,
      'https://seu-dominio.com',
      'https://www.seu-dominio.com'
    ].filter(Boolean);

    // Validar Origin header
    if (origin && allowedOrigins.includes(origin)) {
      return true;
    }

    // Validar Referer header como fallback
    if (referer) {
      try {
        const refererUrl = new URL(referer);
        return allowedOrigins.some(allowed =>
          refererUrl.origin === allowed
        );
      } catch {
        return false;
      }
    }

    return false;
  }

  /**
   * Valida a idade do token CSRF
   */
  private isValidTokenAge(token: string): boolean {
    // Tokens CSRF são stateless por padrão
    // Esta validação pode ser implementada com timestamp embutido
    // ou usando armazenamento em sessão/cache
    return token.length === 64; // Verificar comprimento esperado
  }

  /**
   * Log de atividades suspeitas
   */
  private logSuspiciousActivity(request: any, reason: string): void {
    console.warn('🚨 Atividade suspeita detectada:', {
      reason,
      ip: request.ip || request.connection?.remoteAddress,
      userAgent: request.headers['user-agent'],
      method: request.method,
      url: request.url,
      timestamp: new Date().toISOString()
    });
  }
}

import { Injectable, ExecutionContext } from '@nestjs/common';
import {
    ThrottlerGuard,
    ThrottlerException,
    ThrottlerStorage,
    ThrottlerModuleOptions,
    InjectThrottlerOptions,
    InjectThrottlerStorage,
    ThrottlerLimitDetail,
} from '@nestjs/throttler';
import { Reflector } from '@nestjs/core';

@Injectable()
export class SecurityThrottlerGuard extends ThrottlerGuard {
    constructor(
        @InjectThrottlerOptions() options: ThrottlerModuleOptions,
        @InjectThrottlerStorage() storageService: ThrottlerStorage,
        reflector: Reflector,
    ) {
        super(options, storageService, reflector);
    }

    protected async handleRequest(
        requestProps: any // Em v6 é ThrottlerRequest
    ): Promise<boolean> {
        const { context, limit, ttl, throttler } = requestProps;
        const isProduction = process.env.NODE_ENV === 'production';

        // Logica simplificada sem DB por enquanto para testar se volta o serviço
        if (throttler?.name === 'login') {
            return super.handleRequest(requestProps);
        }

        const req = context.switchToHttp().getRequest();
        const hasAuth = req.headers?.authorization || req.user;

        if (hasAuth) {
            // 10000 requisições por minuto para usuários autenticados
            return super.handleRequest({
                ...requestProps,
                limit: 10000,
                ttl: 60000
            });
        }

        // Limites padrão seguros
        const finalLimit = isProduction ? 100 : 10000;
        const finalWindow = 60000;

        return super.handleRequest({
            ...requestProps,
            limit: finalLimit,
            ttl: finalWindow
        });
    }

    protected async throwThrottlingException(
        _context: ExecutionContext,
        _throttlerLimitDetail: ThrottlerLimitDetail,
    ): Promise<void> {
        throw new ThrottlerException(
            'Limite de requisições atingido. Para evitar sobrecarga, o sistema bloqueou novas tentativas. Tente novamente em instantes.'
        );
    }
}

import { CanActivate, ExecutionContext, Injectable, Logger } from '@nestjs/common';
import { JwtService } from '@nestjs/jwt';
import { ConfigService } from '@nestjs/config';
import { PrismaService } from '@core/prisma/prisma.service';

@Injectable()
export class WsJwtGuard implements CanActivate {
  private readonly logger = new Logger(WsJwtGuard.name);

  constructor(
    private jwtService: JwtService,
    private configService: ConfigService,
    private prismaService: PrismaService,
  ) { }

  async canActivate(context: ExecutionContext): Promise<boolean> {
    this.logger.log(`🔐 WsJwtGuard: INÍCIO - Verificando cliente`);
    try {
      const client = context.switchToWs().getClient();
      const token = this.extractToken(client);

      this.logger.log(`🔐 WsJwtGuard: Cliente ${client.id} - Token extraído:`, token ? 'Presente' : 'Ausente');

      if (!token) {
        this.logger.warn('❌ Conexão WebSocket rejeitada: Nenhum token fornecido');
        return false;
      }

      const payload = this.jwtService.verify(token, {
        secret: this.configService.get('JWT_SECRET'),
      });

      if (!payload.sub) {
        this.logger.warn('Conexão WebSocket rejeitada: Payload de token inválido');
        return false;
      }

      const user = await this.prismaService.user.findUnique({
        where: { id: payload.sub },
        include: { tenant: true }
      });

      if (!user) {
        this.logger.warn(`Conexão WebSocket rejeitada: Usuário não encontrado (${payload.sub})`);
        return false;
      }

      // Anexar contexto do usuário ao cliente
      (client as any).user = {
        id: user.id,
        tenantId: user.tenantId,
        role: user.role,
        email: user.email,
        name: user.name
      };

      this.logger.log(`✅ Autenticação WebSocket bem-sucedida: Usuário ${user.id} (${user.email})`);
      this.logger.log(`✅ User anexado ao cliente:`, (client as any).user);
      return true;

    } catch (error) {
      this.logger.error('❌ EXCEPTION na autenticação WebSocket:', error);
      this.logger.error('❌ Stack trace:', error.stack);
      return false;
    }
  }

  private extractToken(client: any): string | null {
    return client.handshake?.auth?.token ||
      client.handshake?.headers?.authorization?.replace('Bearer ', '') ||
      null;
  }
}

import { Injectable, NestInterceptor, ExecutionContext, CallHandler } from '@nestjs/common';
import { Observable } from 'rxjs';
import { tap } from 'rxjs/operators';

@Injectable()
export class DuplicateRequestInterceptor implements NestInterceptor {
  private requestLog = new Map<string, number>();
  private readonly DUPLICATE_THRESHOLD = 1000; // 1 segundo

  intercept(context: ExecutionContext, next: CallHandler): Observable<any> {
    const request = context.switchToHttp().getRequest();
    const method = request.method;
    const url = request.url;
    const userAgent = request.headers['user-agent'] || 'unknown';
    const ip = request.ip || 'unknown';

    // Cria uma chave única para a requisição
    const requestKey = `${method}:${url}:${ip}:${userAgent}`;
    const now = Date.now();

    // Verifica se é uma requisição duplicada
    const lastRequest = this.requestLog.get(requestKey);
    if (lastRequest && (now - lastRequest) < this.DUPLICATE_THRESHOLD) {
      console.warn(`🚨 [DUPLICATE] Possível requisição duplicada detectada:`, {
        method,
        url,
        ip,
        timeSinceLastRequest: now - lastRequest,
        userAgent: userAgent.substring(0, 50)
      });
    }

    // Atualiza o log
    this.requestLog.set(requestKey, now);

    // Limpa entradas antigas a cada 100 requisições
    if (this.requestLog.size > 1000) {
      const cutoff = now - (this.DUPLICATE_THRESHOLD * 10);
      for (const [key, timestamp] of this.requestLog.entries()) {
        if (timestamp < cutoff) {
          this.requestLog.delete(key);
        }
      }
    }

    return next.handle().pipe(
      tap(() => {
        // Log da requisição bem-sucedida
        if (url.includes('/modules/') && url.includes('/toggle')) {
          // Additional logging if needed
        }
      })
    );
  }
}

import {
  Injectable,
  NestInterceptor,
  ExecutionContext,
  CallHandler,
  ForbiddenException,
} from '@nestjs/common';
import { Observable } from 'rxjs';
import { Reflector } from '@nestjs/core';

export const SKIP_TENANT_ISOLATION = 'skipTenantIsolation';

@Injectable()
export class TenantInterceptor implements NestInterceptor {
  constructor(private reflector: Reflector) {
      // Empty implementation
    }

  intercept(context: ExecutionContext, next: CallHandler): Observable<any> {
    const request = context.switchToHttp().getRequest();
    const user = request.user;

    // SEMPRE validar tenantId mesmo para SUPER_ADMIN
    const skipIsolation = this.reflector.getAllAndOverride<boolean>(
      SKIP_TENANT_ISOLATION,
      [context.getHandler(), context.getClass()],
    );

    if (user && !skipIsolation) {
      // Validar que tenantId do payload corresponde ao usuário
      const payloadTenantId = request.body?.tenantId || request.query?.tenantId;

      // Para usuários normais, validar que o tenantId do payload bate com o do usuário
      if (payloadTenantId && payloadTenantId !== user.tenantId && user.role !== 'SUPER_ADMIN') {
        throw new ForbiddenException('Acesso negado a dados de outro tenant');
      }

      // Para SUPER_ADMIN, ainda validar contexto mas permitir acesso cross-tenant
      // quando explicitamente autorizado
      if (user.role === 'SUPER_ADMIN' && payloadTenantId) {
        // Registrar acesso cross-tenant para auditoria
        console.warn(`SUPER_ADMIN acessando tenant ${payloadTenantId}`, {
          userId: user.id,
          fromTenant: user.tenantId,
          toTenant: payloadTenantId,
          timestamp: new Date().toISOString()
        });
      }

      request.tenantId = user.tenantId;
    }

    return next.handle();
  }
}

import { PipeTransform, Injectable, ArgumentMetadata } from '@nestjs/common';
import * as sanitizeHtml from 'sanitize-html';

/**
 * Pipe para sanitização automática de inputs
 * Remove espaços em branco extras e previne injeções
 */
@Injectable()
export class SanitizationPipe implements PipeTransform {
  transform(value: unknown, metadata: ArgumentMetadata) {
    if (!value) return value;

    // Se for objeto, sanitiza recursivamente
    if (typeof value === 'object' && !Array.isArray(value)) {
      return this.sanitizeObject(value);
    }

    // Se for array, sanitiza cada item
    if (Array.isArray(value)) {
      return value.map((item) => this.transform(item, metadata));
    }

    // Se for string, sanitiza
    if (typeof value === 'string') {
      return this.sanitizeString(value);
    }

    return value;
  }

  private sanitizeObject(obj: any): any {
    const sanitized: any = {};

    for (const key in obj) {
      if (Object.prototype.hasOwnProperty.call(obj, key)) {
        const value = obj[key];

        if (typeof value === 'string') {
          sanitized[key] = this.sanitizeString(value);
        } else if (typeof value === 'object' && value !== null) {
          sanitized[key] = this.sanitizeObject(value);
        } else {
          sanitized[key] = value;
        }
      }
    }

    return sanitized;
  }

  private sanitizeString(str: string): string {
    // Remove espaços em branco no início e fim
    let sanitized = str.trim();

    // Remove múltiplos espaços consecutivos
    sanitized = sanitized.replace(/\s+/g, ' ');

    // Sanitização robusta contra XSS usando sanitize-html
    // Remove tags HTML e atributos perigosos, mas mantém texto seguro
    sanitized = sanitizeHtml(sanitized, {
      allowedTags: [], // Remove TODAS as tags HTML
      allowedAttributes: {}, // Remove TODOS os atributos
      disallowedTagsMode: 'recursiveEscape', // Escapa o conteúdo das tags em vez de remover
    });

    return sanitized;
  }
}

 import { Injectable } from '@nestjs/common';
import { PrismaService } from '@core/prisma/prisma.service';
import * as bcrypt from 'bcrypt';

@Injectable()
export class PasswordHistoryService {
  constructor(private prisma: PrismaService) {
      // Empty implementation
    }

  /**
   * Verificar se a senha já foi usada recentemente
   */
  async isPasswordReused(userId: string, newPassword: string): Promise<{
    isReused: boolean;
    message?: string;
  }> {
    const user = await this.prisma.user.findUnique({
      where: { id: userId },
    });

    if (!user || !user.passwordHistory) {
      return { isReused: false };
    }

    // Buscar configuração de limite de reutilização
    const securityConfig = await this.prisma.securityConfig.findFirst();
    const reuseLimit = securityConfig?.passwordReuseLimit || 5;

    try {
      const passwordHistory: string[] = JSON.parse(user.passwordHistory);

      // Verificar contra cada senha no histórico
      for (let i = 0; i < passwordHistory.length; i++) {
        const isMatch = await bcrypt.compare(newPassword, passwordHistory[i]);
        if (isMatch) {
          const _positionInHistory = i + 1;
          return {
            isReused: true,
            message: `Esta senha já foi utilizada recentemente. Você não pode reutilizar as últimas ${reuseLimit} senhas.`,
          };
        }
      }

      return { isReused: false };
    } catch (error) {
      // Se houver erro ao parsear JSON, considerar que não há histórico
      return { isReused: false };
    }
  }

  /**
   * Adicionar nova senha ao histórico
   */
  async addPasswordToHistory(userId: string, hashedPassword: string): Promise<void> {
    const user = await this.prisma.user.findUnique({
      where: { id: userId },
    });

    if (!user) {
      return;
    }

    // Buscar configuração de limite
    const securityConfig = await this.prisma.securityConfig.findFirst();
    const reuseLimit = securityConfig?.passwordReuseLimit || 5;

    let passwordHistory: string[] = [];

    if (user.passwordHistory) {
      try {
        passwordHistory = JSON.parse(user.passwordHistory);
      } catch (error) {
        passwordHistory = [];
      }
    }

    // Adicionar nova senha no início do array
    passwordHistory.unshift(hashedPassword);

    // Manter apenas as últimas N senhas
    if (passwordHistory.length > reuseLimit) {
      passwordHistory = passwordHistory.slice(0, reuseLimit);
    }

    // Salvar histórico atualizado
    await this.prisma.user.update({
      where: { id: userId },
      data: {
        passwordHistory: JSON.stringify(passwordHistory),
        lastPasswordChange: new Date(),
      },
    });
  }

  /**
   * Validar requisitos de complexidade de senha
   */
  async validatePasswordComplexity(password: string): Promise<{
    isValid: boolean;
    errors: string[];
  }> {
    const securityConfig = await this.prisma.securityConfig.findFirst();
    const errors: string[] = [];

    const minLength = securityConfig?.passwordMinLength || 8;
    const requireUppercase = securityConfig?.passwordRequireUppercase ?? true;
    const requireLowercase = securityConfig?.passwordRequireLowercase ?? true;
    const requireNumbers = securityConfig?.passwordRequireNumbers ?? true;
    const requireSpecial = securityConfig?.passwordRequireSpecial ?? true;

    if (password.length < minLength) {
      errors.push(`A senha deve ter no mínimo ${minLength} caracteres`);
    }

    if (requireUppercase && !/[A-Z]/.test(password)) {
      errors.push('A senha deve conter pelo menos uma letra maiúscula');
    }

    if (requireLowercase && !/[a-z]/.test(password)) {
      errors.push('A senha deve conter pelo menos uma letra minúscula');
    }

    if (requireNumbers && !/\d/.test(password)) {
      errors.push('A senha deve conter pelo menos um número');
    }

    if (requireSpecial && !/[!@#$%^&*()_+\-=[\]{};':"\\|,.<>/?]/.test(password)) {
      errors.push('A senha deve conter pelo menos um caractere especial');
    }

    return {
      isValid: errors.length === 0,
      errors,
    };
  }

  /**
   * Verificar se senha é comum/fraca
   */
  isCommonPassword(password: string): boolean {
    // Lista de senhas mais comuns (top 100)
    const commonPasswords = [
      '123456', 'password', '12345678', 'qwerty', '123456789', '12345',
      '1234', '111111', '1234567', 'dragon', '123123', 'baseball', 'iloveyou',
      '121212', 'trustno1', 'monkey', 'liverpoo', 'dragon', 'princess', 'qwertyuiop',
      'starwars', 'montypython', 'superman', 'michael', 'michelle', 'football',
      'password1', 'abc123', '000000', 'letmein', 'liverpool', 'master', 'sunshine',
      'ashley', 'bailey', 'passw0rd', 'shadow', 'charlie', 'qwerty123', 'admin',
      'welcome', 'solo', 'jesus', 'ninja', 'mustang', 'password123', 'freedom',
      'whatever', 'starwars', 'test', 'trustno1', 'football1', 'secret', 'love'
    ];

    return commonPasswords.includes(password.toLowerCase());
  }

  /**
   * Gerar sugestões de senha forte
   */
  generatePasswordSuggestions(): string[] {
    const suggestions = [
      'Use pelo menos 12 caracteres',
      'Combine letras maiúsculas e minúsculas',
      'Inclua números e caracteres especiais',
      'Evite informações pessoais (nome, data de nascimento)',
      'Não reutilize senhas de outros serviços',
      'Use um gerenciador de senhas',
      'Considere usar uma frase-senha (passphrase)',
    ];

    return suggestions;
  }

  /**
   * Calcular força da senha
   */
  calculatePasswordStrength(password: string): {
    score: number; // 0-100
    level: 'weak' | 'medium' | 'strong' | 'very_strong';
    feedback: string[];
  } {
    let score = 0;
    const feedback: string[] = [];

    // Comprimento (até 40 pontos)
    if (password.length >= 8) score += 10;
    if (password.length >= 12) score += 10;
    if (password.length >= 16) score += 10;
    if (password.length >= 20) score += 10;

    // Complexidade (até 40 pontos)
    if (/[a-z]/.test(password)) {
      score += 10;
    } else {
      feedback.push('Adicione letras minúsculas');
    }

    if (/[A-Z]/.test(password)) {
      score += 10;
    } else {
      feedback.push('Adicione letras maiúsculas');
    }

    if (/\d/.test(password)) {
      score += 10;
    } else {
      feedback.push('Adicione números');
    }

    if (/[!@#$%^&*()_+\-=[\]{};':"\\|,.<>/?]/.test(password)) {
      score += 10;
    } else {
      feedback.push('Adicione caracteres especiais');
    }

    // Diversidade (até 20 pontos)
    const uniqueChars = new Set(password).size;
    if (uniqueChars >= 8) score += 5;
    if (uniqueChars >= 12) score += 5;
    if (uniqueChars >= 16) score += 10;

    // Penalidades
    if (this.isCommonPassword(password)) {
      score -= 50;
      feedback.push('Esta senha é muito comum. Escolha uma senha mais única.');
    }

    if (/(.)\1{2,}/.test(password)) {
      score -= 10;
      feedback.push('Evite repetir o mesmo caractere consecutivamente');
    }

    if (/012|123|234|345|456|567|678|789|abc|bcd|cde/.test(password.toLowerCase())) {
      score -= 10;
      feedback.push('Evite sequências óbvias');
    }

    // Garantir que score está entre 0-100
    score = Math.max(0, Math.min(100, score));

    // Determinar nível
    let level: 'weak' | 'medium' | 'strong' | 'very_strong';
    if (score < 40) {
      level = 'weak';
    } else if (score < 60) {
      level = 'medium';
    } else if (score < 80) {
      level = 'strong';
    } else {
      level = 'very_strong';
    }

    return {
      score,
      level,
      feedback,
    };
  }
}

/**
 * Interface e implementações para Secret Management
 *
 * Suporta múltiplos provedores de secret management:
 * - Local (.env files)
 * - AWS Secrets Manager
 * - Azure Key Vault
 * - HashiCorp Vault
 * - Google Secret Manager
 */

export interface Secret {
  name: string;
  value: string;
  version?: string;
  createdDate?: Date;
  lastModifiedDate?: Date;
  description?: string;
}

export interface SecretManager {
  /**
   * Obtém um secret pelo nome
   */
  getSecret(name: string): Promise<Secret | null>;

  /**
   * Cria ou atualiza um secret
   */
  putSecret(name: string, value: string, description?: string): Promise<Secret>;

  /**
   * Deleta um secret
   */
  deleteSecret(name: string): Promise<boolean>;

  /**
   * Lista todos os secrets disponíveis
   */
  listSecrets(prefix?: string): Promise<Secret[]>;

  /**
   * Verifica se o secret manager está configurado corretamente
   */
  isAvailable(): Promise<boolean>;

  /**
   * Nome do provedor
   */
  getProviderName(): string;
}

/**
 * Secret Manager Local - Para desenvolvimento e ambientes simples
 */
export class LocalSecretManager implements SecretManager {
  private secrets: Map<string, Secret> = new Map();

  constructor() {
    // Carregar secrets do processo ou variáveis de ambiente
    this.loadFromEnvironment();
  }

  private loadFromEnvironment(): void {
    // Carregar secrets padrão do ambiente
    const envSecrets = [
      'JWT_SECRET',
      'ENCRYPTION_KEY',
      'DATABASE_URL',
      'SMTP_PASSWORD',
      'SENTRY_DSN'
    ];

    for (const secretName of envSecrets) {
      const value = process.env[secretName];
      if (value) {
        this.secrets.set(secretName, {
          name: secretName,
          value: value,
          createdDate: new Date(),
          lastModifiedDate: new Date()
        });
      }
    }
  }

  async getSecret(name: string): Promise<Secret | null> {
    return this.secrets.get(name) || null;
  }

  async putSecret(name: string, value: string, description?: string): Promise<Secret> {
    const secret: Secret = {
      name,
      value,
      description,
      createdDate: new Date(),
      lastModifiedDate: new Date()
    };

    this.secrets.set(name, secret);
    return secret;
  }

  async deleteSecret(name: string): Promise<boolean> {
    return this.secrets.delete(name);
  }

  async listSecrets(prefix?: string): Promise<Secret[]> {
    const allSecrets = Array.from(this.secrets.values());

    if (prefix) {
      return allSecrets.filter(secret => secret.name.startsWith(prefix));
    }

    return allSecrets;
  }

  async isAvailable(): Promise<boolean> {
    return true; // Sempre disponível localmente
  }

  getProviderName(): string {
    return 'Local';
  }
}

/**
 * AWS Secrets Manager Implementation
 */
export class AWSSecretManager implements SecretManager {
  private client: any; // AWS.SecretsManager

  constructor() {
    try {
      // Import dinâmico para evitar dependência obrigatória
      const AWS = require('aws-sdk');
      this.client = new AWS.SecretsManager({
        region: process.env.AWS_REGION || 'us-east-1'
      });
    } catch (error) {
      console.warn('AWS SDK não disponível:', error.message);
      this.client = null;
    }
  }

  async getSecret(name: string): Promise<Secret | null> {
    if (!this.client) return null;

    try {
      const response = await this.client.getSecretValue({ SecretId: name }).promise();

      return {
        name: response.Name,
        value: response.SecretString,
        version: response.VersionId,
        createdDate: new Date(response.CreatedDate),
        lastModifiedDate: new Date(response.LastChangedDate)
      };
    } catch (error) {
      if (error.code === 'ResourceNotFoundException') {
        return null;
      }
      throw error;
    }
  }

  async putSecret(name: string, value: string, description?: string): Promise<Secret> {
    if (!this.client) {
      throw new Error('AWS Secrets Manager não disponível');
    }

    const params: any = {
      Name: name,
      SecretString: value
    };

    if (description) {
      params.Description = description;
    }

    const response = await this.client.createSecret(params).promise();

    return {
      name: response.Name,
      value,
      version: response.VersionId,
      createdDate: new Date(),
      lastModifiedDate: new Date(),
      description
    };
  }

  async deleteSecret(name: string): Promise<boolean> {
    if (!this.client) return false;

    try {
      await this.client.deleteSecret({
        SecretId: name,
        ForceDeleteWithoutRecovery: false
      }).promise();
      return true;
    } catch (error) {
      console.error('Erro ao deletar secret:', error);
      return false;
    }
  }

  async listSecrets(prefix?: string): Promise<Secret[]> {
    if (!this.client) return [];

    try {
      const params: any = {};
      if (prefix) {
        params.Filters = [{ Key: 'name', Values: [prefix] }];
      }

      const response = await this.client.listSecrets(params).promise();

      return response.SecretList.map((secret: any) => ({
        name: secret.Name,
        value: '', // Não retornamos o valor em listagens
        version: secret.LastChangedDate,
        createdDate: new Date(secret.CreatedDate),
        lastModifiedDate: new Date(secret.LastChangedDate),
        description: secret.Description
      }));
    } catch (error) {
      console.error('Erro ao listar secrets:', error);
      return [];
    }
  }

  async isAvailable(): Promise<boolean> {
    if (!this.client) return false;

    try {
      // Testar conexão básica
      await this.client.listSecrets({ MaxResults: 1 }).promise();
      return true;
    } catch (error) {
      console.warn('AWS Secrets Manager não acessível:', error.message);
      return false;
    }
  }

  getProviderName(): string {
    return 'AWS Secrets Manager';
  }
}

/**
 * Factory para obter o secret manager apropriado
 */
export class SecretManagerFactory {
  static async createSecretManager(): Promise<SecretManager> {
    // Determinar qual secret manager usar baseado em variáveis de ambiente

    // 1. AWS Secrets Manager
    if (process.env.SECRET_PROVIDER === 'aws' || process.env.AWS_SECRET_ACCESS_KEY) {
      const awsManager = new AWSSecretManager();
      if (await awsManager.isAvailable()) {
        // Using AWS Secrets Manager
        return awsManager;
      }
    }

    // 2. Azure Key Vault (implementação futura)
    if (process.env.SECRET_PROVIDER === 'azure' || process.env.AZURE_CLIENT_ID) {
      // Implementar Azure Key Vault
      console.warn('⚠️  Azure Key Vault ainda não implementado');
    }

    // 3. HashiCorp Vault (implementação futura)
    if (process.env.SECRET_PROVIDER === 'vault' || process.env.VAULT_ADDR) {
      // Implementar HashiCorp Vault
      console.warn('⚠️  HashiCorp Vault ainda não implementado');
    }

    // 4. Google Secret Manager (implementação futura)
    if (process.env.SECRET_PROVIDER === 'google' || process.env.GOOGLE_APPLICATION_CREDENTIALS) {
      // Implementar Google Secret Manager
      console.warn('⚠️  Google Secret Manager ainda não implementado');
    }

    // 5. Default: Local Secret Manager
    // Using Local Secret Manager (desenvolvimento)
    return new LocalSecretManager();
  }

  /**
   * Helper para carregar todas as secrets necessárias da aplicação
   */
  static async loadApplicationSecrets(): Promise<void> {
    const secretManager = await this.createSecretManager();

    // Secrets críticas da aplicação
    const requiredSecrets = [
      'JWT_SECRET',
      'ENCRYPTION_KEY',
      'DATABASE_URL'
    ];

    for (const secretName of requiredSecrets) {
      try {
        const secret = await secretManager.getSecret(secretName);
        if (secret && secret.value) {
          process.env[secretName] = secret.value;
          // Secret loaded successfully
        } else {
          console.warn(`⚠️  Secret não encontrado: ${secretName}`);
        }
      } catch (error) {
        console.error(`❌ Erro ao carregar secret ${secretName}:`, error.message);
      }
    }
  }
}

/**
 * Middleware para NestJS que carrega secrets na inicialização
 */
export class SecretLoaderMiddleware {
  static async loadSecrets(): Promise<void> {
    // Loading secrets...
    await SecretManagerFactory.loadApplicationSecrets();

    // Validar secrets críticos
    const criticalSecrets = ['JWT_SECRET', 'ENCRYPTION_KEY'];
    for (const secret of criticalSecrets) {
      if (!process.env[secret]) {
        throw new Error(`Secret crítico não encontrado: ${secret}`);
      }
    }

    // All secrets loaded successfully
  }
}

import { Injectable, Logger } from '@nestjs/common';
import { PrismaService } from '@core/prisma/prisma.service';

type PrismaModelDelegateKey = {
  [K in keyof PrismaService]: PrismaService[K] extends { findMany: (...args: never[]) => Promise<unknown> } ? K : never;
}[keyof PrismaService] & string;

@Injectable()
export class SecurePrismaService {
  private readonly logger = new Logger(SecurePrismaService.name);

  constructor(private prisma: PrismaService) {
    // Empty implementation
  }

  /**
   * Wrapper seguro para findMany com validação automática de tenant isolation
   */
  async findManySecure<T>(
    model: PrismaModelDelegateKey,
    where: any,
    tenantId: string,
    userRole: string,
    options: {
      select?: unknown;
      include?: unknown;
      orderBy?: unknown;
      skip?: number;
      take?: number;
    } = {
        // Empty implementation
      }
  ): Promise<T[]> {
    try {
      // Aplicar tenant isolation automaticamente
      const tenantWhere = userRole !== 'SUPER_ADMIN'
        ? { ...where, tenantId }
        : where;

      // Adicionar logging de segurança para operações sensíveis
      this.logger.debug(`Busca segura em ${String(model)} para tenant ${tenantId}`, {
        userRole,
        whereKeys: Object.keys(where),
        hasTenantFilter: userRole !== 'SUPER_ADMIN'
      });

      const result = await (this.prisma as Record<string, any>)[model].findMany({
        where: tenantWhere,
        select: options.select,
        include: options.include,
        orderBy: options.orderBy,
        skip: options.skip,
        take: options.take
      });

      return result as T[];
    } catch (error) {
      this.logger.error(`Erro na busca segura em ${String(model)}:`, error);
      throw error;
    }
  }

  /**
   * Wrapper seguro para findUnique com validação de ownership
   */
  async findUniqueSecure<T>(
    model: PrismaModelDelegateKey,
    where: any,
    tenantId: string,
    userRole: string,
    options: {
      select?: unknown;
      include?: unknown;
    } = {
        // Empty implementation
      }
  ): Promise<T | null> {
    try {
      const result = await (this.prisma as Record<string, any>)[model].findUnique({
        where,
        select: options.select,
        include: options.include
      });

      if (!result) {
        return null;
      }

      // Para SUPER_ADMIN, permitir acesso a qualquer recurso
      if (userRole === 'SUPER_ADMIN') {
        this.logger.debug(`SUPER_ADMIN acessando recurso em ${String(model)}`, {
          resourceId: where.id,
          tenantId
        });
        return result as T;
      }

      // Verificar se o recurso pertence ao tenant do usuário
      const resourceTenantId = (result as any).tenantId;
      if (resourceTenantId !== tenantId) {
        this.logger.warn(`Tentativa de acesso cross-tenant bloqueada`, {
          model: String(model),
          resourceId: where.id,
          userTenant: tenantId,
          resourceTenant: resourceTenantId,
          userRole
        });
        return null; // Ou lançar exceção, dependendo da política
      }

      return result as T;
    } catch (error) {
      this.logger.error(`Erro na busca única segura em ${String(model)}:`, error);
      throw error;
    }
  }

  /**
   * Wrapper seguro para create com validação de tenant
   */
  async createSecure<T>(
    model: PrismaModelDelegateKey,
    data: any,
    tenantId: string,
    userId: string,
    userRole: string
  ): Promise<T> {
    try {
      // Sempre associar o recurso ao tenant do usuário
      const secureData = {
        ...data,
        tenantId: userRole !== 'SUPER_ADMIN' ? tenantId : (data.tenantId || tenantId),
        createdBy: userId
      };

      this.logger.debug(`Criação segura em ${String(model)}`, {
        model: String(model),
        tenantId,
        userId,
        hasExplicitTenant: !!data.tenantId
      });

      const result = await (this.prisma as Record<string, any>)[model].create({
        data: secureData
      });

      // Logar criação para auditoria
      this.logger.log(`Recurso criado: ${String(model)}`, {
        id: (result as any).id,
        tenantId: (result as any).tenantId,
        createdBy: userId,
        timestamp: new Date().toISOString()
      });

      return result as T;
    } catch (error) {
      this.logger.error(`Erro na criação segura em ${String(model)}:`, error);
      throw error;
    }
  }

  /**
   * Wrapper seguro para update com validação de ownership
   */
  async updateSecure<T>(
    model: PrismaModelDelegateKey,
    where: any,
    data: any,
    tenantId: string,
    userId: string,
    userRole: string
  ): Promise<T> {
    try {
      // Primeiro verificar se o recurso existe e pertence ao tenant
      const existing = await this.findUniqueSecure(
        model,
        where,
        tenantId,
        userRole
      );

      if (!existing) {
        throw new Error('Recurso não encontrado ou acesso não autorizado');
      }

      this.logger.debug(`Atualização segura em ${String(model)}`, {
        resourceId: where.id,
        tenantId,
        userId
      });

      const result = await (this.prisma as Record<string, any>)[model].update({
        where,
        data: {
          ...data,
          updatedBy: userId,
          updatedAt: new Date()
        }
      });

      // Logar atualização para auditoria
      this.logger.log(`Recurso atualizado: ${String(model)}`, {
        id: where.id,
        tenantId: (result as any).tenantId,
        updatedBy: userId,
        timestamp: new Date().toISOString()
      });

      return result as T;
    } catch (error) {
      this.logger.error(`Erro na atualização segura em ${String(model)}:`, error);
      throw error;
    }
  }

  /**
   * Wrapper seguro para delete com validação de ownership
   */
  async deleteSecure<T>(
    model: PrismaModelDelegateKey,
    where: any,
    tenantId: string,
    userId: string,
    userRole: string
  ): Promise<T> {
    try {
      // Verificar ownership antes de deletar
      const existing = await this.findUniqueSecure(
        model,
        where,
        tenantId,
        userRole
      );

      if (!existing) {
        throw new Error('Recurso não encontrado ou acesso não autorizado');
      }

      this.logger.warn(`Exclusão segura em ${String(model)}`, {
        resourceId: where.id,
        tenantId,
        userId,
        userRole
      });

      const result = await (this.prisma as Record<string, any>)[model].delete({
        where
      });

      // Logar exclusão para auditoria
      this.logger.log(`Recurso excluído: ${String(model)}`, {
        id: where.id,
        tenantId: (result as any).tenantId,
        deletedBy: userId,
        timestamp: new Date().toISOString()
      });

      return result as T;
    } catch (error) {
      this.logger.error(`Erro na exclusão segura em ${String(model)}:`, error);
      throw error;
    }
  }

  /**
   * Previnir injeção de SQL em raw queries
   */
  sanitizeRawQuery(query: string, params: unknown[]): string {
    return query.replace(/\$\d+/g, (match, _index) => {
      const paramIndex = parseInt(match.slice(1)) - 1;
      const param = params[paramIndex];

      if (param === null || param === undefined) {
        return 'NULL';
      }

      if (typeof param === 'string') {
        // Escapar aspas simples
        return `'${param.replace(/'/g, "''")}'`;
      }

      if (typeof param === 'number') {
        return String(param);
      }

      if (param instanceof Date) {
        return `'${param.toISOString()}'`;
      }

      // Para objetos/arrays, converter para JSON
      return `'${JSON.stringify(param).replace(/'/g, "''")}'`;
    });
  }

  /**
   * Executar query raw com sanitização
   */
  async executeRawSecure(query: string, params: unknown[] = []): Promise<unknown> {
    try {
      const sanitizedQuery = this.sanitizeRawQuery(query, params);

      this.logger.debug('Executando query raw sanitizada', {
        queryPreview: sanitizedQuery.substring(0, 200) + (sanitizedQuery.length > 200 ? '...' : '')
      });

      // Em produção, usar prepared statements
      return await this.prisma.$executeRawUnsafe(sanitizedQuery, ...params);
    } catch (error) {
      this.logger.error('Erro na execução de query raw:', error);
      throw error;
    }
  }

  /**
   * Obter estatísticas de uso para monitoramento
   */
  getUsageStats(): any {
    // Implementar coleta de métricas de uso do Prisma
    return {
      timestamp: new Date().toISOString(),
      // Adicionar métricas relevantes
    };
  }
}

import * as Sentry from '@sentry/node';
import { Injectable } from '@nestjs/common';
import { ConfigService } from '@nestjs/config';

@Injectable()
export class SentryService {
  constructor(private config: ConfigService) {
    this.init();
  }

  private init() {
    const dsn = this.config.get('SENTRY_DSN');
    const environment = this.config.get('NODE_ENV', 'development');

    // Apenas inicializar se DSN estiver configurado
    if (!dsn) {
      return;
    }

    Sentry.init({
      dsn,
      environment,
      integrations: [],
      // Performance Monitoring
      tracesSampleRate: environment === 'production' ? 0.1 : 1.0, // 10% em produção, 100% em dev
      // Filtrar dados sensíveis
      beforeSend(event, _hint) {
        // Remover dados sensíveis
        if (event.request) {
          // Remover headers sensíveis
          if (event.request.headers) {
            delete event.request.headers['authorization'];
            delete event.request.headers['cookie'];
          }

          // Remover dados sensíveis do body
          if (event.request.data) {
            const data = typeof event.request.data === 'string'
              ? JSON.parse(event.request.data)
              : event.request.data;

            if (data.password) data.password = '[FILTERED]';
            if (data.currentPassword) data.currentPassword = '[FILTERED]';
            if (data.newPassword) data.newPassword = '[FILTERED]';
            if (data.adminPassword) data.adminPassword = '[FILTERED]';
            if (data.refreshToken) data.refreshToken = '[FILTERED]';

            event.request.data = data;
          }
        }

        return event;
      },
    });

  }

  /**
   * Capturar exceção manualmente
   */
  captureException(exception: any, context?: Record<string, unknown>) {
    Sentry.captureException(exception, {
      extra: context,
    });
  }

  /**
   * Capturar mensagem
   */
  captureMessage(message: string, level: Sentry.SeverityLevel = 'info') {
    Sentry.captureMessage(message, level);
  }

  /**
   * Adicionar contexto do usuário
   */
  setUser(user: { id: string; email: string; role: string }) {
    Sentry.setUser({
      id: user.id,
      email: user.email,
      role: user.role,
    } as any);
  }

  /**
   * Remover contexto do usuário
   */
  clearUser() {
    Sentry.setUser(null);
  }

  /**
   * Adicionar breadcrumb (rastro de ações)
   */
  addBreadcrumb(message: string, category: string, data?: Record<string, unknown>) {
    Sentry.addBreadcrumb({
      message,
      category,
      data,
      level: 'info',
    });
  }
}

import { Injectable, Logger } from '@nestjs/common';
import { PrismaService } from '@core/prisma/prisma.service';

@Injectable()
export class TokenBlacklistService {
  private readonly logger = new Logger(TokenBlacklistService.name);
  private blacklist = new Set<string>(); // Em produção: usar Redis

  constructor(private prisma: PrismaService) { }

  /**
   * Adiciona um token à blacklist
   */
  async blacklistToken(token: string, expiry: Date, userId?: string): Promise<void> {
    // Armazenar na memória (temporário)
    this.blacklist.add(token);

    // Armazenar no banco para persistência
    try {
      await this.prisma.blacklistedToken.create({
        data: {
          token,
          expiresAt: expiry,
          userId,
        },
      });
    } catch (error) {
      this.logger.error('Falha ao armazenar token blacklistado no banco', error);
    }

    // Limpar token expirado automaticamente
    const ttl = expiry.getTime() - Date.now();
    if (ttl > 0) {
      setTimeout(() => {
        this.blacklist.delete(token);
        this.cleanupExpiredTokens();
      }, ttl);
    }

    this.logger.log(`Token adicionado à blacklist para usuário ${userId}`, {
      token: token.substring(0, 10) + '...',
      expiry: expiry.toISOString()
    });
  }

  /**
   * Verifica se um token está na blacklist
   */
  async isTokenBlacklisted(token: string): Promise<boolean> {
    // Verificar primeiro na memória (rápido)
    if (this.blacklist.has(token)) {
      return true;
    }

    // Verificar no banco de dados
    try {
      const blacklistedToken = await this.prisma.blacklistedToken.findUnique({
        where: { token },
      });

      if (blacklistedToken) {
        // Se encontrado, adicionar à memória para próxima verificação rápida
        this.blacklist.add(token);
        return true;
      }
    } catch (error) {
      this.logger.error('Erro ao verificar token blacklistado', error);
    }

    return false;
  }

  /**
   * Remove tokens expirados do banco
   */
  async cleanupExpiredTokens(): Promise<void> {
    try {
      const _now = new Date();
      const result = await this.prisma.blacklistedToken.deleteMany({
        where: {
          expiresAt: {
            lt: _now,
          },
        },
      });

      this.logger.log(`Removidos ${result.count} tokens expirados da blacklist`);
    } catch (error) {
      this.logger.error('Erro ao limpar tokens expirados', error);
    }
  }

  /**
   * Revoga todos os tokens de um usuário (logout completo)
   */
  async revokeAllUserTokens(userId: string): Promise<void> {
    try {
      // Buscar todos os refresh tokens do usuário
      const refreshTokens = await this.prisma.refreshToken.findMany({
        where: { userId },
      });

      // Adicionar todos à blacklist
      const _now = new Date();
      for (const refreshToken of refreshTokens) {
        await this.blacklistToken(refreshToken.token, refreshToken.expiresAt, userId);
      }

      // Remover refresh tokens do banco
      await this.prisma.refreshToken.deleteMany({
        where: { userId },
      });

      this.logger.log(`Revogados todos os tokens do usuário ${userId}`);
    } catch (error) {
      this.logger.error(`Erro ao revogar tokens do usuário ${userId}`, error);
      throw error;
    }
  }

  /**
   * Limpa toda a blacklist (usado em manutenção)
   */
  async clearBlacklist(): Promise<void> {
    this.blacklist.clear();
    try {
      await this.prisma.blacklistedToken.deleteMany({});
      this.logger.log('Blacklist completamente limpa');
    } catch (error) {
      this.logger.error('Erro ao limpar blacklist', error);
      throw error;
    }
  }
}

import * as fs from 'fs';
import * as path from 'path';
import * as semver from 'semver';

export function formatVersionTag(version: string): string {
  const clean = semver.clean(version);
  return clean ? `v${clean}` : version;
}

export function resolveAppVersionTag(options?: { cwd?: string; env?: NodeJS.ProcessEnv }): string {
  const cwd = options?.cwd || process.cwd();
  const env = options?.env || process.env;

  const envVersion = semver.clean(env.APP_VERSION || env.npm_package_version || '');
  if (envVersion) {
    return formatVersionTag(envVersion);
  }

  const candidates = [
    path.resolve(cwd, 'package.json'),
    path.resolve(cwd, 'apps', 'backend', 'package.json'),
    path.resolve(__dirname, '..', '..', '..', 'package.json'),
  ];

  for (const packagePath of candidates) {
    try {
      if (!fs.existsSync(packagePath)) {
        continue;
      }

      const raw = fs.readFileSync(packagePath, 'utf8');
      const parsed = JSON.parse(raw);
      const clean = semver.clean(parsed?.version || '');
      if (clean) {
        return formatVersionTag(clean);
      }
    } catch (_error) {
      // Ignore and try next candidate path.
    }
  }

  return 'v0.0.0';
}

import { Injectable, OnModuleInit, Logger, Inject } from '@nestjs/common';
import * as fs from 'fs';
import * as path from 'path';
import { PrismaService } from './prisma.service';
import { CoreContext } from './context/CoreContext';
import { ModuleContract, RegisteredModule } from './contracts/ModuleContract';
import { ModuleStatus } from '@prisma/client';

/**
 * Loader seguro de módulos
 * Princípio: NENHUM código de módulo executa sem autorização do CORE
 */
@Injectable()
export class ModuleLoader implements OnModuleInit {
    private readonly logger = new Logger(ModuleLoader.name);
    private readonly modulesPath = path.resolve(process.cwd(), 'modules');
    private loadedModules: Map<string, RegisteredModule> = new Map();
    private coreContext: CoreContext;

    constructor(
        private readonly prisma: PrismaService,
        @Inject('CoreContext') coreContext: CoreContext
    ) {
        this.coreContext = coreContext;
    }

    async onModuleInit() {
        this.logger.log('🔐 Inicializando Module Loader Seguro...');
        await this.initializeCoreContext();
        await this.scanAndRegisterModules();
        await this.loadActiveModules();
    }

    /**
     * Inicializa o contexto do CORE
     */
    private async initializeCoreContext() {
        // O contexto já é injetado, mas podemos adicionar inicializações específicas
        this.logger.log('✅ Core Context inicializado');
    }

    /**
     * Escaneia diretório de módulos e registra no banco se não existir
     * Status inicial: 'detected'
     */
    private async scanAndRegisterModules() {
        if (!fs.existsSync(this.modulesPath)) {
            this.logger.warn(`📁 Diretório de módulos não encontrado: ${this.modulesPath}`);
            return;
        }

        const dirs = fs.readdirSync(this.modulesPath, { withFileTypes: true });

        for (const dir of dirs) {
            if (dir.isDirectory() && !dir.name.startsWith('.') && dir.name !== 'node_modules') {
                await this.registerDiscoveredModule(dir.name);
            }
        }
    }

    /**
     * Registra módulo descoberto no banco (se não existir)
     */
    private async registerDiscoveredModule(slug: string) {
        try {
            const modulePath = path.join(this.modulesPath, slug);
            const moduleJsonPath = path.join(modulePath, 'module.json');

            if (!fs.existsSync(moduleJsonPath)) {
                this.logger.warn(`⚠️ module.json não encontrado para ${slug}`);
                return;
            }

            const moduleJson = JSON.parse(fs.readFileSync(moduleJsonPath, 'utf-8'));

            // Verificar se já existe no banco
            const existingModule = await this.prisma.module.findUnique({
                where: { slug }
            });

            if (!existingModule) {
                // Registrar como detectado
                await this.prisma.module.create({
                    data: {
                        slug,
                        name: moduleJson.name || slug,
                        version: moduleJson.version || '1.0.0',
                        description: moduleJson.description || '',
                        status: ModuleStatus.detected,
                        hasBackend: fs.existsSync(path.join(modulePath, 'backend')),
                        hasFrontend: fs.existsSync(path.join(modulePath, 'frontend')),
                        installedAt: new Date()
                    }
                });

                this.logger.log(`📝 Módulo detectado e registrado: ${slug}`);
            }
        } catch (error) {
            this.logger.error(`❌ Erro ao registrar módulo ${slug}:`, error);
        }
    }

    /**
     * Carrega apenas módulos ativos do banco
     */
    private async loadActiveModules() {
        const activeModules = await this.prisma.module.findMany({
            where: { status: ModuleStatus.active }
        });

        for (const moduleData of activeModules) {
            await this.loadModule(moduleData);
        }

        this.logger.log(`✅ ${this.loadedModules.size} módulos ativos carregados`);
    }

    /**
     * Carrega um módulo específico (apenas se autorizado pelo CORE)
     */
    private async loadModule(moduleData: unknown) {
        try {
            const moduleSlug = (moduleData as any).slug;
            const modulePath = path.join(this.modulesPath, moduleSlug);
            const moduleEntry = this.findModuleEntry(modulePath);

            if (!moduleEntry) {
                this.logger.warn(`⚠️ Arquivo de entrada não encontrado para ${moduleSlug}`);
                return;
            }

            // Importar dinamicamente (com validação de segurança)
            const moduleExports = await this.safeImport(moduleEntry);

            if (!this.validateModuleContract(moduleExports)) {
                this.logger.error(`❌ Contrato inválido para módulo ${moduleSlug}`);
                return;
            }

            const moduleContract: ModuleContract = (moduleExports as any).default || moduleExports;

            // Registrar no módulo
            await moduleContract.register(this.coreContext);

            // Marcar como carregado
            const registeredModule: RegisteredModule = {
                ...moduleContract,
                status: 'active',
                registeredAt: new Date(),
                updatedAt: new Date()
            };

            this.loadedModules.set(moduleSlug, registeredModule);
            this.logger.log(`🚀 Módulo carregado com sucesso: ${moduleSlug}`);

        } catch (error) {
            const moduleSlug = (moduleData as any).slug;
            this.logger.error(`❌ Erro ao carregar módulo ${moduleSlug}:`, error);

            // Atualizar status no banco
            if (moduleSlug) {
                await this.prisma.module.update({
                    where: { slug: moduleSlug },
                    data: { status: ModuleStatus.disabled }
                });
            }
        }
    }

    /**
     * Encontra o arquivo de entrada do módulo
     */
    private findModuleEntry(modulePath: string): string | null {
        const possibleEntries = ['module.ts', 'module.js', 'index.ts', 'index.js'];

        for (const entry of possibleEntries) {
            const entryPath = path.join(modulePath, entry);
            if (fs.existsSync(entryPath)) {
                return entryPath;
            }
        }

        return null;
    }

    /**
     * Importação segura com validações básicas
     */
    private async safeImport(modulePath: string): Promise<unknown> {
        // Validações de segurança básicas
        if (!modulePath.startsWith(this.modulesPath)) {
            throw new Error('Tentativa de importação fora do diretório de módulos');
        }

        // Verificar se o arquivo existe e é legível
        if (!fs.existsSync(modulePath)) {
            throw new Error('Arquivo de módulo não encontrado');
        }

        // Importar dinamicamente
        return await import(modulePath);
    }

    /**
     * Valida se o módulo implementa o contrato obrigatório
     */
    private validateModuleContract(moduleExport: unknown): moduleExport is ModuleContract {
        const m = (moduleExport as any)?.default || moduleExport;
        return (
            m &&
            typeof m.name === 'string' &&
            typeof m.slug === 'string' &&
            typeof m.version === 'string' &&
            typeof m.register === 'function'
        );
    }

    /**
     * Obtém módulo carregado por slug
     */
    getModule(slug: string): RegisteredModule | undefined {
        return this.loadedModules.get(slug);
    }

    /**
     * Lista todos os módulos carregados
     */
    getLoadedModules(): RegisteredModule[] {
        return Array.from(this.loadedModules.values());
    }

    /**
     * Ativa um módulo (chamado pelo instalador após migrations)
     * Aceita módulos com status 'db_ready' ou 'disabled' (reativação)
     */
    async activateModule(slug: string): Promise<boolean> {
        try {
            const moduleData = await this.prisma.module.findUnique({
                where: { slug }
            });

            // Permite ativação de módulos db_ready ou disabled
            if (!moduleData ||
                (moduleData.status !== ModuleStatus.db_ready && moduleData.status !== ModuleStatus.disabled)) {
                this.logger.warn(`⚠️ Não é possível ativar módulo ${slug} com status: ${moduleData?.status}`);
                return false;
            }

            // Carregar o módulo
            await this.loadModule(moduleData);

            // Atualizar status
            await this.prisma.module.update({
                where: { slug },
                data: {
                    status: ModuleStatus.active,
                    activatedAt: new Date()
                }
            });

            this.logger.log(`✅ Módulo ativado: ${slug}`);
            return true;

        } catch (error) {
            this.logger.error(`❌ Erro ao ativar módulo ${slug}:`, error);
            return false;
        }
    }

    /**
     * Desativa um módulo
     */
    async deactivateModule(slug: string): Promise<boolean> {
        try {
            const module = this.loadedModules.get(slug);
            if (module?.shutdown) {
                await module.shutdown();
            }

            this.loadedModules.delete(slug);

            await this.prisma.module.update({
                where: { slug },
                data: { status: ModuleStatus.disabled }
            });

            this.logger.log(`⏸️ Módulo desativado: ${slug}`);
            return true;

        } catch (error) {
            this.logger.error(`❌ Erro ao desativar módulo ${slug}:`, error);
            return false;
        }
    }
}

 import { Injectable, Logger } from '@nestjs/common';
import { Cron, CronExpression } from '@nestjs/schedule';
import { UpdateService } from './update.service';
import { PrismaService } from '@core/prisma/prisma.service';

/**
 * Serviço de CronJob para verificação automática de atualizações
 * 
 * Executa diariamente Ã  meia-noite para verificar se há novas versões
 * disponíveis no repositório Git configurado
 */
@Injectable()
export class UpdateCronService {
  private readonly logger = new Logger(UpdateCronService.name);

  constructor(
    private updateService: UpdateService,
    private prisma: PrismaService,
  ) {
      // Empty implementation
    }

  /**
   * CronJob que executa diariamente Ã  meia-noite
   * Verifica automaticamente por novas versões disponíveis
   */
  @Cron(CronExpression.EVERY_DAY_AT_MIDNIGHT)
  async handleUpdateCheck() {
    try {
      this.logger.log('Iniciando verificação automática de atualizações...');

      const result = await this.updateService.checkForUpdates();

      if (result.updateAvailable) {
        this.logger.log(`Nova versão disponível: ${result.availableVersion}`);
      } else {
        this.logger.log('Sistema está atualizado');
      }

    } catch (error) {
      this.logger.error('Erro na verificação automática de atualizações:', error);
    }
  }

  /**
   * CronJob para limpeza de logs antigos (executa semanalmente)
   * Remove logs de atualização com mais de 90 dias
   */
  @Cron(CronExpression.EVERY_WEEK)
  async handleLogCleanup() {
    try {
      this.logger.log('Iniciando limpeza de logs antigos...');

      // Data limite: 90 dias atrás
      const cutoffDate = new Date();
      cutoffDate.setDate(cutoffDate.getDate() - 90);

      // Contar logs que serão removidos
      const logsToDelete = await (this.prisma as any).updateLog.count({
        where: {
          startedAt: {
            lt: cutoffDate,
          },
        },
      });

      if (logsToDelete > 0) {
        // Remover logs antigos
        await (this.prisma as any).updateLog.deleteMany({
          where: {
            startedAt: {
              lt: cutoffDate,
            },
          },
        });

        this.logger.log(`Removidos ${logsToDelete} logs antigos (>90 dias)`);
      } else {
        this.logger.log('Nenhum log antigo para remover');
      }

    } catch (error) {
      this.logger.error('Erro na limpeza de logs:', error);
    }
  }
}

