}

import { Injectable, Logger } from '@nestjs/common';
import { PrismaService } from '@core/prisma/prisma.service';
import { CreateEmailConfigDto, UpdateEmailConfigDto } from './dto/email-config.dto';
import { EmailConfiguration } from '@prisma/client';

@Injectable()
export class EmailConfigService {
  private readonly logger = new Logger(EmailConfigService.name);

  constructor(
    private prisma: PrismaService,
  ) { }

  /**
   * Get predefined email provider configurations
   */
  getPredefinedProviders() {
    return [
      // Gmail SMTP configurations
      {
        providerName: 'Gmail (SSL/TLS - Port 465)',
        smtpHost: 'smtp.gmail.com',
        smtpPort: 465,
        encryption: 'SSL',
        authMethod: 'LOGIN',
        description: 'Configuração recomendada para Gmail com SSL/TLS',
      },
      {
        providerName: 'Gmail (STARTTLS - Port 587)',
        smtpHost: 'smtp.gmail.com',
        smtpPort: 587,
        encryption: 'STARTTLS',
        authMethod: 'LOGIN',
        description: 'Configuração alternativa para Gmail com STARTTLS',
      },
      // Hotmail/Outlook SMTP configuration
      {
        providerName: 'Hotmail/Outlook (STARTTLS - Port 587)',
        smtpHost: 'smtp-mail.outlook.com',
        smtpPort: 587,
        encryption: 'STARTTLS',
        authMethod: 'LOGIN',
        description: 'Configuração para Hotmail e Outlook.com',
      },
      // Titan Mail SMTP configuration
      {
        providerName: 'Titan Mail (SSL/TLS - Port 465)',
        smtpHost: 'smtp.titan.email',
        smtpPort: 465,
        encryption: 'SSL',
        authMethod: 'LOGIN',
        description: 'Configuração para Titan Email',
      },
    ];
  }

  /**
   * Get active email configuration
   */
  async getActiveConfig(): Promise<EmailConfiguration | null> {
    return this.prisma.emailConfiguration.findFirst({
      where: { isActive: true },
    });
  }



  /**
   * Get all email configurations
   */
  async getAllConfigs(): Promise<EmailConfiguration[]> {
    return this.prisma.emailConfiguration.findMany({
      orderBy: { createdAt: 'desc' },
    });
  }

  /**
   * Create a new email configuration
   * Only one email configuration can exist at a time (replaces the previous one)
   */
  async createConfig(dto: CreateEmailConfigDto, userId: string): Promise<EmailConfiguration> {
    this.logger.log(`Creating new email configuration for user ${userId}`);

    // Delete all existing configurations (only one email config allowed)
    const existingConfigs = await this.prisma.emailConfiguration.findMany();
    if (existingConfigs.length > 0) {
      await this.prisma.emailConfiguration.deleteMany({});
      this.logger.log(`Deleted ${existingConfigs.length} existing email configurations`);
    }

    // Create new configuration and activate it
    const newConfig = await this.prisma.emailConfiguration.create({
      data: {
        ...dto,
        createdBy: userId,
        updatedBy: userId,
        isActive: true,
      },
    });

    this.logger.log(`Created new email configuration with ID: ${newConfig.id}`);
    return newConfig;
  }

  /**
   * Update an email configuration
   */
  async updateConfig(id: string, dto: UpdateEmailConfigDto, userId: string): Promise<EmailConfiguration> {
    this.logger.log(`Updating email configuration ${id} by user ${userId}`);

    // Since only one configuration exists, just update it
    const updatedConfig = await this.prisma.emailConfiguration.update({
      where: { id },
      data: {
        ...dto,
        updatedBy: userId,
        isActive: true, // Always keep it active since it's the only one
      },
    });

    this.logger.log(`Updated email configuration ${id}`);
    return updatedConfig;
  }

  /**
   * Delete an email configuration
   */
  async deleteConfig(id: string): Promise<EmailConfiguration> {
    return this.prisma.emailConfiguration.delete({
      where: { id },
    });
  }

  /**
   * Activate an email configuration
   * Since only one configuration exists, this just ensures it's active
   */
  async activateConfig(id: string, userId: string): Promise<EmailConfiguration> {
    this.logger.log(`Activating email configuration ${id} by user ${userId}`);

    // Since only one configuration exists, just ensure it's active
    const activatedConfig = await this.prisma.emailConfiguration.update({
      where: { id },
      data: {
        isActive: true,
        updatedBy: userId,
      },
    });

    this.logger.log(`Activated email configuration ${id}`);
    return activatedConfig;
  }

  /**
   * Get SMTP credentials from SecurityConfig
   */
  async getSmtpCredentials(): Promise<{ smtpUsername?: string; smtpPassword?: string }> {
    try {
      const securityConfig = await this.prisma.securityConfig.findFirst();
      return {
        smtpUsername: securityConfig?.smtpUsername || undefined,
        smtpPassword: securityConfig?.smtpPassword || undefined,
      };
    } catch (error) {
      this.logger.error('Error fetching SMTP credentials:', error);
      return {};
    }
  }

  /**
   * Test email configuration by sending a test email
   * Note: This method now requires the emailService to be passed in
   */
  async testConfig(email: string, smtpUser: string, smtpPass: string, user: any, emailService: any): Promise<{ success: boolean; message: string }> {
    try {
      this.logger.log(`Testing email configuration for user ${user.id} to ${email}`);

      // Get active configuration
      const config = await this.getActiveConfig();

      if (!config) {
        this.logger.warn('No active email configuration found');
        return {
          success: false,
          message: 'Nenhuma configuração de email ativa encontrada. Configure um provedor de email primeiro.'
        };
      }

      this.logger.log(`Using email configuration: ${config.providerName} (${config.smtpHost}:${config.smtpPort})`);

      // Send test email with credentials
      const sent = await emailService.sendTestEmail(
        email,
        user.name || user.email,
        config,
        smtpUser,
        smtpPass
      );

      if (sent) {
        this.logger.log(`✅ Test email sent successfully by user ${user.id} to ${email}`);
        return {
          success: true,
          message: `Email de teste enviado com sucesso para ${email}. Verifique sua caixa de entrada.`
        };
      } else {
        this.logger.warn(`❌ Failed to send test email to ${email}`);
        return {
          success: false,
          message: 'Falha ao enviar email de teste. Verifique as configurações e credenciais.'
        };
      }
    } catch (error) {
      this.logger.error(`❌ Error testing email configuration for ${email}:`, error);

      // Return the specific error message from the email service
      return {
        success: false,
        message: error.message || 'Erro desconhecido ao testar configuração de email'
      };
    }
  }
}

import { Injectable, Logger, OnModuleInit } from '@nestjs/common';
import { ConfigService } from '@nestjs/config';
import * as nodemailer from 'nodemailer';
import { Transporter } from 'nodemailer';
import { PrismaService } from '@core/prisma/prisma.service';
import { getPlatformName } from '@core/common/constants/platform.constants';
import { SecurityConfigService } from '@core/security-config/security-config.service';

@Injectable()
export class EmailService implements OnModuleInit {
  private transporter: Transporter;
  private readonly logger = new Logger(EmailService.name);
  private isEnabled: boolean;
  private dbConfig: any = null;


  constructor(
    private config: ConfigService,
    private prisma: PrismaService,
    private securityConfigService: SecurityConfigService
  ) {
    this.isEnabled = false;
  }

  async onModuleInit() {
    // Initialize with database configuration if available
    await this.initializeTransporter();
  }

  /**
   * Initialize transporter with database configuration or fallback to env vars
   */
  private async initializeTransporter() {
    try {
      // Try to get active database configuration
      const result = await this.prisma.emailConfiguration.findFirst({
        where: { isActive: true }
      });
      this.dbConfig = result;

      // Get security config to access SMTP credentials
      const smtpCredentials = await this.securityConfigService.getSmtpCredentials();

      let smtpConfig;

      if (this.dbConfig) {
        // Use database configuration
        this.logger.log('Usando configuração de email do banco de dados');
        smtpConfig = {
          host: this.dbConfig.smtpHost,
          port: this.dbConfig.smtpPort,
          secure: this.dbConfig.encryption === 'SSL', // true for port 465, false for other ports
          tls: this.dbConfig.encryption === 'STARTTLS' || this.dbConfig.encryption === 'TLS' ? {
            rejectUnauthorized: false
          } : undefined,
        };
      } else {
        // Fallback to environment variables
        this.logger.log('Usando configuração de email do arquivo .env');
        smtpConfig = {
          host: this.config.get('SMTP_HOST'),
          port: parseInt(this.config.get('SMTP_PORT', '587')),
          secure: this.config.get('SMTP_SECURE') === 'true',
          tls: {
            rejectUnauthorized: false
          },
        };
      }

      // Check if SMTP is configured
      this.isEnabled = !!smtpConfig.host;

      if (this.isEnabled) {
        // Add authentication if available
        if (smtpCredentials.smtpUsername && smtpCredentials.smtpPassword) {
          // Use database credentials from SecurityConfig (decrypted)
          smtpConfig.auth = {
            user: smtpCredentials.smtpUsername,
            pass: smtpCredentials.smtpPassword,
          };
        } else if (this.config.get('SMTP_USER') && this.config.get('SMTP_PASS')) {
          // Fallback to environment variables
          smtpConfig.auth = {
            user: this.config.get('SMTP_USER'),
            pass: this.config.get('SMTP_PASS'),
          };
        }

        this.transporter = nodemailer.createTransport(smtpConfig);
        this.logger.log('Email service configurado e ativo');
      } else {
        this.logger.warn('Email service desabilitado - SMTP_HOST não configurado');
      }
    } catch (error) {
      this.logger.error('Erro ao inicializar o serviço de email:', error);
      this.isEnabled = false;
    }
  }

  /**
   * Enviar email de verificação
   */
  async sendVerificationEmail(email: string, name: string, token: string, smtpUser?: string, smtpPass?: string): Promise<boolean> {
    if (!this.isEnabled) {
      this.logger.warn(`Email de verificação não enviado (serviço desabilitado): ${email}`);
      return false;
    }

    const verificationUrl = `${this.config.get('FRONTEND_URL')}/verify-email?token=${token}`;
    const html = this.getVerificationEmailTemplate(name, verificationUrl);

    // If database configuration is active and credentials are provided, use them
    if (this.dbConfig && smtpUser && smtpPass) {
      return this.sendEmailWithCredentials(
        email,
        `Verifique seu email - ${await getPlatformName()}`,
        html,
        smtpUser,
        smtpPass
      );
    }

    // Otherwise, use the default transporter (environment variables)
    try {
      const platformName = await getPlatformName();
      await this.transporter.sendMail({
        from: `"${this.config.get('EMAIL_FROM_NAME', platformName)}" <${this.config.get('EMAIL_FROM', 'noreply@example.com')}>`,
        to: email,
        subject: `Verifique seu email - ${platformName}`,
        html,
      });

      this.logger.log(`Email de verificação enviado para: ${email}`);
      return true;
    } catch (error) {
      this.logger.error(`Erro ao enviar email de verificação para ${email}:`, error);
      return false;
    }
  }

