      });

      const platformName = await getPlatformName();

      await tempTransporter.sendMail({
        from: `"${platformName}" <${smtpUser}>`,
        to: email,
        subject: subject,
        html: html,
      });

      this.logger.log(`Email enviado para: ${email}`);
      return true;
    } catch (error) {
      this.logger.error(`Erro ao enviar email para ${email}:`, error);
