import { Injectable, Logger } from '@nestjs/common';
import { PrismaService } from '@core/prisma/prisma.service';

export interface PlatformConfig {
  platformName: string;
  platformEmail: string;
  platformPhone: string;
}

@Injectable()
export class PlatformConfigService {
  private readonly logger = new Logger(PlatformConfigService.name);
  private cachedConfig: PlatformConfig | null = null;
  private cacheTimestamp: number = 0;
  private readonly CACHE_TTL = 5 * 60 * 1000; // 5 minutos

  constructor(private prisma: PrismaService) { }

  /**
   * Get platform configuration with caching
   */
  async getPlatformConfig(): Promise<PlatformConfig> {
    // Check cache first
    if (this.cachedConfig && (Date.now() - this.cacheTimestamp) < this.CACHE_TTL) {
      return this.cachedConfig;
    }

    try {
      const securityConfig = await this.prisma.securityConfig.findFirst();

      const config: PlatformConfig = {
        platformName: securityConfig?.platformName || 'Sistema Multitenant',
        platformEmail: securityConfig?.platformEmail || 'contato@sistema.com',
        platformPhone: securityConfig?.platformPhone || '(11) 99999-9999',
      };

      // Update cache
      this.cachedConfig = config;
      this.cacheTimestamp = Date.now();

      return config;
    } catch (error) {
      this.logger.error('Error fetching platform configuration:', error);

      // Return default values on error
      return {
        platformName: 'Sistema Multitenant',
        platformEmail: 'contato@sistema.com',
        platformPhone: '(11) 99999-9999',
      };
    }
  }

  /**
   * Update platform configuration
   */
  async updatePlatformConfig(
    platformName?: string,
    platformEmail?: string,
    platformPhone?: string,
    userId?: string
  ): Promise<PlatformConfig> {
    try {
      // Get or create security config
      let securityConfig = await this.prisma.securityConfig.findFirst();

      const updateData: any = {
        updatedBy: userId,
      };

      if (platformName !== undefined) updateData.platformName = platformName;
      if (platformEmail !== undefined) updateData.platformEmail = platformEmail;
      if (platformPhone !== undefined) updateData.platformPhone = platformPhone;

      if (securityConfig) {
        // Update existing
        securityConfig = await this.prisma.securityConfig.update({
          where: { id: securityConfig.id },
          data: updateData,
        });
      } else {
        // Create new
        securityConfig = await this.prisma.securityConfig.create({
          data: {
            ...updateData,
            platformName: platformName || 'Sistema Multitenant',
            platformEmail: platformEmail || 'contato@sistema.com',
            platformPhone: platformPhone || '(11) 99999-9999',
          },
        });
      }

      // Clear cache
      this.cachedConfig = null;

      this.logger.log(`Platform configuration updated by user ${userId}`);

      return await this.getPlatformConfig();
    } catch (error) {
      this.logger.error('Error updating platform configuration:', error);
      throw error;
    }
  }

  /**
   * Get platform name
   */
  async getPlatformName(): Promise<string> {
    const config = await this.getPlatformConfig();
    return config.platformName;
  }

  /**
   * Get platform email
   */
  async getPlatformEmail(): Promise<string> {
    const config = await this.getPlatformConfig();
    return config.platformEmail;
  }

  /**
   * Get platform phone
   */
  async getPlatformPhone(): Promise<string> {
    const config = await this.getPlatformConfig();
    return config.platformPhone;
  }

  /**
   * Clear cache (useful for testing or manual refresh)
   */
  clearCache(): void {
    this.cachedConfig = null;
    this.cacheTimestamp = 0;
    this.logger.log('Platform configuration cache cleared');
  }
}

import { PipeTransform, Injectable, ArgumentMetadata } from '@nestjs/common';
import * as sanitizeHtml from 'sanitize-html';

/**
 * Pipe para sanitização automática de inputs
 * Remove espaços em branco extras e previne injeções
 */
@Injectable()
export class SanitizationPipe implements PipeTransform {
  transform(value: unknown, metadata: ArgumentMetadata) {
    if (!value) return value;

    // Se for objeto, sanitiza recursivamente
    if (typeof value === 'object' && !Array.isArray(value)) {
      return this.sanitizeObject(value);
    }

    // Se for array, sanitiza cada item
    if (Array.isArray(value)) {
      return value.map((item) => this.transform(item, metadata));
    }

    // Se for string, sanitiza
    if (typeof value === 'string') {
      return this.sanitizeString(value);
    }

    return value;
  }

  private sanitizeObject(obj: any): any {
    const sanitized: any = {};

    for (const key in obj) {
      if (Object.prototype.hasOwnProperty.call(obj, key)) {
        const value = obj[key];

        if (typeof value === 'string') {
          sanitized[key] = this.sanitizeString(value);
        } else if (typeof value === 'object' && value !== null) {
          sanitized[key] = this.sanitizeObject(value);
        } else {
          sanitized[key] = value;
        }
      }
    }

    return sanitized;
  }

  private sanitizeString(str: string): string {
    // Remove espaços em branco no início e fim
    let sanitized = str.trim();

    // Remove múltiplos espaços consecutivos
    sanitized = sanitized.replace(/\s+/g, ' ');

    // Sanitização robusta contra XSS usando sanitize-html
    // Remove tags HTML e atributos perigosos, mas mantém texto seguro
    sanitized = sanitizeHtml(sanitized, {
      allowedTags: [], // Remove TODAS as tags HTML
      allowedAttributes: {}, // Remove TODOS os atributos
      disallowedTagsMode: 'recursiveEscape', // Escapa o conteúdo das tags em vez de remover
    });

    return sanitized;
  }
}

import {
  Controller,
  Post,
  Get,
  Delete,
  Param,
  Query,
  UseGuards,
  UseInterceptors,
  UploadedFile,
  Req,
  Res,
  BadRequestException,
  Body,
} from '@nestjs/common';
import { FileInterceptor } from '@nestjs/platform-express';
import { Response } from 'express';
import { JwtAuthGuard } from '@core/common/guards/jwt-auth.guard';
import { SecureFileAccessGuard } from './guards/secure-file-access.guard';
import { SecureFilesService } from './secure-files.service';
import { UploadFileDto } from './dto/upload-file.dto';
import { FileQueryDto } from './dto/file-query.dto';
import { ConfigService } from '@nestjs/config';
import { diskStorage } from 'multer';
import { v4 as uuidv4 } from 'uuid';
import { extname } from 'path';

/**
 * Controller para gerenciamento de arquivos sensíveis
 * Todos os endpoints protegidos por JWT
 */
@Controller('secure-files')
@UseGuards(JwtAuthGuard)
export class SecureFilesController {
  constructor(
    private readonly secureFilesService: SecureFilesService,
    private readonly configService: ConfigService,
  ) { }

  /**
   * Upload de arquivo sensível
   * POST /secure-files/upload
   */
  @Post('upload')
  @UseInterceptors(
    FileInterceptor('file', {
      storage: diskStorage({
        destination: './uploads/temp',
        filename: (req, file, cb) => {
          const ext = extname(file.originalname);
          cb(null, `${uuidv4()}${ext}`);
        },
      }),
      limits: {
        fileSize: 10485760, // 10MB default, será sobrescrito por env
      },
      fileFilter: (req, file, cb) => {
        // Validação básica de MIME type
        const allowedTypes = [
          'image/jpeg',
          'image/png',
          'image/webp',
          'image/gif',
          'application/pdf',
          'application/msword',
          'application/vnd.openxmlformats-officedocument.wordprocessingml.document',
          'application/vnd.ms-excel',
          'application/vnd.openxmlformats-officedocument.spreadsheetml.sheet',
        ];

        if (allowedTypes.includes(file.mimetype)) {
          cb(null, true);
        } else {
          cb(
            new BadRequestException(
              `Tipo de arquivo não permitido: ${file.mimetype}`,
            ),
            false,
          );
        }
      },
    }),
  )
  async uploadFile(
    @UploadedFile() file: Express.Multer.File,
    @Body() uploadDto: UploadFileDto,
    @Req() req: any,
  ) {
    if (!file) {
      throw new BadRequestException('Nenhum arquivo foi enviado');
    }

    const user = req.user;
    const tenantId = user.tenantId;
    const userId = user.id;

    return await this.secureFilesService.uploadFile(
      file,
      tenantId,
      uploadDto.moduleName,
      uploadDto.documentType,
      userId,
      uploadDto.metadata,
    );
  }

  /**
   * Download/streaming de arquivo
   * GET /secure-files/:fileId
   */
  @Get(':fileId')
  @UseGuards(SecureFileAccessGuard)
  async getFile(
    @Param('fileId') fileId: string,
    @Req() req: any,
    @Res() res: Response,
  ) {
    const user = req.user;
    const { stream, headers } = await this.secureFilesService.getFileStream(
      fileId,
      user.id,
      user.tenantId,
    );

    // Definir headers de resposta
    res.set(headers);

    // Fazer pipe do stream para response
    stream.pipe(res);
  }

  /**
   * Obter metadata do arquivo
   * GET /secure-files/:fileId/metadata
   */
  @Get(':fileId/metadata')
  @UseGuards(SecureFileAccessGuard)
  async getFileMetadata(@Param('fileId') fileId: string, @Req() req: any) {
    const user = req.user;
    return await this.secureFilesService.getFileMetadata(fileId, user.tenantId);
  }

  /**
   * Deletar arquivo (soft delete)
   * DELETE /secure-files/:fileId
   */
  @Delete(':fileId')
  @UseGuards(SecureFileAccessGuard)
  async deleteFile(@Param('fileId') fileId: string, @Req() req: any) {
    const user = req.user;
    await this.secureFilesService.deleteFile(fileId, user.id, user.tenantId);
    return { message: 'Arquivo deletado com sucesso' };
  }

  /**
   * Listar arquivos do tenant
   * GET /secure-files/list
   */
  @Get()
  async listFiles(@Query() query: FileQueryDto, @Req() req: any) {
    const user = req.user;
    return await this.secureFilesService.listFiles(
      user.tenantId,
      query.moduleName,
      query.documentType,
    );
  }
}

import {
  Injectable,
  BadRequestException,
  NotFoundException,
  InternalServerErrorException,
  Logger,
} from '@nestjs/common';
import { ConfigService } from '@nestjs/config';
import { PrismaService } from '@core/prisma/prisma.service';
import { createReadStream, promises as fsPromises } from 'fs';
import { join } from 'path';
import { v4 as uuidv4 } from 'uuid';
import {
  SecureFileUploadResponse,
  SecureFileMetadata,
  SecureFileStream,
} from './interfaces/secure-file.interface';
import {
  validateFileSignature,
  sanitizeFileName,
} from './config/secure-multer.config';

@Injectable()
export class SecureFilesService {
  private readonly logger = new Logger(SecureFilesService.name);
  private readonly uploadsRoot: string;
  private readonly secureDir: string;

  constructor(
    private readonly prisma: PrismaService,
    private readonly configService: ConfigService,
  ) {
    // Configurar paths dinâmicos (Docker-ready)
    this.uploadsRoot = join(
      process.cwd(),
      this.configService.get<string>('UPLOADS_ROOT', 'uploads'),
    );
    this.secureDir = join(this.uploadsRoot, 'secure');
  }

  /**
   * Realiza upload de arquivo sensível
   */
  async uploadFile(
    file: Express.Multer.File,
    tenantId: string,
    moduleName: string,
    documentType: string,
    userId: string,
    metadata?: string,
  ): Promise<SecureFileUploadResponse> {
    this.logger.log(
      `Iniciando upload: tenant=${tenantId}, module=${moduleName}, type=${documentType}`,
    );

    try {
      // 1. Validar assinatura do arquivo
      await this.validateFileContent(file);

      // 2. Sanitizar nome original
      const sanitizedName = sanitizeFileName(file.originalname);

      // 3. Gerar nome único para armazenamento
      const extension = file.originalname.split('.').pop();
      const storedName = `${uuidv4()}.${extension}`;

      // 4. Criar diretório dinâmico
      const filePath = await this.createSecureDirectory(
        tenantId,
        moduleName,
        documentType,
        storedName,
      );

      // 5. Mover arquivo para destino final
      await fsPromises.rename(file.path, filePath);

      // 6. Registrar metadata no banco
      const secureFile = await this.prisma.secureFile.create({
        data: {
          id: uuidv4(),
          tenantId,
          moduleName,
          documentType,
          originalName: sanitizedName,
          storedName,
          mimeType: file.mimetype,
          sizeBytes: BigInt(file.size),
          uploadedBy: userId,
          metadata: metadata || null,
        },
      });

      this.logger.log(`Upload concluído: fileId=${secureFile.id}`);

      // 7. Registrar em auditoria
      await this.logAuditEvent('SECURE_FILE_UPLOADED', userId, tenantId, {
        fileId: secureFile.id,
        moduleName,
        documentType,
        sizeBytes: file.size,
      });

      return {
        fileId: secureFile.id,
        originalName: sanitizedName,
        sizeBytes: file.size,
        uploadedAt: secureFile.uploadedAt,
        moduleName,
        documentType,
      };
    } catch (error) {
      this.logger.error(`Erro no upload: ${error.message}`, error.stack);

      // Tentar deletar arquivo se foi criado
      if (file.path) {
        try {
          await fsPromises.unlink(file.path);
        } catch (unlinkError) {
          this.logger.warn(`Não foi possível deletar arquivo temporário: ${file.path}`);
        }
      }

      throw new InternalServerErrorException(
        'Erro ao processar upload. Tente novamente.',
      );
    }
  }

  /**
   * Obtém stream do arquivo para download/visualização
   */
  async getFileStream(
    fileId: string,
    userId: string,
    tenantId: string,
  ): Promise<SecureFileStream> {
    // 1. Buscar metadata do arquivo
    const file = await this.prisma.secureFile.findUnique({
      where: { id: fileId },
    });

    if (!file) {
      throw new NotFoundException('Arquivo não encontrado');
    }

    // 2. Validar que arquivo pertence ao tenant
    if (file.tenantId !== tenantId) {
      this.logger.warn(
        `Tentativa de acesso cross-tenant: user=${userId}, file=${fileId}`,
      );
      throw new NotFoundException('Arquivo não encontrado');
    }

    // 3. Verificar se arquivo foi deletado (soft delete)
    if (file.deletedAt) {
      throw new NotFoundException('Arquivo foi deletado');
    }

    // 4. Construir path do arquivo
    const filePath = this.getFilePath(
      file.tenantId,
      file.moduleName,
      file.documentType,
      file.storedName,
    );

    // 5. Verificar se arquivo existe fisicamente
    try {
      await fsPromises.access(filePath);
    } catch {
      this.logger.error(`Arquivo físico não encontrado: ${filePath}`);
      throw new NotFoundException('Arquivo corrompido ou não encontrado');
    }

    // 6. Atualizar estatísticas de acesso
    await this.prisma.secureFile.update({
      where: { id: fileId },
      data: {
        lastAccessedAt: new Date(),
        accessCount: {
          increment: 1,
        },
      },
    });

    // 7. Registrar acesso em auditoria
    await this.logAuditEvent('SECURE_FILE_ACCESSED', userId, tenantId, {
      fileId,
      moduleName: file.moduleName,
      documentType: file.documentType,
    });

    // 8. Obter stats do arquivo para Content-Length
    const stats = await fsPromises.stat(filePath);

    // 9. Criar stream
    const stream = createReadStream(filePath);

    return {
      stream,
      headers: {
        'Content-Type': file.mimeType,
        'Content-Length': stats.size,
        'Content-Disposition': `inline; filename="${file.originalName}"`,
        'Cache-Control': 'no-store, no-cache, must-revalidate',
      },
    };
  }

  /**
   * Obtém metadata do arquivo
   */
  async getFileMetadata(
    fileId: string,
    tenantId: string,
  ): Promise<SecureFileMetadata> {
    const file = await this.prisma.secureFile.findUnique({
      where: { id: fileId },
    });

    if (!file) {
      throw new NotFoundException('Arquivo não encontrado');
    }

    if (file.tenantId !== tenantId) {
      throw new NotFoundException('Arquivo não encontrado');
    }

    if (file.deletedAt) {
      throw new NotFoundException('Arquivo foi deletado');
    }

    return {
      fileId: file.id,
      originalName: file.originalName,
      mimeType: file.mimeType,
      sizeBytes: Number(file.sizeBytes),
      uploadedAt: file.uploadedAt,
      lastAccessedAt: file.lastAccessedAt,
      accessCount: file.accessCount,
    };
  }

  /**
   * Deleta arquivo (soft delete)
   */
  async deleteFile(
    fileId: string,
    userId: string,
    tenantId: string,
  ): Promise<void> {
    const file = await this.prisma.secureFile.findUnique({
      where: { id: fileId },
    });

    if (!file) {
      throw new NotFoundException('Arquivo não encontrado');
    }

    if (file.tenantId !== tenantId) {
      throw new NotFoundException('Arquivo não encontrado');
    }

    if (file.deletedAt) {
      throw new BadRequestException('Arquivo já foi deletado');
    }

    // Soft delete
    await this.prisma.secureFile.update({
      where: { id: fileId },
      data: {
        deletedAt: new Date(),
      },
    });

    // Registrar em auditoria
    await this.logAuditEvent('SECURE_FILE_DELETED', userId, tenantId, {
      fileId,
      moduleName: file.moduleName,
      documentType: file.documentType,
    });

    this.logger.log(`Arquivo deletado (soft): fileId=${fileId}`);
  }

  /**
   * Lista arquivos do tenant com filtros opcionais
   */
  async listFiles(
    tenantId: string,
    moduleName?: string,
    documentType?: string,
  ) {
    const where: any = {
      tenantId,
      deletedAt: null, // Apenas arquivos não deletados
    };

    if (moduleName) {
      where.moduleName = moduleName;
    }

    if (documentType) {
      where.documentType = documentType;
    }

    const files = await this.prisma.secureFile.findMany({
      where,
      select: {
        id: true,
        moduleName: true,
        documentType: true,
        originalName: true,
        mimeType: true,
        sizeBytes: true,
        uploadedAt: true,
        lastAccessedAt: true,
        accessCount: true,
      },
      orderBy: {
        uploadedAt: 'desc',
      },
    });

    return files.map((file) => ({
      ...file,
      sizeBytes: Number(file.sizeBytes),
    }));
  }

  /**
   * Cria diretório seguro dinamicamente
   */
  private async createSecureDirectory(
    tenantId: string,
    moduleName: string,
    documentType: string,
    fileName: string,
  ): Promise<string> {
    const directoryPath = join(
      this.secureDir,
      'tenants',
      tenantId,
      'modules',
      moduleName,
      documentType,
    );

    // Criar diretório recursivamente se não existir
    await fsPromises.mkdir(directoryPath, { recursive: true });

    return join(directoryPath, fileName);
  }

  /**
   * Obtém path do arquivo
   */
  private getFilePath(
    tenantId: string,
    moduleName: string,
    documentType: string,
    fileName: string,
  ): string {
    return join(
      this.secureDir,
      'tenants',
      tenantId,
      'modules',
      moduleName,
      documentType,
      fileName,
    );
  }

  /**
   * Valida conteúdo do arquivo (assinatura)
   */
  private async validateFileContent(file: Express.Multer.File): Promise<void> {
    // Ler primeiros bytes do arquivo
    const buffer = await fsPromises.readFile(file.path);

    // Validar assinatura
    if (!validateFileSignature(buffer, file.mimetype)) {
      // Deletar arquivo inválido
      await fsPromises.unlink(file.path);
      throw new BadRequestException(
        'Assinatura de arquivo inválida. O arquivo pode estar corrompido.',
      );
    }

    // Validar tamanho mínimo (evitar arquivos vazios ou muito pequenos)
    if (buffer.length < 100) {
      await fsPromises.unlink(file.path);
      throw new BadRequestException(
        'Arquivo muito pequeno ou corrompido',
      );
    }
  }

  /**
   * Registra evento de auditoria
   */
  private async logAuditEvent(
    action: string,
    userId: string,
    tenantId: string,
    details: any,
  ): Promise<void> {
    try {
      await this.prisma.auditLog.create({
        data: {
          action,
          userId,
          tenantId,
          details: JSON.stringify(details),
        },
      });
    } catch (error) {
      this.logger.warn(`Falha ao registrar auditoria: ${error.message}`);
      // Não falhar a operação principal por falha na auditoria
    }
  }
}

import { Controller, Get, Put, Body, UseGuards, Request } from '@nestjs/common';
import { SkipThrottle } from '@nestjs/throttler';
import { SecurityConfigService } from './security-config.service';
