    });
  }
}

import { Injectable, Logger, BadRequestException } from '@nestjs/common';
import { Pool, PoolClient } from 'pg';
import { ConfigService } from '@nestjs/config';

/**
 * Serviço Executor de Banco de Dados para Módulos
 * Usa pg.Pool para execução segura de SQL com transações e rollback automático
 */
@Injectable()
export class ModuleDatabaseExecutorService {
    private readonly logger = new Logger(ModuleDatabaseExecutorService.name);
    private pool: Pool;

    constructor(private configService: ConfigService) {
        this.initializePool();
    }

    /**
     * Inicializa o pool de conexões PostgreSQL
     */
    private initializePool() {
        const databaseUrl = this.configService.get<string>('DATABASE_URL');

        if (!databaseUrl) {
            throw new Error('DATABASE_URL não configurada');
        }

        this.pool = new Pool({
            connectionString: databaseUrl,
            max: 10, // Máximo de conexões
            idleTimeoutMillis: 30000,
            connectionTimeoutMillis: 2000,
        });

        this.pool.on('error', (err) => {
            this.logger.error('Erro inesperado no pool PostgreSQL:', err);
        });

        this.logger.log('✅ Pool PostgreSQL inicializado para executor de módulos');
    }

    /**
     * Executa SQL completo em transação com rollback automático
     * BEGIN → EXECUTE → COMMIT ou ROLLBACK em erro
     */
    async executeInTransaction(sql: string, tenantId?: string): Promise<void> {
        const client = await this.pool.connect();

        try {
            await client.query('BEGIN');

            // Se tenantId fornecido, configura isolamento
            if (tenantId) {
                await this.setTenantContext(client, tenantId);
            }

            // Executa o SQL completo
            await client.query(sql);

            await client.query('COMMIT');
            this.logger.log('✅ Transação executada com sucesso');

        } catch (error) {
            await client.query('ROLLBACK');
            this.logger.error('❌ Erro na transação, rollback executado:', error.message);
            throw new BadRequestException(`Erro ao executar SQL: ${error.message}`);
        } finally {
            client.release();
        }
    }

    /**
     * Executa múltiplas queries SQL em uma única transação
     */
    async executeMultipleInTransaction(queries: string[], tenantId?: string): Promise<void> {
        const client = await this.pool.connect();

        try {
            await client.query('BEGIN');

            if (tenantId) {
                await this.setTenantContext(client, tenantId);
            }

            for (const query of queries) {
                if (query.trim()) {
                    await client.query(query);
                }
            }

            await client.query('COMMIT');
            this.logger.log(`✅ ${queries.length} queries executadas em transação`);

        } catch (error) {
            await client.query('ROLLBACK');
            this.logger.error('❌ Erro em transação múltipla, rollback executado:', error.message);
            throw new BadRequestException(`Erro ao executar queries: ${error.message}`);
        } finally {
            client.release();
        }
    }

    /**
     * Executa query e retorna resultados
     */
    async executeQuery<T = any>(sql: string, params: any[] = [], tenantId?: string): Promise<T[]> {
        const client = await this.pool.connect();

        try {
            if (tenantId) {
                await this.setTenantContext(client, tenantId);
            }

            const result = await client.query(sql, params);
            return result.rows;

        } catch (error) {
            this.logger.error('❌ Erro ao executar query:', error.message);
            throw new BadRequestException(`Erro na query: ${error.message}`);
        } finally {
            client.release();
        }
    }

    /**
     * Verifica se tabela existe
     */
    async tableExists(tableName: string, tenantId?: string): Promise<boolean> {
        const query = `
            SELECT EXISTS (
                SELECT 1
                FROM information_schema.tables
                WHERE table_schema = 'public'
                AND table_name = $1
            )
        `;

        const result = await this.executeQuery<{ exists: boolean }>(query, [tableName], tenantId);
        return result[0]?.exists || false;
    }

    /**
     * Configura contexto do tenant para isolamento
     */
    private async setTenantContext(client: PoolClient, tenantId: string): Promise<void> {
        // Configura variável de sessão para isolamento por tenant
        await client.query('SET app.tenant_id = $1', [tenantId]);
        this.logger.debug(`🔒 Contexto tenant configurado: ${tenantId}`);
    }

    /**
     * Fecha o pool de conexões
     */
    async close(): Promise<void> {
        if (this.pool) {
            await this.pool.end();
            this.logger.log('🔌 Pool PostgreSQL fechado');
        }
    }

    /**
     * Health check do pool
     */
    async healthCheck(): Promise<boolean> {
        try {
            const client = await this.pool.connect();
            await client.query('SELECT 1');
            client.release();
            return true;
        } catch (error) {
            this.logger.error('❌ Health check do pool falhou:', error.message);
            return false;
        }
    }
}

 import { Injectable } from '@nestjs/common';
import { PrismaService } from '@core/prisma/prisma.service';
import * as bcrypt from 'bcrypt';

@Injectable()
export class PasswordHistoryService {
  constructor(private prisma: PrismaService) {
      // Empty implementation
    }

  /**
   * Verificar se a senha já foi usada recentemente
   */
  async isPasswordReused(userId: string, newPassword: string): Promise<{
    isReused: boolean;
    message?: string;
  }> {
    const user = await this.prisma.user.findUnique({
      where: { id: userId },
    });

    if (!user || !user.passwordHistory) {
      return { isReused: false };
    }

    // Buscar configuração de limite de reutilização
    const securityConfig = await this.prisma.securityConfig.findFirst();
    const reuseLimit = securityConfig?.passwordReuseLimit || 5;

    try {
      const passwordHistory: string[] = JSON.parse(user.passwordHistory);

      // Verificar contra cada senha no histórico
      for (let i = 0; i < passwordHistory.length; i++) {
        const isMatch = await bcrypt.compare(newPassword, passwordHistory[i]);
        if (isMatch) {
          const _positionInHistory = i + 1;
          return {
            isReused: true,
            message: `Esta senha já foi utilizada recentemente. Você não pode reutilizar as últimas ${reuseLimit} senhas.`,
          };
        }
      }

      return { isReused: false };
    } catch (error) {
      // Se houver erro ao parsear JSON, considerar que não há histórico
      return { isReused: false };
    }
  }

  /**
   * Adicionar nova senha ao histórico
   */
  async addPasswordToHistory(userId: string, hashedPassword: string): Promise<void> {
    const user = await this.prisma.user.findUnique({
      where: { id: userId },
    });

    if (!user) {
      return;
    }

    // Buscar configuração de limite
    const securityConfig = await this.prisma.securityConfig.findFirst();
    const reuseLimit = securityConfig?.passwordReuseLimit || 5;

    let passwordHistory: string[] = [];

    if (user.passwordHistory) {
      try {
        passwordHistory = JSON.parse(user.passwordHistory);
      } catch (error) {
        passwordHistory = [];
      }
    }

    // Adicionar nova senha no início do array
    passwordHistory.unshift(hashedPassword);

    // Manter apenas as últimas N senhas
    if (passwordHistory.length > reuseLimit) {
      passwordHistory = passwordHistory.slice(0, reuseLimit);
    }

    // Salvar histórico atualizado
    await this.prisma.user.update({
      where: { id: userId },
      data: {
        passwordHistory: JSON.stringify(passwordHistory),
        lastPasswordChange: new Date(),
      },
    });
  }

  /**
   * Validar requisitos de complexidade de senha
   */
  async validatePasswordComplexity(password: string): Promise<{
    isValid: boolean;
    errors: string[];
  }> {
    const securityConfig = await this.prisma.securityConfig.findFirst();
    const errors: string[] = [];

    const minLength = securityConfig?.passwordMinLength || 8;
    const requireUppercase = securityConfig?.passwordRequireUppercase ?? true;
    const requireLowercase = securityConfig?.passwordRequireLowercase ?? true;
    const requireNumbers = securityConfig?.passwordRequireNumbers ?? true;
    const requireSpecial = securityConfig?.passwordRequireSpecial ?? true;

    if (password.length < minLength) {
      errors.push(`A senha deve ter no mínimo ${minLength} caracteres`);
    }

    if (requireUppercase && !/[A-Z]/.test(password)) {
      errors.push('A senha deve conter pelo menos uma letra maiúscula');
    }

    if (requireLowercase && !/[a-z]/.test(password)) {
      errors.push('A senha deve conter pelo menos uma letra minúscula');
    }

    if (requireNumbers && !/\d/.test(password)) {
      errors.push('A senha deve conter pelo menos um número');
    }

    if (requireSpecial && !/[!@#$%^&*()_+\-=[\]{};':"\\|,.<>/?]/.test(password)) {
      errors.push('A senha deve conter pelo menos um caractere especial');
    }

    return {
      isValid: errors.length === 0,
      errors,
    };
  }

  /**
   * Verificar se senha é comum/fraca
   */
  isCommonPassword(password: string): boolean {
    // Lista de senhas mais comuns (top 100)
    const commonPasswords = [
      '123456', 'password', '12345678', 'qwerty', '123456789', '12345',
      '1234', '111111', '1234567', 'dragon', '123123', 'baseball', 'iloveyou',
      '121212', 'trustno1', 'monkey', 'liverpoo', 'dragon', 'princess', 'qwertyuiop',
      'starwars', 'montypython', 'superman', 'michael', 'michelle', 'football',
      'password1', 'abc123', '000000', 'letmein', 'liverpool', 'master', 'sunshine',
      'ashley', 'bailey', 'passw0rd', 'shadow', 'charlie', 'qwerty123', 'admin',
      'welcome', 'solo', 'jesus', 'ninja', 'mustang', 'password123', 'freedom',
      'whatever', 'starwars', 'test', 'trustno1', 'football1', 'secret', 'love'
    ];

    return commonPasswords.includes(password.toLowerCase());
  }

  /**
   * Gerar sugestões de senha forte
   */
  generatePasswordSuggestions(): string[] {
    const suggestions = [
      'Use pelo menos 12 caracteres',
      'Combine letras maiúsculas e minúsculas',
      'Inclua números e caracteres especiais',
      'Evite informações pessoais (nome, data de nascimento)',
      'Não reutilize senhas de outros serviços',
      'Use um gerenciador de senhas',
      'Considere usar uma frase-senha (passphrase)',
    ];

    return suggestions;
  }

  /**
   * Calcular força da senha
   */
  calculatePasswordStrength(password: string): {
    score: number; // 0-100
    level: 'weak' | 'medium' | 'strong' | 'very_strong';
    feedback: string[];
  } {
    let score = 0;
    const feedback: string[] = [];

    // Comprimento (até 40 pontos)
    if (password.length >= 8) score += 10;
    if (password.length >= 12) score += 10;
    if (password.length >= 16) score += 10;
    if (password.length >= 20) score += 10;

    // Complexidade (até 40 pontos)
    if (/[a-z]/.test(password)) {
      score += 10;
    } else {
      feedback.push('Adicione letras minúsculas');
    }

    if (/[A-Z]/.test(password)) {
      score += 10;
    } else {
      feedback.push('Adicione letras maiúsculas');
    }

    if (/\d/.test(password)) {
      score += 10;
    } else {
      feedback.push('Adicione números');
    }

    if (/[!@#$%^&*()_+\-=[\]{};':"\\|,.<>/?]/.test(password)) {
      score += 10;
    } else {
      feedback.push('Adicione caracteres especiais');
    }

    // Diversidade (até 20 pontos)
    const uniqueChars = new Set(password).size;
    if (uniqueChars >= 8) score += 5;
    if (uniqueChars >= 12) score += 5;
    if (uniqueChars >= 16) score += 10;

    // Penalidades
    if (this.isCommonPassword(password)) {
      score -= 50;
      feedback.push('Esta senha é muito comum. Escolha uma senha mais única.');
    }

    if (/(.)\1{2,}/.test(password)) {
      score -= 10;
      feedback.push('Evite repetir o mesmo caractere consecutivamente');
    }

    if (/012|123|234|345|456|567|678|789|abc|bcd|cde/.test(password.toLowerCase())) {
      score -= 10;
      feedback.push('Evite sequências óbvias');
    }

    // Garantir que score está entre 0-100
    score = Math.max(0, Math.min(100, score));

    // Determinar nível
    let level: 'weak' | 'medium' | 'strong' | 'very_strong';
    if (score < 40) {
      level = 'weak';
    } else if (score < 60) {
      level = 'medium';
    } else if (score < 80) {
      level = 'strong';
    } else {
      level = 'very_strong';
    }

    return {
      score,
      level,
      feedback,
    };
  }
}

import * as Sentry from '@sentry/node';
import { Injectable } from '@nestjs/common';
import { ConfigService } from '@nestjs/config';

@Injectable()
export class SentryService {
  constructor(private config: ConfigService) {
    this.init();
  }

  private init() {
    const dsn = this.config.get('SENTRY_DSN');
    const environment = this.config.get('NODE_ENV', 'development');

    // Apenas inicializar se DSN estiver configurado
    if (!dsn) {
      return;
    }

    Sentry.init({
      dsn,
      environment,
      integrations: [],
      // Performance Monitoring
      tracesSampleRate: environment === 'production' ? 0.1 : 1.0, // 10% em produção, 100% em dev
      // Filtrar dados sensíveis
      beforeSend(event, _hint) {
        // Remover dados sensíveis
        if (event.request) {
          // Remover headers sensíveis
          if (event.request.headers) {
            delete event.request.headers['authorization'];
            delete event.request.headers['cookie'];
          }

          // Remover dados sensíveis do body
          if (event.request.data) {
            const data = typeof event.request.data === 'string'
              ? JSON.parse(event.request.data)
              : event.request.data;

            if (data.password) data.password = '[FILTERED]';
            if (data.currentPassword) data.currentPassword = '[FILTERED]';
            if (data.newPassword) data.newPassword = '[FILTERED]';
            if (data.adminPassword) data.adminPassword = '[FILTERED]';
            if (data.refreshToken) data.refreshToken = '[FILTERED]';

            event.request.data = data;
          }
        }

        return event;
      },
    });

  }

  /**
   * Capturar exceção manualmente
   */
  captureException(exception: any, context?: Record<string, unknown>) {
    Sentry.captureException(exception, {
      extra: context,
    });
  }

  /**
   * Capturar mensagem
   */
  captureMessage(message: string, level: Sentry.SeverityLevel = 'info') {
    Sentry.captureMessage(message, level);
  }

  /**
   * Adicionar contexto do usuário
   */
  setUser(user: { id: string; email: string; role: string }) {
    Sentry.setUser({
      id: user.id,
      email: user.email,
      role: user.role,
    } as any);
  }

  /**
   * Remover contexto do usuário
   */
  clearUser() {
    Sentry.setUser(null);
  }

  /**
   * Adicionar breadcrumb (rastro de ações)
   */
  addBreadcrumb(message: string, category: string, data?: Record<string, unknown>) {
    Sentry.addBreadcrumb({
      message,
      category,
      data,
      level: 'info',
    });
  }
}

/**
 * CARREGADOR DINÂMICO DE MÓDULOS
 * 
 * Sistema que carrega módulos baseado EXCLUSIVAMENTE no banco de dados
 * SEM listas fixas, SEM hardcoded modules
 * 
 * PRINCÍPIO: O BANCO É A ÚNICA FONTE DE VERDADE
 */

import { moduleRegistry } from '../registry/module-registry';
import { ModuleContribution } from '../types/module.types';

/**
 * Carrega módulos externos baseado nos dados da API
 * Não há lista fixa - os módulos são descobertos dinamicamente
 */
export async function loadExternalModules(): Promise<void> {
  try {
    // Buscar módulos ativos da API
    const response = await fetch('/api/me/modules', {
      credentials: 'include'
    });

    if (!response.ok) {
      console.warn('⚠️ Não foi possível carregar módulos da API');
      return;
    }

    const _data = await response.json();
    const modules = _data.modules || [];

    console.warn(`📦 ${modules.length} módulo(s) encontrado(s) no banco de dados`);

    // Para cada módulo retornado pela API, tentar carregar sua definição
    for (const module of modules) {
      try {
        await loadModuleDynamically(module);
      } catch (error) {
        console.error(`❌ Erro ao carregar módulo ${module.slug}:`, error);
        // Continua carregando outros módulos mesmo se um falhar
      }
    }

  } catch (error) {
    console.error('❌ Erro ao carregar lista de módulos:', error);
  }
}

/**
 * Carrega um módulo específico dinamicamente
 * Tenta importar o módulo baseado em convenção de nomes
 */
async function loadModuleDynamically(moduleData: any): Promise<void> {
  const { slug, name, menus } = moduleData;

  try {
    // Tentar carregar definição do módulo se existir
    // Convenção: @modules/{slug}/frontend/index.ts exporta ModuleContribution
    const _modulePath = `@modules/${slug}/frontend`;

    // Import dinâmico (pode falhar se módulo não tiver definição frontend)
    const moduleDefinition = await import(
      /* webpackIgnore: true */
      `../../../../../packages/modules/${slug}/frontend/index`
    ).catch(() => null);

    if (moduleDefinition && moduleDefinition.default) {
      // Módulo tem definição completa - registrar
      moduleRegistry.register(moduleDefinition.default);
    } else {
      // Módulo não tem definição - criar contribuição básica baseada nos dados da API
      const basicContribution: ModuleContribution = {
        id: slug,
        name: name,
        version: '1.0.0',
        enabled: true,
        sidebar: menus?.map((menu: any, index: number) => ({
          id: menu.id || `${slug}-${index}`,
          name: menu.label,
          href: menu.route,
          icon: menu.icon || 'Package',
          order: menu.order || 50
        })) || [],
        dashboard: []
      };

      moduleRegistry.register(basicContribution);
    }

  } catch (error) {
    console.warn(`⚠️ Não foi possível carregar definição de ${slug}, usando fallback`);

    // Fallback: registrar apenas com dados da API
    const fallbackContribution: ModuleContribution = {
      id: slug,
      name: name,
      version: '1.0.0',
      enabled: true,
      sidebar: menus?.map((menu: any, index: number) => ({
        id: menu.id || `${slug}-${index}`,
        name: menu.label,
        href: menu.route,
        icon: menu.icon || 'Package',
        order: menu.order || 50
      })) || [],
      dashboard: []
    };

    moduleRegistry.register(fallbackContribution);
  }
}

