  type?: 'info' | 'success' | 'warning' | 'error';
  read?: boolean;
  tenantId?: string;
  userId?: string;
  dateFrom?: Date;
  dateTo?: Date;
  page?: number;
  limit?: number;
}

export interface NotificationResponse {
  notifications: Notification[];
  total: number;
  unreadCount: number;
  hasMore: boolean;
}

/**
 * NOTIFICATION GATEWAY - Socket.IO Gateway para notificações em tempo real
 */

import {
  WebSocketGateway,
  WebSocketServer,
  SubscribeMessage,
  OnGatewayConnection,
  OnGatewayDisconnect,
  ConnectedSocket,
  MessageBody,
} from '@nestjs/websockets';
import { Logger, UseGuards } from '@nestjs/common';
import { Server, Socket } from 'socket.io';
import { JwtService } from '@nestjs/jwt';
import { ConfigService } from '@nestjs/config';
import { PrismaService } from '@core/prisma/prisma.service';
import { JwtAuthGuard } from '@core/common/guards/jwt-auth.guard';
import { WsJwtGuard } from '@common/guards/ws-jwt.guard';
import { NotificationService } from './notification.service';
import { Notification } from './notification.entity';
import { PushNotificationService } from './push-notification.service';

interface ConnectionMetrics {
  totalConnections: number;
  activeConnections: number;
  peakConnections: number;
  connectionAttempts: number;
  failedConnections: number;
  avgConnectionDuration: number;
  connectionFailureRate: number;
}

interface AuthenticatedSocket extends Socket {
  user?: {
    id: string;
    tenantId: string;
    role: string;
  };
}

@WebSocketGateway({
  namespace: '/notifications',
  cors: {
    origin: (origin, callback) => {
      // Domínios de produção
      const allowedOrigins = [
        process.env.FRONTEND_URL,
        process.env.FRONTEND_URL?.replace('https://', 'wss://'), // Protocolo WebSocket
      ].filter(Boolean);

      // Domínios de desenvolvimento
      if (process.env.NODE_ENV !== 'production') {
        allowedOrigins.push(
          'http://localhost:5000',
          'http://localhost:3000',
          'ws://localhost:5000',
          'ws://localhost:3000',
          'http://127.0.0.1:5000',
          'http://127.0.0.1:3000'
        );
      }

      // Permitir se não houver origem (apps móveis, conexões diretas) ou estiver na lista permitida
      if (!origin || allowedOrigins.includes(origin)) {
        callback(null, true);
      } else {
        callback(new Error(`Origem não permitida: ${origin}`));
      }
    },
    credentials: true,
    methods: ['GET', 'POST'],
    allowedHeaders: ['Authorization', 'Content-Type'],
  },
})
export class NotificationGateway implements OnGatewayConnection, OnGatewayDisconnect {
  @WebSocketServer()
  server: Server;

  private readonly logger = new Logger(NotificationGateway.name);
  private connectedClients = new Map<string, AuthenticatedSocket>();
  private connectionMetrics: ConnectionMetrics = {
    totalConnections: 0,
    activeConnections: 0,
    peakConnections: 0,
    connectionAttempts: 0,
    failedConnections: 0,
    avgConnectionDuration: 0,
    connectionFailureRate: 0
  };
  private connectionStartTimes = new Map<string, number>();
  private monitoringInterval: NodeJS.Timeout;

  constructor(
    private notificationService: NotificationService,
    private pushNotificationService: PushNotificationService,
    private jwtService: JwtService,
    private configService: ConfigService,
    private prismaService: PrismaService
  ) {
    this.startMonitoring();
  }

  private startMonitoring() {
    this.monitoringInterval = setInterval(() => {
      try {
        this.updateMetrics();
        this.checkThresholds();
        this.logMetrics();
      } catch (error) {
        // CRÍTICO: Nunca permitir que erros de monitoramento quebrem outras operações
        this.logger.error('Erro no monitoramento do gateway (não crítico):', error);
      }
    }, 60000); // A cada minuto
  }

  private updateMetrics() {
    try {
      const currentActive = this.connectedClients.size;
      this.connectionMetrics.activeConnections = currentActive;
      this.connectionMetrics.peakConnections = Math.max(
        this.connectionMetrics.peakConnections,
        currentActive
      );

      // Calcular taxa de falha
      if (this.connectionMetrics.connectionAttempts > 0) {
        this.connectionMetrics.connectionFailureRate = 
          (this.connectionMetrics.failedConnections / this.connectionMetrics.connectionAttempts) * 100;
      }
    } catch (error) {
      this.logger.error('Erro ao atualizar métricas:', error);
    }
  }

  private checkThresholds() {
    try {
      const maxConnections = parseInt(process.env.MAX_WEBSOCKET_CONNECTIONS) || 1000;

      // Alertar sobre uso alto de conexões
      if (this.connectionMetrics.activeConnections > maxConnections * 0.8) {
        this.logger.warn('ALTO_USO_CONEXOES', {
          active: this.connectionMetrics.activeConnections,
          threshold: maxConnections * 0.8,
          percentage: (this.connectionMetrics.activeConnections / maxConnections * 100).toFixed(2)
        });
      }

      // Alertar sobre alta taxa de falhas - APENAS LOG, NUNCA THROW
      if (this.connectionMetrics.connectionFailureRate > 5) {
        this.logger.warn('ALTA_TAXA_FALHAS_CONEXAO', {
          connectionFailureRate: this.connectionMetrics.connectionFailureRate,
          failedConnections: this.connectionMetrics.failedConnections,
          connectionAttempts: this.connectionMetrics.connectionAttempts
        });

        // CRÍTICO: NUNCA fazer throw aqui - apenas log
        // Isso estava causando o HTTP 500 anteriormente
      }
    } catch (error) {
      // CRÍTICO: Capturar QUALQUER erro e apenas logar
      this.logger.error('Erro ao verificar thresholds (não crítico):', error);
      // NUNCA re-throw o erro
    }
  }

  private logMetrics() {
    try {
      this.logger.log('METRICAS_CONEXOES', {
        ...this.connectionMetrics,
        timestamp: new Date().toISOString(),
        memoryUsage: process.memoryUsage(),
        uptime: process.uptime()
      });
    } catch (error) {
      this.logger.error('Erro ao logar métricas:', error);
    }
  }

  // Lifecycle hook para limpeza
  onModuleDestroy() {
    if (this.monitoringInterval) {
      clearInterval(this.monitoringInterval);
    }
  }

  async handleConnection(client: AuthenticatedSocket) {
    try {
      // Rastrear início da conexão para métricas
      this.connectionMetrics.totalConnections++;
      this.connectionMetrics.connectionAttempts++;
      this.connectionStartTimes.set(client.id, Date.now());

      // DEBUG: Verificar se o token está sendo enviado
      this.logger.log(`🔍 Cliente conectando: ${client.id}`);
      this.logger.log(`🔍 Handshake auth:`, client.handshake?.auth);
      this.logger.log(`🔍 Handshake headers:`, client.handshake?.headers?.authorization);

      // AUTENTICAÇÃO DIRETA: Extrair e validar token
      const token = this.extractTokenFromHandshake(client);
      if (!token) {
        this.logger.warn(`❌ Cliente rejeitado - nenhum token fornecido: ${client.id}`);
        this.connectionMetrics.failedConnections++;
        client.disconnect(true);
        return;
      }

      // Validar token JWT
      const user = await this.validateTokenForConnection(token);
      if (!user) {
        this.logger.warn(`❌ Cliente rejeitado - token inválido: ${client.id}`);
        this.connectionMetrics.failedConnections++;
        client.disconnect(true);
        return;
      }

      // Anexar usuário ao cliente
      (client as any).user = user;
      this.logger.log(`✅ Cliente autenticado: ${client.id} (user: ${user.id}, tenant: ${user.tenantId})`);

      this.connectedClients.set(client.id, client);

      // Entrar nas salas apropriadas
      await this.joinRooms(client);

      this.logger.log(`Cliente conectado: ${client.id} (user: ${user.id}, tenant: ${user.tenantId})`);

      // Enviar contagem de não lidas
      const unreadCount = await this.notificationService.countUnread(user);
      client.emit('notification:unread-count', { count: unreadCount });

    } catch (error) {
      this.logger.error(`Erro na conexão do cliente ${client.id}:`, error);
      this.connectionMetrics.failedConnections++;
      client.disconnect(true);
    }
  }

  handleDisconnect(client: AuthenticatedSocket) {
    // Calcular duração da conexão
    const startTime = this.connectionStartTimes.get(client.id);
    if (startTime) {
      const duration = Date.now() - startTime;
      this.connectionMetrics.avgConnectionDuration = 
        ((this.connectionMetrics.avgConnectionDuration * (this.connectionMetrics.totalConnections - 1)) + duration) 
        / this.connectionMetrics.totalConnections;

      this.connectionStartTimes.delete(client.id);
    }

    this.connectedClients.delete(client.id);
    this.logger.log(`Cliente desconectado: ${client.id}`);
  }

  @SubscribeMessage('notification:mark-read')
  async handleMarkAsRead(
    @ConnectedSocket() client: AuthenticatedSocket,
    @MessageBody() data: { id: string }
  ) {
    try {
      const notification = await this.notificationService.markAsRead(data.id, client.user);

      if (notification) {
        // Emitir para o usuário que a notificação foi lida
        client.emit('notification:read', notification);

        // Emitir nova contagem de não lidas
        const unreadCount = await this.notificationService.countUnread(client.user);
        client.emit('notification:unread-count', { count: unreadCount });

        this.logger.log(`Notificação marcada como lida via Socket.IO: ${data.id}`);
      }
    } catch (error) {
      this.logger.error(`Erro ao marcar notificação como lida: ${data.id}`, {
        error: error.message,
        stack: error.stack,
        clientId: client.id,
        userId: client.user?.id,
        timestamp: new Date().toISOString()
      });
      client.emit('notification:error', { 
        message: 'Não foi possível processar a solicitação',
        code: 'MARK_READ_FAILED'
      });
    }
  }

  @SubscribeMessage('notification:mark-all-read')
  async handleMarkAllAsRead(@ConnectedSocket() client: AuthenticatedSocket) {
    try {
      const count = await this.notificationService.markAllAsRead(client.user);

      // Emitir confirmação
      client.emit('notification:all-read', { count });

      // Emitir nova contagem (deve ser 0)
      client.emit('notification:unread-count', { count: 0 });

      this.logger.log(`${count} notificações marcadas como lidas via Socket.IO`);
    } catch (error) {
      this.logger.error('Erro ao marcar todas como lidas:', {
        error: error.message,
        stack: error.stack,
        clientId: client.id,
        userId: client.user?.id,
        timestamp: new Date().toISOString()
      });
      client.emit('notification:error', { 
        message: 'Não foi possível processar a solicitação',
        code: 'MARK_ALL_READ_FAILED'
      });
    }
  }

  @SubscribeMessage('notification:delete')
  async handleDelete(
    @ConnectedSocket() client: AuthenticatedSocket,
    @MessageBody() data: { id: string }
  ) {
    try {
      const notification = await this.notificationService.delete(data.id, client.user);

      if (notification) {
        // Emitir confirmação de exclusão
        client.emit('notification:deleted', { id: data.id });

        // Atualizar contagem se era não lida
        if (!notification.read) {
          const unreadCount = await this.notificationService.countUnread(client.user);
          client.emit('notification:unread-count', { count: unreadCount });
        }

        this.logger.log(`Notificação deletada via Socket.IO: ${data.id}`);
      }
    } catch (error) {
      this.logger.error(`Erro ao deletar notificação: ${data.id}`, {
        error: error.message,
        stack: error.stack,
        clientId: client.id,
        userId: client.user?.id,
        timestamp: new Date().toISOString()
      });
      client.emit('notification:error', { 
        message: 'Não foi possível processar a solicitação',
        code: 'DELETE_NOTIFICATION_FAILED'
      });
    }
  }

  /**
   * Emite nova notificação para usuários apropriados
   * CRÍTICO: Nunca deve falhar ou quebrar requisições HTTP
   */
  async emitNewNotification(notification: Notification) {
    try {
      const rooms = this.determineTargetRooms(notification);

      for (const room of rooms) {
        try {
          this.server.to(room).emit('notification:new', notification);
          this.logger.log(`Nova notificação emitida para sala: ${room}`);
        } catch (roomError) {
          // CRÍTICO: Erro em uma sala não deve afetar outras
          this.logger.error(`Erro ao emitir para sala ${room}:`, roomError);
        }
      }

      // Atualizar contagem de não lidas para usuários afetados
      try {
        await this.updateUnreadCounts(notification);
      } catch (countError) {
        // CRÍTICO: Erro na contagem não deve quebrar a emissão
        this.logger.error('Erro ao atualizar contagens (não crítico):', countError);
      }

      // Enviar push para PWA/background sem afetar fluxo principal
      try {
        await this.pushNotificationService.sendNotification(notification);
      } catch (pushError) {
        this.logger.error('Erro ao enviar push (nao critico):', pushError);
      }

    } catch (error) {
      // CRÍTICO: NUNCA permitir que este método falhe
      this.logger.error('Erro ao emitir nova notificação (não crítico):', error);
      // NUNCA re-throw - isso quebraria requisições HTTP
    }
  }

  /**
   * Emite evento de notificação lida
   */
  async emitNotificationRead(notification: Notification) {
    try {
      const rooms = this.determineTargetRooms(notification);

      for (const room of rooms) {
        this.server.to(room).emit('notification:read', notification);
      }

    } catch (error) {
      this.logger.error('Erro ao emitir notificação lida:', error);
    }
  }

  /**
   * Emite evento de notificação deletada
   */
  async emitNotificationDeleted(notificationId: string, notification: Notification) {
    try {
      const rooms = this.determineTargetRooms(notification);

      for (const room of rooms) {
        this.server.to(room).emit('notification:deleted', { id: notificationId });
      }

    } catch (error) {
      this.logger.error('Erro ao emitir notificação deletada:', error);
    }
  }

  // ============================================================================
  // MÉTODOS PRIVADOS
  // ============================================================================

  private async joinRooms(client: AuthenticatedSocket) {
    const user = client.user;

    // Sala do usuário específico
    await client.join(`user:${user.id}`);

    // Sala do tenant apenas para perfis administrativos
    if (user.tenantId && (user.role === 'ADMIN' || user.role === 'SUPER_ADMIN')) {
      await client.join(`tenant:${user.tenantId}`);
    }

    // Sala global (para super admins)
    if (user.role === 'SUPER_ADMIN') {
      await client.join('global');
    }

    this.logger.debug(`Cliente ${client.id} entrou nas salas apropriadas`);
  }

  private determineTargetRooms(notification: Notification): string[] {
    const rooms: string[] = [];

    // Notificação para usuário específico
    if (notification.userId) {
      rooms.push(`user:${notification.userId}`);
    }
    // Notificação para tenant
    else if (notification.tenantId) {
      rooms.push(`tenant:${notification.tenantId}`);
    }
    // Notificação global
    else {
      rooms.push('global');
    }

    return rooms;
  }

  private async updateUnreadCounts(notification: Notification) {
    try {
      // Determinar quais usuários devem receber atualização de contagem
      const targetUsers = await this.getTargetUsers(notification);

      for (const userId of targetUsers) {
        const client = Array.from(this.connectedClients.values())
          .find(c => c.user?.id === userId);

        if (client) {
          const unreadCount = await this.notificationService.countUnread(client.user);
          client.emit('notification:unread-count', { count: unreadCount });
        }
      }
    } catch (error) {
      this.logger.error('Erro ao atualizar contagens:', error);
    }
  }

  private async getTargetUsers(notification: Notification): Promise<string[]> {
    // Implementar lógica para determinar usuários que devem receber a notificação
    // Por simplicidade, retornando apenas o usuário específico se houver
    if (notification.userId) {
      return [notification.userId];
    }

    // Para notificações de tenant, você precisaria buscar todos os usuários do tenant
    // Para notificações globais, todos os super admins

    return [];
  }

  private extractTokenFromHandshake(client: AuthenticatedSocket): string | null {
    return client.handshake?.auth?.token ||
           client.handshake?.headers?.authorization?.replace('Bearer ', '') ||
           null;
  }

  private async validateTokenForConnection(token: string): Promise<any> {
    try {
      // Validar JWT token usando o JwtService
      const payload = this.jwtService.verify(token, {
        secret: this.configService.get('JWT_SECRET'),
      });

      if (!payload.sub) {
        return null;
      }

      // Buscar usuário no banco de dados
      const user = await this.prismaService.user.findUnique({
        where: { id: payload.sub },
        include: {
          tenant: true
        }
      });

      if (!user) {
        return null;
      }

      return {
        id: user.id,
        tenantId: user.tenantId,
        role: user.role,
        email: user.email,
        name: user.name
      };
    } catch (error) {
      this.logger.error('Erro ao validar token JWT para conexão:', error.message);
      return null;
    }
  }

  private async validateToken(token: string): Promise<unknown> {
    // Método legado - manter para compatibilidade
    return this.validateTokenForConnection(token);
  }
}

﻿/**
 * NOTIFICATION SERVICE - Lógica de negócio e persistência
 */

import { Injectable, Logger } from '@nestjs/common';
import { PrismaService } from '@core/prisma/prisma.service';
import {
  Notification,
  NotificationCreateData,
  NotificationFilters,
  NotificationResponse
} from './notification.entity';
import { BroadcastNotificationDto } from './notification.dto';

@Injectable()
export class NotificationService {
  private readonly logger = new Logger(NotificationService.name);

  constructor(private prisma: PrismaService) {
      // Empty implementation
    }

  /**
   * Cria uma nova notificação
   */
  async create(data: NotificationCreateData): Promise<Notification> {
    try {
      const notification = await this.prisma.notification.create({
        data: {
          title: data.title,
          message: data.description, // Prisma usa 'message', nossa interface usa 'description'
          severity: data.type, // Prisma usa 'severity', nossa interface usa 'type'
          audience: this.determineAudience(data.tenantId, data.userId),
          source: 'core',
          tenantId: data.tenantId,
          userId: data.userId,
          data: JSON.stringify(data.metadata || {}),
          read: false,
        },
      });

      this.logger.log(`Notificação criada: ${notification.id} - ${notification.title}`);
      return this.mapToEntity(notification);
    } catch (error) {
      this.logger.error('Erro ao criar notificação:', error);
      throw error;
    }
  }

  /**
   * Busca notificações para o dropdown (últimas 10)
   */
  async findForDropdown(user: unknown): Promise<NotificationResponse> {
    const where = this.buildWhereClause(user);

    const [notifications, total, unreadCount] = await Promise.all([
      this.prisma.notification.findMany({
        where,
        orderBy: { createdAt: 'desc' },
        take: 10,
      }),
      this.prisma.notification.count({ where }),
      this.prisma.notification.count({
        where: { ...where, read: false }
      }),
    ]);

    return {
      notifications: notifications.map(n => this.mapToEntity(n)),
      total,
      unreadCount,
      hasMore: total > 10,
    };
  }

  /**
   * Busca notificações com filtros e paginação
   */
  async findMany(user: any, filters: NotificationFilters = {}): Promise<NotificationResponse> {
    const where = this.buildWhereClause(user, filters);
    const page = filters.page || 1;
    const limit = filters.limit || 20;
    const skip = (page - 1) * limit;

    const [notifications, total, unreadCount] = await Promise.all([
      this.prisma.notification.findMany({
        where,
        orderBy: { createdAt: 'desc' },
        skip,
        take: limit,
      }),
      this.prisma.notification.count({ where }),
      this.prisma.notification.count({
        where: { ...where, read: false }
      }),
    ]);

    return {
      notifications: notifications.map(n => this.mapToEntity(n)),
      total,
      unreadCount,
      hasMore: skip + notifications.length < total,
    };
  }

  /**
   * Marca notificação como lida
   */
  async markAsRead(id: string, user: unknown): Promise<Notification | null> {
    const where = {
      id,
      ...this.buildWhereClause(user)
    };

    try {
      const notification = await this.prisma.notification.update({
        where,
        data: {
          read: true,
          readAt: new Date()
        },
      });

      this.logger.log(`Notificação marcada como lida: ${id}`);
      return this.mapToEntity(notification);
    } catch (error) {
      this.logger.warn(`Notificação não encontrada ou sem permissão: ${id}`);
      return null;
    }
  }

  /**
   * Marca notificação como NÃO lida
   */
  async markAsUnread(id: string, user: unknown): Promise<Notification | null> {
    const where = {
      id,
      ...this.buildWhereClause(user)
    };

    try {
      const notification = await this.prisma.notification.update({
        where,
        data: {
          read: false,
          readAt: null
        },
      });

      this.logger.log(`Notificação marcada como não lida: ${id}`);
      return this.mapToEntity(notification);
    } catch (error) {
      this.logger.warn(`Notificação não encontrada ou sem permissão: ${id}`);
      return null;
    }
  }

  /**
   * Marca todas as notificações como lidas
   */
  async markAllAsRead(user: any, filters?: NotificationFilters): Promise<number> {
    const where = this.buildWhereClause(user, filters);

    const result = await this.prisma.notification.updateMany({
      where: { ...where, read: false },
      data: {
        read: true,
        readAt: new Date()
      },
    });

    this.logger.log(`${result.count} notificações marcadas como lidas`);
    return result.count;
  }

  /**
   * Deleta uma notificação
   */
  async delete(id: string, user: unknown): Promise<Notification | null> {
    const where = {
      id,
      ...this.buildWhereClause(user)
    };

    try {
      const notification = await this.prisma.notification.delete({
        where,
      });

      this.logger.log(`Notificação deletada: ${id}`);
      return this.mapToEntity(notification);
    } catch (error) {
      this.logger.warn(`Notificação não encontrada ou sem permissão: ${id}`);
      return null;
    }
  }

  /**
   * Deleta múltiplas notificações
   */
  async deleteMany(ids: string[], user: unknown): Promise<number> {
    const where = {
      id: { in: ids },
      ...this.buildWhereClause(user)
    };

    const result = await this.prisma.notification.deleteMany({
      where,
    });

    this.logger.log(`${result.count} notificações deletadas`);
    return result.count;
  }

  /**
   * Conta notificações não lidas
   */
  async countUnread(user: unknown): Promise<number> {
    const where = {
      ...this.buildWhereClause(user),
      read: false
    };

    return this.prisma.notification.count({ where });
  }

  /**
   * Envia notificação em massa (Broadcast)
   */
  async broadcast(dto: BroadcastNotificationDto, authorInfo: unknown): Promise<{ count: number }> {
    const where: any = {};

    // 1. Filtro de Target (Role)
    if (dto.target === 'admins_only') {
      where.role = { in: ['ADMIN', 'SUPER_ADMIN'] };
    } else if (dto.target === 'super_admins') {
      where.role = 'SUPER_ADMIN';
    }

    // 2. Filtro de Escopo (Tenants)
    if (dto.scope === 'tenants' && dto.tenantIds && dto.tenantIds.length > 0) {
      where.tenantId = { in: dto.tenantIds };
    }

    // Buscar Usuários Alvo
    const users = await this.prisma.user.findMany({
      where,
      select: { id: true, tenantId: true }
    });

    if (!users || users.length === 0) {
      return { count: 0 };
    }

    // 4. Mapear Severidade
    const severityMap = {
      'error': 'critical',
      'warning': 'warning',
      'success': 'info', // ou success se o banco suportar
      'info': 'info'
    };
    const dbSeverity = severityMap[dto.type] || 'info';

    // 5. Preparar dados para Bulk Insert
    const notificationsData = users.map(u => ({
      title: dto.title,
      message: dto.description,
      severity: dbSeverity,
      userId: u.id,
      tenantId: u.tenantId,
      source: 'broadcast',
      audience: 'user',
      read: false,
      data: JSON.stringify({ broadcast: true, target: dto.target }),
      createdAt: new Date(),
      updatedAt: new Date()
    }));

    // 6. Inserir (createMany)
    const result = await this.prisma.notification.createMany({
      data: notificationsData
    });

    this.logger.log(`Broadcast enviado para ${result.count} usuários. Scope: ${dto.scope}`);

    return { count: result.count };
  }

  /**
   * Busca uma notificação por ID
   */
  async findById(id: string, user: unknown): Promise<Notification | null> {
    const where = {
      id,
      ...this.buildWhereClause(user)
    };

    try {
      const notification = await this.prisma.notification.findUnique({
        where,
      });

      return notification ? this.mapToEntity(notification) : null;
    } catch (error) {
      return null;
    }
  }

  // ============================================================================
  // MÉTODOS PRIVADOS
  // ============================================================================

  private buildWhereClause(user: any, filters?: NotificationFilters) {
    const where: any = {};

    // Filtros de permissão baseados no papel do usuário
    if (user.role === 'USER') {
      // Usuário comum: apenas suas próprias notificações
      where.userId = user.id;
    } else if (user.role === 'ADMIN' || user.role === 'SUPER_ADMIN') {
      // Perfis administrativos:
      // - visualizam tudo da própria tenant (incluindo notificações de outros usuários da tenant)
      // - mantêm acesso às próprias notificações diretas
      if (user.tenantId) {
        where.OR = [
          { tenantId: user.tenantId },
          { userId: user.id },
        ];
      } else {
        // Fallback seguro para contas administrativas sem tenant vinculada
        where.OR = [
          { userId: user.id },
          { userId: null, tenantId: null },
        ];
      }
    }

    // Aplicar filtros adicionais
    if (filters) {
      if (filters.type) {
        // Mapear type para severity
        const severityMap = {
          'error': 'critical',
          'warning': 'warning',
          'info': 'info',
          'success': 'info'
        };
        where.severity = severityMap[filters.type] || 'info';
      }
      if (filters.read !== undefined) {
        where.read = filters.read;
      }
      if (filters.tenantId && user.role === 'SUPER_ADMIN') {
        where.tenantId = filters.tenantId;
      }
      if (filters.userId && (user.role === 'ADMIN' || user.role === 'SUPER_ADMIN')) {
        where.userId = filters.userId;
      }
      if (filters.dateFrom) {
        where.createdAt = { ...where.createdAt, gte: filters.dateFrom };
      }
      if (filters.dateTo) {
        where.createdAt = { ...where.createdAt, lte: filters.dateTo };
      }
    }

    return where;
  }

  private mapToEntity(notification: any): Notification {
    return {
      id: notification.id,
      title: notification.title,
      description: notification.message, // Prisma usa 'message'
      type: this.mapSeverityToType(notification.severity), // Converte severity para type
      tenantId: notification.tenantId,
      userId: notification.userId,
      read: notification.read,
      readAt: notification.readAt,
      createdAt: notification.createdAt,
      updatedAt: notification.updatedAt,
      metadata: this.parseMetadata(notification.data),
    };
  }

  private determineAudience(tenantId?: string | null, userId?: string | null): string {
    if (userId) return 'user';
    if (tenantId) return 'admin';
    return 'super_admin';
  }

  private mapSeverityToType(severity: string): 'info' | 'success' | 'warning' | 'error' {
    switch (severity) {
      case 'critical': return 'error';
      case 'warning': return 'warning';
      case 'info': return 'info';
      default: return 'info';
    }
  }

  private parseMetadata(data: string): Record<string, any> {
    try {
      return JSON.parse(data || '{}');
    } catch {
      return {};
    }
  }
}

/**
 * NOTIFICATIONS CONTROLLER - Endpoints REST para notificações
 */

import {
  Controller,
  Get,
  Post,
  Patch,
  Delete,
  Body,
  Param,
  Query,
  UseGuards,
  Request,
} from '@nestjs/common';
import { JwtAuthGuard } from '@core/common/guards/jwt-auth.guard';
import { NotificationService } from './notification.service';
import { NotificationGateway } from './notification.gateway';
import { PushNotificationService } from './push-notification.service';
import {
  CreateNotificationDto,
  NotificationFiltersDto,
  BroadcastNotificationDto,
  SavePushSubscriptionDto,
  RemovePushSubscriptionDto,
} from './notification.dto';

@Controller('notifications')
@UseGuards(JwtAuthGuard)
export class NotificationsController {
  constructor(
    private notificationService: NotificationService,
    private notificationGateway: NotificationGateway,
    private pushNotificationService: PushNotificationService,
  ) {}

  @Get('push/public-key')
  async getPushPublicKey() {
    const publicKey = await this.pushNotificationService.getPublicKey();
    return {
      enabled: !!publicKey,
      publicKey,
    };
  }

  @Post('push/subscribe')
  async subscribeToPush(@Body() body: SavePushSubscriptionDto, @Request() req) {
    const userAgentHeader = req.headers?.['user-agent'];
    const userAgent = Array.isArray(userAgentHeader) ? userAgentHeader[0] : userAgentHeader;

    const success = await this.pushNotificationService.saveSubscription(
      req.user,
      body,
      userAgent,
    );

    return { success };
  }

  @Post('push/unsubscribe')
  async unsubscribeFromPush(@Body() body: RemovePushSubscriptionDto, @Request() req) {
    const count = await this.pushNotificationService.removeSubscription(req.user, body.endpoint);
    return { success: count > 0, count };
  }

  /**
   * Cria uma nova notificação
   */
  @Post()
  async create(@Body() createDto: CreateNotificationDto, @Request() req) {
    const notification = await this.notificationService.create(createDto);

    // Emite via Socket.IO
    await this.notificationGateway.emitNewNotification(notification);

    return { success: true, notification };
  }

  /**
   * Envia notificação em massa (Broadcast)
   */
  @Post('broadcast')
  async broadcast(@Body() body: BroadcastNotificationDto, @Request() req) {
    return this.notificationService.broadcast(body, req.user);
  }

  /**
   * Busca notificações para o dropdown (últimas 10)
   */
  @Get('dropdown')
  async getDropdown(@Request() req) {
    return this.notificationService.findForDropdown(req.user);
  }

  /**
   * Busca notificações com filtros e paginação
   */
  @Get()
  async findMany(@Query() query: NotificationFiltersDto, @Request() req) {
    const filters = {
      type: query.type,
      read: query.read,
      tenantId: query.tenantId,
      userId: query.userId,
      dateFrom: query.dateFrom && query.dateFrom !== 'undefined' ? new Date(query.dateFrom) : undefined,
      dateTo: query.dateTo && query.dateTo !== 'undefined' ? new Date(query.dateTo) : undefined,
      page: query.page ? Number(query.page) : 1,
      limit: query.limit ? Number(query.limit) : 20,
    };

    return this.notificationService.findMany(req.user, filters);
  }

  /**
   * Conta notificações não lidas
   */
  @Get('unread-count')
  async getUnreadCount(@Request() req) {
    const count = await this.notificationService.countUnread(req.user);
    return { count };
  }

  /**
   * Marca notificação como lida
   */
  @Patch(':id/read')
  async markAsRead(@Param('id') id: string, @Request() req) {
    const notification = await this.notificationService.markAsRead(id, req.user);

    if (notification) {
      // Emite evento via Socket.IO
      await this.notificationGateway.emitNotificationRead(notification);
    }

    return { success: !!notification };
  }

  /**
   * Marca notificação como NÃO lida
   */
  @Patch(':id/unread')
  async markAsUnread(@Param('id') id: string, @Request() req) {
    const notification = await this.notificationService.markAsUnread(id, req.user);

    // Não emite socket conforme regra de isolamento da lista

    return { success: !!notification };
  }

  /**
   * Marca todas as notificações como lidas
   */
  @Patch('mark-all-read')
  async markAllAsRead(@Request() req) {
    const count = await this.notificationService.markAllAsRead(req.user);
    return { success: true, count };
  }

  /**
   * Deleta múltiplas notificações (Via POST para garantir envio do body)
   */
  @Post('batch-delete')
  async deleteMany(@Body() body: { ids: string[] }, @Request() req) {
    try {
      let idsToDelete = body.ids;

      // Sanitização robusta para garantir array puro de strings
      if (Array.isArray(idsToDelete)) {
        idsToDelete = [...idsToDelete]; // Clone para remover propriedades estranhas de Proxy se houver
      } else if (typeof idsToDelete === 'object' && idsToDelete !== null) {
        // Converte objeto {0: 'a', 1: 'b'} para array
        idsToDelete = Object.values(idsToDelete).filter(i => typeof i === 'string');
      } else {
        idsToDelete = [];
      }

      const count = await this.notificationService.deleteMany(idsToDelete, req.user);
      return { success: true, count };
    } catch (e) {
      console.error('❌ ERRO [Batch Delete]:', e);
      throw e;
    }
  }

  /**
   * Deleta uma notificação
   */
  @Delete(':id')
  async delete(@Param('id') id: string, @Request() req) {
    const notification = await this.notificationService.delete(id, req.user);

    if (notification) {
      // Emite evento via Socket.IO
      await this.notificationGateway.emitNotificationDeleted(id, notification);
    }

    return { success: !!notification };
  }
}

