import { Injectable, ConflictException, BadRequestException, NotFoundException } from '@nestjs/common';
import { PrismaService } from '@core/prisma/prisma.service';
import { CreateTenantDto } from './dto/create-tenant.dto';
import { UpdateTenantDto } from './dto/update-tenant.dto';
import * as bcrypt from 'bcrypt';
import { access, unlink } from 'fs/promises';
import { basename, join, resolve } from 'path';

@Injectable()
export class TenantsService {
  constructor(private prisma: PrismaService) { }

  private getLogosUploadDir(): string {
    return resolve(process.cwd(), process.env.LOGOS_UPLOAD_DIR || './uploads/logos');
  }

  private getSafeLogoFilename(logoUrl?: string | null): string | null {
    if (!logoUrl || typeof logoUrl !== 'string') {
      return null;
    }

    const normalized = logoUrl.trim();
    if (!normalized) {
      return null;
    }

    const safeName = basename(normalized);
    if (safeName !== normalized) {
      return null;
    }

    return safeName;
  }

  private async resolveExistingLogo(logoUrl?: string | null): Promise<string | null> {
    const safeName = this.getSafeLogoFilename(logoUrl);
    if (!safeName) {
      return null;
    }

    try {
      const logoPath = join(this.getLogosUploadDir(), safeName);
      await access(logoPath);
      return safeName;
    } catch {
      return null;
    }
  }

  async findAll() {
    return this.prisma.tenant.findMany({
      orderBy: { createdAt: 'desc' },
      include: {
        _count: {
          select: { users: true },
        },
      },
    });
  }

  async findOne(id: string) {
    const tenant = await this.prisma.tenant.findUnique({
      where: { id },
      include: {
        _count: {
          select: { users: true },
        },
      },
    });

    if (!tenant) {
      throw new NotFoundException('Empresa não encontrada');
    }

    return tenant;
  }

  async create(createTenantDto: CreateTenantDto) {
    const { email, cnpjCpf, nomeFantasia, nomeResponsavel, telefone, adminEmail, adminPassword, adminName } = createTenantDto;

    // Verifica se já existe tenant com o mesmo email ou CNPJ/CPF
    const existingTenant = await this.prisma.tenant.findFirst({
      where: {
        OR: [{ email }, { cnpjCpf }],
      },
    });

    if (existingTenant) {
      throw new ConflictException('Já existe uma empresa com este email ou CNPJ/CPF');
    }

    // Verifica se já existe usuário com o email do admin
    const existingUser = await this.prisma.user.findUnique({
      where: { email: adminEmail },
    });

    if (existingUser) {
      throw new ConflictException('Já existe um usuário com este email');
    }

    // Hash da senha do admin
    const hashedPassword = await bcrypt.hash(adminPassword, 10);

    // Cria o tenant e o usuário admin em uma transação
    return this.prisma.$transaction(async (prisma) => {
      // Cria o tenant
      const tenant = await (prisma as any).tenant.create({
        data: {
          email,
          cnpjCpf,
          nomeFantasia,
          nomeResponsavel,
          telefone,
        },
      });

      // Cria o usuário admin do tenant
      await (prisma as any).user.create({
        data: {
          email: adminEmail,
          password: hashedPassword,
          name: adminName,
          role: 'ADMIN',
          tenantId: tenant.id,
        },
      });

      // Buscar todos os módulos ativos do sistema
      const activeModules = await (prisma as any).module.findMany({
        where: { status: 'active' },
      });

      // Vincular módulos ao novo tenant (DESABILITADOS por padrão)
      // Cada tenant deve ativar os módulos que deseja usar
      if (activeModules.length > 0) {
        await (prisma as any).moduleTenant.createMany({
          data: activeModules.map((module) => ({
            tenantId: tenant.id,
            moduleId: module.id,
            enabled: false, // ✅ Módulos desabilitados por padrão
          })),
        });
      }

      return tenant;
    });
  }

  async update(id: string, updateTenantDto: UpdateTenantDto) {
    // Verifica se o tenant existe
    await this.findOne(id);

    // Se está atualizando email ou CNPJ, verifica duplicação
    if (updateTenantDto.email || updateTenantDto.cnpjCpf) {
      const existingTenant = await this.prisma.tenant.findFirst({
        where: {
          AND: [
            { id: { not: id } },
            {
              OR: [
                updateTenantDto.email ? { email: updateTenantDto.email } : {},
                updateTenantDto.cnpjCpf ? { cnpjCpf: updateTenantDto.cnpjCpf } : {},
              ],
            },
          ],
        },
      });

      if (existingTenant) {
        throw new ConflictException('Já existe uma empresa com este email ou CNPJ/CPF');
      }
    }

    return this.prisma.tenant.update({
      where: { id },
      data: updateTenantDto,
    });
  }

  async toggleStatus(id: string) {
    const tenant = await this.findOne(id);

    // Bloqueia a desativação da empresa padrão (Empresa Exemplo LTDA)
    if (tenant.email === 'empresa1@example.com' && tenant.ativo) {
      throw new BadRequestException('A empresa padrão do sistema não pode ser desativada');
    }

    return this.prisma.tenant.update({
      where: { id },
      data: {
        ativo: !tenant.ativo,
      },
    });
  }

  async changeAdminPassword(id: string, changePasswordDto: { newPassword: string }) {
    // Verifica se o tenant existe
    await this.findOne(id);

    // Busca o usuário admin do tenant
    const admin = await this.prisma.user.findFirst({
      where: {
        tenantId: id,
        role: 'ADMIN',
      },
    });

    if (!admin) {
      throw new NotFoundException('Administrador do tenant não encontrado');
    }

    // Hash da nova senha
    const hashedPassword = await bcrypt.hash(changePasswordDto.newPassword, 10);

    // Atualiza a senha
    await this.prisma.user.update({
      where: { id: admin.id },
      data: { password: hashedPassword },
    });

    return { message: 'Senha alterada com sucesso' };
  }

  async updateLogo(id: string, filename: string) {
    const tenant = await this.findOne(id);

    // Remove o logo antigo se existir
    if (tenant.logoUrl) {
      try {
        const oldLogoPath = join(process.cwd(), 'uploads', 'logos', tenant.logoUrl);
        await unlink(oldLogoPath);
      } catch (error) {
        // Ignora erro se o arquivo não existir
      }
    }

    // Atualiza com o novo logo
    return this.prisma.tenant.update({
      where: { id },
      data: { logoUrl: filename },
    });
  }

  async removeLogo(id: string) {
    const tenant = await this.findOne(id);

    if (!tenant.logoUrl) {
      throw new BadRequestException('Esta empresa não possui logo');
    }

    // Remove o arquivo físico
    try {
      const logoPath = join(process.cwd(), 'uploads', 'logos', tenant.logoUrl);
      await unlink(logoPath);
    } catch (error) {
      // Ignora erro se o arquivo não existir
    }

    // Remove a referência do banco
    return this.prisma.tenant.update({
      where: { id },
      data: { logoUrl: null },
    });
  }

  async remove(id: string) {
    const tenant = await this.findOne(id);

    // Não permite deletar a empresa padrão
    if (tenant.email === 'empresa1@example.com') {
      throw new BadRequestException('A empresa padrão do sistema não pode ser deletada');
    }

    // Verifica se há usuários vinculados
    const usersCount = await this.prisma.user.count({
      where: { tenantId: id },
    });

    if (usersCount > 0) {
      throw new BadRequestException(
        `Não é possível deletar esta empresa pois existem ${usersCount} usuário(s) vinculado(s). Delete os usuários primeiro.`,
      );
    }

    // Remove o logo se existir
    if (tenant.logoUrl) {
      try {
        const logoPath = join(process.cwd(), 'uploads', 'logos', tenant.logoUrl);
        await unlink(logoPath);
      } catch (error) {
        // Ignora erro se o arquivo não existir
      }
    }

    // Deleta a empresa
    await this.prisma.tenant.delete({
      where: { id },
    });

    return { message: 'Empresa deletada com sucesso' };
  }

  async getMasterLogo() {
    // Busca a empresa marcada como master (tenant principal da plataforma)
    const masterTenant = await this.prisma.tenant.findFirst({
      where: {
        isMasterTenant: true,
        ativo: true,
      },
      select: {
        logoUrl: true,
        nomeFantasia: true,
      },
    });

    // Fallback: se não houver master definido, usa a primeira ativa
    if (!masterTenant) {
      const fallbackTenant = await this.prisma.tenant.findFirst({
        where: { ativo: true },
        orderBy: { createdAt: 'asc' },
        select: {
          logoUrl: true,
          nomeFantasia: true,
        },
      });

      const validFallbackLogo = await this.resolveExistingLogo(fallbackTenant?.logoUrl);
      return {
        logoUrl: validFallbackLogo,
        nomeFantasia: fallbackTenant?.nomeFantasia || 'Sistema',
      };
    }

    const validMasterLogo = await this.resolveExistingLogo(masterTenant.logoUrl);
    return {
      logoUrl: validMasterLogo,
      nomeFantasia: masterTenant.nomeFantasia,
    };
  }

  async getTenantLogo(id: string) {
    const tenant = await this.prisma.tenant.findUnique({
      where: { id },
      select: {
        logoUrl: true,
        nomeFantasia: true,
      },
    });

    if (!tenant) {
      throw new NotFoundException('Empresa não encontrada');
    }

    const validTenantLogo = await this.resolveExistingLogo(tenant.logoUrl);
    return {
      logoUrl: validTenantLogo,
      nomeFantasia: tenant.nomeFantasia,
    };
  }

  // Métodos para gerenciamento de módulos dos tenants

  async getTenantActiveModules(tenantId: string) {
    // Método temporariamente desabilitado - usar ModuleSecurityService
    return {
      activeModules: [],
      modules: [],
    };
  }

  async activateModuleForTenant(tenantId: string, moduleName: string) {
    // Método temporariamente desabilitado - usar ModuleInstallerService
    throw new BadRequestException('Use o novo sistema de módulos');
  }

  async deactivateModuleForTenant(tenantId: string, moduleName: string) {
    // Método temporariamente desabilitado - usar ModuleInstallerService
    throw new BadRequestException('Use o novo sistema de módulos');
  }

  async toggleModuleForTenant(tenantId: string, moduleName: string) {
    // Método temporariamente desabilitado - usar ModuleInstallerService
    throw new BadRequestException('Use o novo sistema de módulos');
  }

  async configureTenantModule(tenantId: string, moduleName: string, config: unknown) {
    // Método temporariamente desabilitado - usar ModuleInstallerService
    throw new BadRequestException('Use o novo sistema de módulos');
  }
}

import {
  Body,
  Controller,
  Get,
  HttpException,
  HttpStatus,
  Param,
  Post,
  Put,
  Query,
  Request,
  UseGuards,
} from '@nestjs/common';
import { Throttle } from '@nestjs/throttler';
import { Role } from '@prisma/client';
import { Roles } from '@core/common/decorators/roles.decorator';
import { JwtAuthGuard } from '@core/common/guards/jwt-auth.guard';
import { RolesGuard } from '@core/common/guards/roles.guard';
import { ExecuteUpdateDto, UpdateConfigDto } from './dto/update.dto';
import { UpdateService } from './update.service';

@Controller('update')
@UseGuards(JwtAuthGuard)
export class UpdateController {
  constructor(private updateService: UpdateService) {
    // Empty implementation
  }

  private rethrowPreservingHttp(error: unknown, fallbackMessage: string): never {
    if (error instanceof HttpException) {
      throw error;
    }
    throw new HttpException(fallbackMessage, HttpStatus.INTERNAL_SERVER_ERROR);
  }

  @Get('status')
  async getStatus() {
    try {
      return await this.updateService.getUpdateStatus();
    } catch (error) {
      this.rethrowPreservingHttp(error, 'Erro ao buscar status de atualizações');
    }
  }

  @Get('check')
  @UseGuards(RolesGuard)
  @Roles(Role.SUPER_ADMIN)
  @Throttle({ default: { limit: 10, ttl: 60000 } })
  async checkForUpdates(@Request() _req) {
    try {
      const result = await this.updateService.checkForUpdates();
      return {
        success: true,
        message: result.updateAvailable
          ? `Nova versão disponível: ${result.availableVersion}`
          : 'Sistema está atualizado',
        ...result,
      };
    } catch (error) {
      this.rethrowPreservingHttp(error, 'Erro ao verificar atualizações');
    }
  }

  @Post('execute')
  @UseGuards(RolesGuard)
  @Roles(Role.SUPER_ADMIN)
  @Throttle({ default: { limit: 3, ttl: 3600000 } })
  async executeUpdate(@Body() updateData: ExecuteUpdateDto, @Request() req) {
    try {
      const userId = req.user.sub;
      const ipAddress = req.ip;
      const userAgent = req.headers['user-agent'];

      return await this.updateService.executeUpdate(updateData, userId, ipAddress, userAgent);
    } catch (error) {
      this.rethrowPreservingHttp(error, 'Erro ao executar atualização');
    }
  }

  @Put('config')
  @UseGuards(RolesGuard)
  @Roles(Role.SUPER_ADMIN)
  async updateConfig(@Body() config: UpdateConfigDto, @Request() req) {
    try {
      const userId = req.user.sub;
      return await this.updateService.updateConfig(config, userId);
    } catch (error) {
      this.rethrowPreservingHttp(error, 'Erro ao atualizar configurações');
    }
  }

  @Get('logs')
  @UseGuards(RolesGuard)
  @Roles(Role.SUPER_ADMIN)
  async getLogs(@Query('limit') limit?: string) {
    try {
      const limitNum = limit ? parseInt(limit, 10) : 50;
      if (limitNum > 200) {
        throw new HttpException('Limite máximo de 200 registros', HttpStatus.BAD_REQUEST);
      }

      const logs = await this.updateService.getUpdateLogs(limitNum);
      return {
        success: true,
        data: logs,
        total: logs.length,
      };
    } catch (error) {
      this.rethrowPreservingHttp(error, 'Erro ao buscar logs de atualização');
    }
  }

  @Get('logs/:id')
  @UseGuards(RolesGuard)
  @Roles(Role.SUPER_ADMIN)
  async getLogDetails(@Param('id') logId: string) {
    try {
      const log = await this.updateService.getUpdateLogDetails(logId);
      return {
        success: true,
        data: log,
      };
    } catch (error) {
      this.rethrowPreservingHttp(error, 'Erro ao buscar detalhes do log');
    }
  }

  @Get('test-connection')
  @UseGuards(RolesGuard)
  @Roles(Role.SUPER_ADMIN)
  @Throttle({ default: { limit: 5, ttl: 60000 } })
  async testConnection() {
    try {
      const result = await this.updateService.checkForUpdates();
      return {
        success: true,
        message: 'Conexão com repositório estabelecida com sucesso',
        connected: true,
        ...result,
      };
    } catch (_error) {
      return {
        success: false,
        message: 'Falha na conexão com o repositório',
        connected: false,
      };
    }
  }
}

 import { IsEmail, IsString, IsOptional, MinLength, IsEnum, IsBoolean, registerDecorator, ValidationOptions, ValidationArguments } from 'class-validator';
import { Role } from '@prisma/client';
import { PrismaService } from '@core/prisma/prisma.service';

// Validador personalizado para senha baseado nas configurações
function IsValidPassword(validationOptions?: ValidationOptions) {
  return function (object: object, propertyName: string) {
    registerDecorator({
      name: 'isValidPassword',
      target: object.constructor,
      propertyName: propertyName,
      options: validationOptions,
      validator: {
        async validate(value: unknown, _args: ValidationArguments) {
          if (!value || typeof value !== 'string' || value.trim() === '') return true; // Se não há senha, é válido (para edição)

          try {
            // Buscar configurações de senha do banco
            const prisma = new PrismaService();
            const config = await prisma.securityConfig.findFirst();

            if (!config) {
              // Usar valores padrão se não houver configuração
              const minLength = 8;
              const requireUppercase = true;
              const requireLowercase = true;
              const requireNumbers = true;
              const requireSpecial = true;

              if (value.length < minLength) return false;
              if (requireUppercase && !/[A-Z]/.test(value)) return false;
              if (requireLowercase && !/[a-z]/.test(value)) return false;
              if (requireNumbers && !/\d/.test(value)) return false;
              if (requireSpecial && !/[!@#$%^&*()_+\-=[\]{};':"\\|,.<>/?]/.test(value)) return false;

              return true;
            }

            // Validar baseado nas configurações do banco
            if (value.length < config.passwordMinLength) return false;
            if (config.passwordRequireUppercase && !/[A-Z]/.test(value)) return false;
            if (config.passwordRequireLowercase && !/[a-z]/.test(value)) return false;
            if (config.passwordRequireNumbers && !/\d/.test(value)) return false;
            if (config.passwordRequireSpecial && !/[!@#$%^&*()_+\-=[\]{};':"\\|,.<>/?]/.test(value)) return false;

            return true;
          } catch (error) {
            // Em caso de erro, usar validação básica
            return value.length >= 8 && /[A-Z]/.test(value) && /[a-z]/.test(value) && /\d/.test(value);
          }
        },
        defaultMessage(_args: ValidationArguments) {
          return 'A senha não atende aos requisitos de segurança configurados';
        },
      },
    });
  };
}

export class UpdateUserDto {
  @IsOptional()
  @IsEmail({
      // Empty implementation
    }, { message: 'Email inválido' })
  email?: string;

  @IsOptional()
  @IsString()
  @MinLength(3, { message: 'Nome deve ter no mínimo 3 caracteres' })
  name?: string;

  @IsOptional()
  @IsEnum({ message: 'Role inválida' })
  role?: Role;

  @IsOptional()
  @IsString()
  @IsValidPassword()
  password?: string;
}

export class ToggleUserStatusDto {
  @IsBoolean()
  ativo: boolean;
}

import { Controller, Get, Post, Body, Patch, Param, Delete, UseGuards, Query, Put } from '@nestjs/common'; 
import { UsersService } from './users.service';
import { CreateUserDto } from './dto/create-user.dto';
import { UpdateUserDto } from './dto/update-user.dto';
import { ChangePasswordDto } from './dto/change-password.dto';
import { UpdateProfileDto } from './dto/update-profile.dto';
import { UpdateUserPreferencesDto } from './dto/update-preferences.dto';
import { JwtAuthGuard } from '@core/common/guards/jwt-auth.guard';
import { RolesGuard } from '@core/common/guards/roles.guard';
import { Roles } from '@core/common/decorators/roles.decorator';
import { SkipTenantIsolation } from '@core/common/decorators/skip-tenant-isolation.decorator';
import { Role } from '@prisma/client';
import { CurrentUser } from '@core/common/decorators/current-user.decorator';

@Controller('users')
@UseGuards(JwtAuthGuard, RolesGuard)
export class UsersController {
  constructor(private readonly usersService: UsersService) { }

  @Post()
  @Roles(Role.SUPER_ADMIN, Role.ADMIN)
  @SkipTenantIsolation()
  create(@Body() createUserDto: CreateUserDto, @CurrentUser() user: any) {
    // Se for ADMIN, força o tenantId do usuário logado
    if (user.role === Role.ADMIN) {
      createUserDto.tenantId = user.tenantId;
      // ADMIN só pode criar USER ou CLIENT
      if (createUserDto.role === Role.SUPER_ADMIN || createUserDto.role === Role.ADMIN) {
        throw new Error('ADMIN não pode criar SUPER_ADMIN ou ADMIN');
      }
    }
    return this.usersService.create(createUserDto);
  }

  @Get()
  @Roles(Role.SUPER_ADMIN, Role.ADMIN)
  @SkipTenantIsolation()
  findAll(@Query('tenantId') tenantId?: string, @CurrentUser() user?: any) {
    // Se for ADMIN, força buscar apenas do seu tenant
    if (user?.role === Role.ADMIN) {
      return this.usersService.findAll(user.tenantId);
    }
    return this.usersService.findAll(tenantId);
  }

  @Get('tenant/:tenantId')
  @Roles(Role.SUPER_ADMIN, Role.ADMIN)
  @SkipTenantIsolation()
  findByTenant(@Param('tenantId') tenantId: string, @CurrentUser() user: any) {
    // ADMIN só pode acessar o próprio tenant
    if (user.role === Role.ADMIN && user.tenantId !== tenantId) {
      throw new Error('ADMIN não pode acessar usuários de outros tenants');
    }
    return this.usersService.findByTenant(tenantId);
  }

  /**
   * PATCH /users/preferences
   * Atualizar preferências do usuário (Tema)
   * MOVED UP to avoid conflict with :id
   */
  @Patch('preferences')
  @Roles(Role.SUPER_ADMIN, Role.ADMIN, Role.USER, Role.CLIENT)
  updatePreferences(
    @Body() updateUserPreferencesDto: UpdateUserPreferencesDto,
    @CurrentUser() user: any,
  ) {
    if (updateUserPreferencesDto.theme) {
      return this.usersService.updatePreferences(user.id, updateUserPreferencesDto.theme);
    }
    return { message: 'No preferences to update' };
  }

  @Get(':id')
  @Roles(Role.SUPER_ADMIN, Role.ADMIN)
  @SkipTenantIsolation()
  findOne(@Param('id') id: string) {
    return this.usersService.findOne(id);
  }

  @Patch(':id')
  @Roles(Role.SUPER_ADMIN, Role.ADMIN)
  @SkipTenantIsolation()
  async update(@Param('id') id: string, @Body() updateUserDto: UpdateUserDto, @CurrentUser() currentUser: any) {
    // Verificar se está tentando editar um SUPER_ADMIN
    const targetUser = await this.usersService.findOne(id);

    if (targetUser.role === Role.SUPER_ADMIN) {
      // Impedir mudança de role de SUPER_ADMIN
      if (updateUserDto.role && updateUserDto.role !== Role.SUPER_ADMIN) {
        throw new Error('Não é possível alterar a função de um SUPER_ADMIN');
      }

      // Apenas SUPER_ADMIN pode editar outro SUPER_ADMIN
      if (currentUser.role !== Role.SUPER_ADMIN) {
        throw new Error('Apenas SUPER_ADMIN pode editar outro SUPER_ADMIN');
      }
    }

    return this.usersService.update(id, updateUserDto);
  }

  @Delete(':id')
  @Roles(Role.SUPER_ADMIN, Role.ADMIN)
  @SkipTenantIsolation()
  async remove(@Param('id') id: string, @CurrentUser() currentUser: any) {
    // Verificar se está tentando deletar um SUPER_ADMIN
    const targetUser = await this.usersService.findOne(id);

    if (targetUser.role === Role.SUPER_ADMIN) {
      throw new Error('Não é possível excluir um usuário SUPER_ADMIN');
    }

    return this.usersService.remove(id);
  }

  /**
   * PUT /users/profile
   * Atualizar perfil do usuário logado
   */
  @Put('profile')
  @Roles(Role.SUPER_ADMIN, Role.ADMIN, Role.USER, Role.CLIENT)
  updateProfile(
    @Body() updateProfileDto: UpdateProfileDto,
    @CurrentUser() user: any,
  ) {
    return this.usersService.updateProfile(user.id, updateProfileDto);
  }

  /**
   * PUT /users/change-password
   * Alterar senha do usuário logado
   */
  @Put('change-password')
  @Roles(Role.SUPER_ADMIN, Role.ADMIN, Role.USER, Role.CLIENT)
  changePassword(
    @Body() changePasswordDto: ChangePasswordDto,
    @CurrentUser() user: any,
  ) {
    return this.usersService.changePassword(user.id, changePasswordDto);
  }

  /**
   * POST /users/:id/unlock
   * Desbloquear usuário
   * Apenas SUPER_ADMIN e ADMIN
   */
  @Post(':id/unlock')
  @Roles(Role.SUPER_ADMIN, Role.ADMIN)
  @SkipTenantIsolation()
  unlockUser(@Param('id') id: string) {
    return this.usersService.unlockUser(id);
  }

}

import { Injectable, ConflictException, BadRequestException, UnauthorizedException, NotFoundException } from '@nestjs/common';
import { PrismaService } from '@core/prisma/prisma.service';
import { CreateUserDto } from './dto/create-user.dto';
import { UpdateUserDto } from './dto/update-user.dto';
import { ChangePasswordDto } from './dto/change-password.dto';
import { ThemeEnum } from './dto/update-preferences.dto';
import * as bcrypt from 'bcrypt';
import { Role } from '@prisma/client';

@Injectable()
export class UsersService {
  constructor(private prisma: PrismaService) { }

  async create(createUserDto: CreateUserDto) {
    const { email, password, name, role, tenantId } = createUserDto;

    // Verifica se já existe usuário com o mesmo email
    const existingUser = await this.prisma.user.findUnique({
      where: { email },
    });

    if (existingUser) {
      throw new ConflictException('Já existe um usuário com este email');
    }

    // Valida tenantId se não for SUPER_ADMIN
    if (role !== Role.SUPER_ADMIN && !tenantId) {
      throw new BadRequestException('TenantId é obrigatório para usuários que não são SUPER_ADMIN');
    }

    // Hash da senha
    const hashedPassword = await bcrypt.hash(password, 10);

    // Cria o usuário
    const user = await this.prisma.user.create({
      data: {
        email,
        password: hashedPassword,
        name,
        role,
        tenantId: role === Role.SUPER_ADMIN ? null : tenantId,
      },
      include: {
        tenant: true,
      },
    });

    // Remove a senha do retorno
    const { password: _, ...userWithoutPassword } = user;
    return userWithoutPassword;
  }

  async findAll(tenantId?: string) {
    const where = tenantId ? { tenantId } : {
      // Empty implementation
    };

    const users = await this.prisma.user.findMany({
      where,
      orderBy: { createdAt: 'desc' },
      include: {
        tenant: {
          select: {
            id: true,
            nomeFantasia: true,
          },
        },
      },
    });

    // Remove password do retorno
    return users.map(({ password, ...user }) => user);
  }

  async findOne(id: string) {
    const user = await this.prisma.user.findUnique({
      where: { id },
      include: {
        tenant: {
          select: {
            id: true,
            nomeFantasia: true,
          },
        },
        preferences: true,
      } as any,
    });

    if (!user) {
      throw new NotFoundException('Usuário não encontrado');
    }

    const { password, ...userWithoutPassword } = user;
    return userWithoutPassword;
  }

  async update(id: string, updateUserDto: UpdateUserDto) {
    // Verifica se o usuário existe
    await this.findOne(id);

    // Se está atualizando email, verifica duplicação
    if (updateUserDto.email) {
      const existingUser = await this.prisma.user.findFirst({
        where: {
          AND: [
            { id: { not: id } },
            { email: updateUserDto.email },
          ],
        },
      });

      if (existingUser) {
        throw new ConflictException('Já existe um usuário com este email');
      }
    }

    // Se está atualizando senha, faz o hash
    const data: any = { ...updateUserDto };
    if (updateUserDto.password && updateUserDto.password.trim() !== '') {
      data.password = await bcrypt.hash(updateUserDto.password, 10);
    } else {
      // Remove password do data se estiver vazio
      delete data.password;
    }

    const user = await this.prisma.user.update({
      where: { id },
      data,
      include: {
        tenant: {
          select: {
            id: true,
            nomeFantasia: true,
          },
        },
      },
    });

    const { password, ...userWithoutPassword } = user;
    return userWithoutPassword;
  }

  async remove(id: string) {
    // Verifica se o usuário existe
    const user = await this.findOne(id);

    // Não permite deletar o SUPER_ADMIN padrão
    if (user.email === 'admin@system.com') {
      throw new BadRequestException('O SUPER_ADMIN padrão não pode ser deletado');
    }

    await this.prisma.user.delete({
      where: { id },
    });

    return { message: 'Usuário deletado com sucesso' };
  }

  async findByTenant(tenantId: string) {
    const users = await this.prisma.user.findMany({
      where: { tenantId },
      orderBy: { createdAt: 'desc' },
    });

    return users.map(({ password, ...user }) => user);
  }

  /**
   * Alterar senha do usuário
   */
  async changePassword(userId: string, changePasswordDto: ChangePasswordDto) {
    const { currentPassword, newPassword } = changePasswordDto;

    // Buscar usuário com senha
    const user = await this.prisma.user.findUnique({
      where: { id: userId },
    });

    if (!user) {
      throw new NotFoundException('Usuário não encontrado');
    }

    // Verificar senha atual
    const isPasswordValid = await bcrypt.compare(currentPassword, user.password);

    if (!isPasswordValid) {
      throw new UnauthorizedException('Senha atual incorreta');
    }

    // Verificar se a nova senha é diferente da atual
    const isSamePassword = await bcrypt.compare(newPassword, user.password);

    if (isSamePassword) {
      throw new BadRequestException('A nova senha deve ser diferente da senha atual');
    }

    // Hash da nova senha
    const hashedPassword = await bcrypt.hash(newPassword, 10);

    // Atualizar senha
    await this.prisma.user.update({
      where: { id: userId },
      data: { password: hashedPassword },
    });

    return { message: 'Senha alterada com sucesso' };
  }

  /**
   * Desbloquear usuário
   */
  async unlockUser(userId: string) {
    const user = await this.prisma.user.findUnique({
      where: { id: userId },
    });

    if (!user) {
      throw new NotFoundException('Usuário não encontrado');
    }

    if (!user.isLocked) {
      throw new BadRequestException('Usuário não está bloqueado');
    }

    // Desbloquear e resetar tentativas
    await this.prisma.user.update({
      where: { id: userId },
      data: {
        isLocked: false,
        loginAttempts: 0,
        lockedAt: null,
        lockedUntil: null,
        lastFailedLoginAt: null,
      },
    });

    return { message: 'Usuário desbloqueado com sucesso' };
  }

  /**
   * Atualizar perfil do próprio usuário
   */
  async updateProfile(userId: string, updateProfileDto: { name: string; email: string }) {
    const { name, email } = updateProfileDto;

    // Verificar se o email já está em uso por outro usuário
    const existingUser = await this.prisma.user.findUnique({
      where: { email },
    });

    if (existingUser && existingUser.id !== userId) {
      throw new ConflictException('Este email já está em uso');
    }

    // Atualizar usuário
    const user = await this.prisma.user.update({
      where: { id: userId },
      data: { name, email },
      include: {
        tenant: true,
      },
    });

    // Remove a senha do retorno
    const { password, ...userWithoutPassword } = user;
    return userWithoutPassword;
  }

  /**
   * Atualizar preferências do usuário (Tema)
   */
  async updatePreferences(userId: string, theme: ThemeEnum) {
    return this.prisma.userPreferences.upsert({
      where: { userId },
      update: { theme },
      create: { userId, theme },
    });
  }
}
